-- Poems batch 436
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-20','被彈','沈佺期','唐','御定全唐诗','yuding','','[]','知人昔不易，舉非貴易失。爾何按國章，無罪見呵叱。',216,'御定全唐詩/json/095.json','["知人昔不易，舉非貴易失。爾何按國章，無罪見呵叱。", "平生守直道，遂為眾所嫉。少以文作吏，手不曾開律。", "一旦法相持，荒忙意如漆。幼子雙囹圄，老夫一念室。", "昆弟兩三人，相次俱囚桎。萬鑠當眾怒，千謗無片實。", "庶以白黑讒，顯此涇渭質。劾吏何咆哮，晨夜聞撲抶。", "事間拾虛證，理外存枉筆。懷痛不見伸，抱冤竟難悉。", "窮囚多垢膩，愁坐饒蟣虱。三日唯一飯，兩旬不再櫛。", "是時盛夏中，暵赫多瘵疾。瞪目眠欲閉，喑嗚氣不出。", "有風自扶搖，鼓蕩無倫匹。安得吹浮雲，令我見白日。"]'),
('yuding-21','枉系二首','沈佺期','唐','御定全唐诗','yuding','','[]','吾憐曾家子，昔有投杼疑。吾憐姬公旦，非無鴟鴞詩。',96,'御定全唐詩/json/095.json','["吾憐曾家子，昔有投杼疑。吾憐姬公旦，非無鴟鴞詩。", "臣子竭忠孝，君親惑讒欺。萋斐離骨肉，含愁興此辭。", "昔日公冶長，非罪遇縲絏。聖人降其子，古來歎獨絕。", "我無毫髮瑕，苦心懷冰雪。今代多秀士，誰能繼明轍。"]'),
('yuding-22','黃鶴','沈佺期','唐','御定全唐诗','yuding','','[]','黃鶴佐丹鳳，不能群白鷳。拂雲遊四海，弄影到三山。',48,'御定全唐詩/json/095.json','["黃鶴佐丹鳳，不能群白鷳。拂雲遊四海，弄影到三山。", "遙憶君軒上，來下天池間。明珠世不重，知有報恩環。"]'),
('yuding-23','傷王學士','沈佺期','唐','御定全唐诗','yuding','','[]','閉囚斷外事，昧坐半餘期。有言穎叔子，亡來已一時。',180,'御定全唐詩/json/095.json','["閉囚斷外事，昧坐半餘期。有言穎叔子，亡來已一時。", "初聞宛不信，中話涕漣洏。痛哉玄夜重，何遽青春姿。", "憶汝曾旅食，屢空瀍澗湄。吾徒祿未厚，筲鬥愧相貽。", "原憲貧無愁，顏回樂自持。詔書擇才善，君為王子師。", "寵儒名可尚，論秩官猶欺。化往不復見，情來安可思。", "目絕毫翰灑，耳無歌諷期。靈柩寄何處，精魂今何之。", "恨予在丹棘，不得看素旗。孀妻知己歎，幼子路人悲。", "感游值商日，絕弦留此詞。"]'),
('yuding-24','古鏡','沈佺期','唐','御定全唐诗','yuding','','[]','莓苔翳清池，蝦蟆蝕明月。埋落今如此，照心未嘗歇。',36,'御定全唐詩/json/095.json','["莓苔翳清池，蝦蟆蝕明月。埋落今如此，照心未嘗歇。", "願垂拂拭恩，為君鑒玄發。"]'),
('yuding-25','鳳簫曲','沈佺期','唐','御定全唐诗','yuding','','[]','八月涼風動高閣，千金麗人卷綃幕。已憐池上歇芳菲，',48,'御定全唐詩/json/095.json','["八月涼風動高閣，千金麗人卷綃幕。已憐池上歇芳菲，", "飛燕侍寢昭陽殿，班姬飲恨長信宮。長信宮，昭陽殿，"]'),
('yuding-26','古歌','沈佺期','唐','御定全唐诗','yuding','','[]','落葉流風向玉台，夜寒秋思洞房開。水晶簾外金波下，',48,'御定全唐詩/json/095.json','["落葉流風向玉台，夜寒秋思洞房開。水晶簾外金波下，", "璿閨窈窕秋夜長，繡戶徘徊明月光。燕姬彩帳芙蓉色，"]'),
('yuding-27','七夕曝衣篇','沈佺期','唐','御定全唐诗','yuding','','[]','君不見昔日宜春太液邊，披香畫閣與天連。',115,'御定全唐詩/json/095.json','["君不見昔日宜春太液邊，披香畫閣與天連。", "燈火灼爍九微映，香氣氛氳百和然。此夜星繁河正白，", "曝衣何許曛半黃，宮中彩女提玉箱。珠履奔騰上蘭砌，", "朝霞散彩羞衣架，晚月分光劣鏡臺。上有仙人長命綹，", "椒房金屋寵新流，意氣驕奢不自由。漢文宜惜露臺費，"]'),
('yuding-28','入少密溪','沈佺期','唐','御定全唐诗','yuding','','[]','雲峰苔壁繞溪斜，江路香風夾岸花。樹密不言通鳥道，',48,'御定全唐詩/json/095.json','["雲峰苔壁繞溪斜，江路香風夾岸花。樹密不言通鳥道，", "遊魚瞥瞥雙釣童，伐木丁丁一樵叟。自言避喧非避秦，"]'),
('yuding-29','霹靂引','沈佺期','唐','御定全唐诗','yuding','','[]','歲七月，火伏而金生。客有鼓琴於門者，奏霹靂之商聲。',70,'御定全唐詩/json/095.json','["歲七月，火伏而金生。客有鼓琴於門者，奏霹靂之商聲。", "始戛羽以騞砉，終扣宮而砰駖。電耀耀兮龍躍，", "有如驅千旗，制五兵；截荒虺，斫長鯨。孰與廣陵比，"]'),
('yuding-0','立春日內出彩花應制','沈佺期','唐','御定全唐诗','yuding','','[]','合殿春應早，開箱彩預知。花迎宸翰發，葉待禦筵披。',48,'御定全唐詩/json/096.json','["合殿春應早，開箱彩預知。花迎宸翰發，葉待禦筵披。", "梅訝香全少，桃驚色頓移。輕生承剪拂，長伴萬年枝。"]'),
('yuding-1','晦日滻水應制','沈佺期','唐','御定全唐诗','yuding','','[]','素滻接宸居，青門盛祓除。摘蘭喧鳳野，浮藻溢龍渠。',48,'御定全唐詩/json/096.json','["素滻接宸居，青門盛祓除。摘蘭喧鳳野，浮藻溢龍渠。", "苑蝶飛殊懶，宮鶯囀不疏。星移天上入，歌舞向儲胥。"]'),
('yuding-2','奉和洛陽玩雪應制','沈佺期','唐','御定全唐诗','yuding','','[]','周王甲子旦，漢後德陽宮。灑瑞天庭裏，驚春御苑中。',48,'御定全唐詩/json/096.json','["周王甲子旦，漢後德陽宮。灑瑞天庭裏，驚春御苑中。", "氛氳生浩氣，颯遝舞回風。宸藻光盈尺，賡歌樂歲豐。"]'),
('yuding-3','三日梨園侍宴','沈佺期','唐','御定全唐诗','yuding','','[]','九重馳道出，三巳禊堂開。畫鷁中流動，青龍上苑來。',48,'御定全唐詩/json/096.json','["九重馳道出，三巳禊堂開。畫鷁中流動，青龍上苑來。", "野花飄御座，河柳拂天杯。日晚迎祥處，笙鏞下帝台。"]'),
('yuding-4','幸梨園亭觀打球應制','沈佺期','唐','御定全唐诗','yuding','','[]','今春芳苑游，接武上瓊樓。宛轉縈香騎，飄颻拂畫球。',48,'御定全唐詩/json/096.json','["今春芳苑游，接武上瓊樓。宛轉縈香騎，飄颻拂畫球。", "俯身迎未落，回轡逐傍流。只為看花鳥，時時誤失籌。"]'),
('yuding-5','九日臨渭亭侍宴應制得長字','沈佺期','唐','御定全唐诗','yuding','','[]','禦氣幸金方，憑高薦羽觴。魏文頒菊蕊，漢武賜萸房。',48,'御定全唐詩/json/096.json','["禦氣幸金方，憑高薦羽觴。魏文頒菊蕊，漢武賜萸房。", "秋變銅池色，晴添銀樹光。年年重九慶，日月奉天長。"]'),
('yuding-6','歲夜安樂公主滿月侍宴','沈佺期','唐','御定全唐诗','yuding','','[]','除夜子星回，天孫滿月杯。詠歌麟趾合，簫管鳳雛來。',48,'御定全唐詩/json/096.json','["除夜子星回，天孫滿月杯。詠歌麟趾合，簫管鳳雛來。", "歲炬常然桂，春盤預折梅。聖皇千萬壽，垂曉禦樓開。"]'),
('yuding-7','安樂公主移入新宅','沈佺期','唐','御定全唐诗','yuding','','[]','初聞衡漢來，移住鬥城隈。錦帳迎風轉，瓊筵拂霧開。',48,'御定全唐詩/json/096.json','["初聞衡漢來，移住鬥城隈。錦帳迎風轉，瓊筵拂霧開。", "馬香遺舊埒，風吹繞新台。為問沈冥子，仙槎何處回。"]'),
('yuding-8','仙萼亭初成侍宴應制','沈佺期','唐','御定全唐诗','yuding','','[]','山中氣色和，宸賞第中過。輦路披仙掌，帷宮拂帝蘿。',48,'御定全唐詩/json/096.json','["山中氣色和，宸賞第中過。輦路披仙掌，帷宮拂帝蘿。", "泉臨香澗落，峰入翠雲多。無異登玄圃，東南望白河。"]'),
('yuding-9','送金城公主適西蕃應制','沈佺期','唐','御定全唐诗','yuding','','[]','金榜扶丹掖，銀河屬紫閽。那堪將鳳女，還以嫁烏孫。',48,'御定全唐詩/json/096.json','["金榜扶丹掖，銀河屬紫閽。那堪將鳳女，還以嫁烏孫。", "玉就歌中怨，珠辭掌上恩。西戎非我匹，明主至公存。"]'),
('yuding-10','幸白鹿觀應制','沈佺期','唐','御定全唐诗','yuding','','[]','紫鳳真人府，斑龍太上家。天流芝蓋下，山轉桂旗斜。',48,'御定全唐詩/json/096.json','["紫鳳真人府，斑龍太上家。天流芝蓋下，山轉桂旗斜。", "聖藻垂寒露，仙杯落晚霞。唯應問王母，桃作幾時花。"]'),
('yuding-11','洛陽道','沈佺期','唐','御定全唐诗','yuding','','[]','九門開洛邑，雙闕對河橋。白日青春道，軒裳半下朝。',48,'御定全唐詩/json/096.json','["九門開洛邑，雙闕對河橋。白日青春道，軒裳半下朝。", "乘羊稚子看，拾翠美人嬌。行樂歸恒晚，香塵撲地遙。"]'),
('yuding-12','驄馬','沈佺期','唐','御定全唐诗','yuding','','[]','西北五花驄，來時道向東。四蹄碧玉片，雙眼黃金瞳。',48,'御定全唐詩/json/096.json','["西北五花驄，來時道向東。四蹄碧玉片，雙眼黃金瞳。", "鞍上留明月，嘶間動朔風。借君馳沛艾，一戰取雲中。"]'),
('yuding-13','銅雀台','沈佺期','唐','御定全唐诗','yuding','','[]','昔年分鼎地，今日望陵台。一旦雄圖盡，千秋遺令開。',48,'御定全唐詩/json/096.json','["昔年分鼎地，今日望陵台。一旦雄圖盡，千秋遺令開。", "綺羅君不見，歌舞妾空來。恩共漳河水，東流無重回。"]'),
('yuding-14','長門怨','沈佺期','唐','御定全唐诗','yuding','','[]','月皎風泠泠，長門次掖庭。玉階聞墜葉，羅幌見飛螢。',48,'御定全唐詩/json/096.json','["月皎風泠泠，長門次掖庭。玉階聞墜葉，羅幌見飛螢。", "清露凝珠綴，流塵下翠屏。妾心君未察，愁歎劇繁星。"]'),
('yuding-15','巫山高二首','沈佺期','唐','御定全唐诗','yuding','','[]','巫山峰十二，合遝隱昭回。俯眺琵琶峽，平看雲雨台。',96,'御定全唐詩/json/096.json','["巫山峰十二，合遝隱昭回。俯眺琵琶峽，平看雲雨台。", "古槎天外倚，瀑水日邊來。何忍猿啼夜，荊王枕席開。", "神女向高唐，巫山下夕陽。裴回作行雨，婉孌逐荊王。", "電影江前落，雷聲峽外長。霽雲無處所，台館曉蒼蒼。"]'),
('yuding-16','巫山高','沈佺期','唐','御定全唐诗','yuding','','[]','巫山高不極，合遝狀奇新。暗谷疑風雨，陰崖若鬼神。',48,'御定全唐詩/json/096.json','["巫山高不極，合遝狀奇新。暗谷疑風雨，陰崖若鬼神。", "月明三峽曙，潮滿九江春。為問陽臺客，應知入夢人。"]'),
('yuding-17','七夕','沈佺期','唐','御定全唐诗','yuding','','[]','秋近雁行稀，天高鵲夜飛。妝成應懶織，今夕渡河歸。',48,'御定全唐詩/json/096.json','["秋近雁行稀，天高鵲夜飛。妝成應懶織，今夕渡河歸。", "月皎宜穿線，風輕得曝衣。來時不可覺，神驗有光輝。"]'),
('yuding-18','春閨','沈佺期','唐','御定全唐诗','yuding','','[]','鐵馬三軍去，金閨二月還。邊愁離上國，春夢失陽關。',48,'御定全唐詩/json/096.json','["鐵馬三軍去，金閨二月還。邊愁離上國，春夢失陽關。", "池水琉璃淨，園花玳瑁斑。歲華空自擲，憂思不勝顏。"]'),
('yuding-19','奉和聖制同皇太子游慈恩寺應制','沈佺期','唐','御定全唐诗','yuding','','[]','肅肅蓮花界，熒熒貝葉宮。金人來夢裏，白馬出城中。',48,'御定全唐詩/json/096.json','["肅肅蓮花界，熒熒貝葉宮。金人來夢裏，白馬出城中。", "湧塔初從地，焚香欲遍空。天歌應春鑰，非是為春風。"]'),
('yuding-20','和洛州康士曹庭芝望月有懷','沈佺期','唐','御定全唐诗','yuding','','[]','天使下西樓，光含萬象秋。台前疑掛鏡，簾外似懸鉤。',48,'御定全唐詩/json/096.json','["天使下西樓，光含萬象秋。台前疑掛鏡，簾外似懸鉤。", "張尹將眉學，班姬取扇儔。佳期應借問，為報在刀頭。"]'),
('yuding-21','壽陽王花燭','沈佺期','唐','御定全唐诗','yuding','','[]','仙媛乘龍夕，天孫捧雁來。可憐桃李樹，更繞鳳凰台。',48,'御定全唐詩/json/096.json','["仙媛乘龍夕，天孫捧雁來。可憐桃李樹，更繞鳳凰台。", "燭送香車入，花臨寶扇開。莫令銀箭曉，為盡合歡杯。"]'),
('yuding-22','隴頭水','沈佺期','唐','御定全唐诗','yuding','','[]','隴山飛落葉，隴雁度寒天。愁見三秋水，分為兩地泉。',48,'御定全唐詩/json/096.json','["隴山飛落葉，隴雁度寒天。愁見三秋水，分為兩地泉。", "西流入羌郡，東下向秦川。征客重回首，肝腸空自憐。"]'),
('yuding-23','關山月','沈佺期','唐','御定全唐诗','yuding','','[]','漢月生遼海，朣朧出半暉。合昏玄菟郡，中夜白登圍。',48,'御定全唐詩/json/096.json','["漢月生遼海，朣朧出半暉。合昏玄菟郡，中夜白登圍。", "暈落關山迥，光含霜霰微。將軍聽曉角，戰馬欲南歸。"]'),
('yuding-24','折楊柳','沈佺期','唐','御定全唐诗','yuding','','[]','玉窗朝日映，羅帳春風吹。拭淚攀楊柳，長條踠地垂。',48,'御定全唐詩/json/096.json','["玉窗朝日映，羅帳春風吹。拭淚攀楊柳，長條踠地垂。", "白花飛曆亂，黃鳥思參差。妾自肝腸斷，傍人那得知。"]'),
('yuding-25','梅花落','沈佺期','唐','御定全唐诗','yuding','','[]','鐵騎幾時回，金閨怨早梅。雪寒花已落，風暖葉應開。',48,'御定全唐詩/json/096.json','["鐵騎幾時回，金閨怨早梅。雪寒花已落，風暖葉應開。", "夕逐新春管，香迎小歲杯。盛時何足貴，書裏報輪台。"]'),
('yuding-26','紫騮馬','沈佺期','唐','御定全唐诗','yuding','','[]','青玉紫騮鞍，驕多影屢盤。荷君能剪拂，躞蹀噴桑幹。',48,'御定全唐詩/json/096.json','["青玉紫騮鞍，驕多影屢盤。荷君能剪拂，躞蹀噴桑幹。", "踠足追奔易，長鳴遇賞難。摐金一萬里，霜露不辭寒。"]'),
('yuding-27','上之回','沈佺期','唐','御定全唐诗','yuding','','[]','制書下關右，天子問回中。壇墠經過遠，威儀侍從雄。',48,'御定全唐詩/json/096.json','["制書下關右，天子問回中。壇墠經過遠，威儀侍從雄。", "黃麾搖晝日，青幰曳松風。回望甘泉道，龍山隱漢宮。"]'),
('yuding-28','王昭君','沈佺期','唐','御定全唐诗','yuding','','[]','非君惜鸞殿，非妾妒蛾眉。薄命由驕虜，無情是畫師。',48,'御定全唐詩/json/096.json','["非君惜鸞殿，非妾妒蛾眉。薄命由驕虜，無情是畫師。", "嫁來胡地日，不並漢宮時。心苦無聊賴，何堪馬上辭。"]'),
('yuding-29','被試出塞','沈佺期','唐','御定全唐诗','yuding','','[]','十年通大漠，萬里出長平。寒日生戈劍，陰雲拂旆旌。',48,'御定全唐詩/json/096.json','["十年通大漠，萬里出長平。寒日生戈劍，陰雲拂旆旌。", "饑烏啼舊壘，疲馬戀空城。辛苦皋蘭北，胡霜損漢兵。"]'),
('yuding-30','牛女','沈佺期','唐','御定全唐诗','yuding','','[]','粉席秋期緩，針樓別怨多。奔龍爭度日，飛鵲亂填河。',48,'御定全唐詩/json/096.json','["粉席秋期緩，針樓別怨多。奔龍爭度日，飛鵲亂填河。", "失喜先臨鏡，含羞未解羅。誰能留夜色，來夕倍還梭。"]'),
('yuding-31','雜詩三首','沈佺期','唐','御定全唐诗','yuding','','[]','落葉驚秋婦，高砧促暝機。蜘蛛尋月度，螢火傍人飛。',144,'御定全唐詩/json/096.json','["落葉驚秋婦，高砧促暝機。蜘蛛尋月度，螢火傍人飛。", "清鏡紅埃入，孤燈綠焰微。怨啼能至曉，獨自懶縫衣。", "妾家臨渭北，春夢著遼西。何苦朝鮮郡，年年事鼓鼙。", "燕來紅壁語，鶯向綠窗啼。為許長相憶，闌幹玉箸齊。", "聞道黃龍戍，頻年不解兵。可憐閨裏月，長在漢家營。", "少婦今春意，良人昨夜情。誰能將旗鼓，一為取龍城。"]'),
('yuding-32','剪綵','沈佺期','唐','御定全唐诗','yuding','','[]','宮女憐芳樹，裁花競早榮。寒依刀尺盡，春向綺羅生。',48,'御定全唐詩/json/096.json','["宮女憐芳樹，裁花競早榮。寒依刀尺盡，春向綺羅生。", "弱蒂盤絲發，香蕤結素成。纖枝幸不棄，長就玉階傾。"]'),
('yuding-33','和中書侍郎楊再思春夜宿直','沈佺期','唐','御定全唐诗','yuding','','[]','西禁青春滿，南端皓月微。千廬宵駕合，五夜曉鐘稀。',48,'御定全唐詩/json/096.json','["西禁青春滿，南端皓月微。千廬宵駕合，五夜曉鐘稀。", "星斗橫綸閣，天河度瑣闈。煙光章奏裏，紛向夕郎飛。"]'),
('yuding-34','和常州崔使君寒食夜','沈佺期','唐','御定全唐诗','yuding','','[]','聞道清明近，春闈向夕闌。行遊晝不厭，風物夜宜看。',48,'御定全唐詩/json/096.json','["聞道清明近，春闈向夕闌。行遊晝不厭，風物夜宜看。", "斗柄更初轉，梅香暗裏殘。無勞秉華燭，晴月在南端。"]'),
('yuding-35','和崔正諫登秋日早朝','沈佺期','唐','御定全唐诗','yuding','','[]','雞鳴朝謁滿，露白禁門秋。爽氣臨旌戟，朝光映冕旒。',48,'御定全唐詩/json/096.json','["雞鳴朝謁滿，露白禁門秋。爽氣臨旌戟，朝光映冕旒。", "河宗來獻寶，天子命焚裘。獨負池陽議，言從建禮遊。"]'),
('yuding-36','答寧處州書','沈佺期','唐','御定全唐诗','yuding','','[]','書報天中赦，人從海上聞。九泉開白日，六翮起青雲。',48,'御定全唐詩/json/096.json','["書報天中赦，人從海上聞。九泉開白日，六翮起青雲。", "質幸恩先貸，情孤枉未分。自憐涇渭別，誰與奏明君。"]'),
('yuding-37','李舍人山園送龐邵','沈佺期','唐','御定全唐诗','yuding','','[]','符傳有光輝，喧喧出帝畿。東鄰借山水，南陌駐驂騑。',48,'御定全唐詩/json/096.json','["符傳有光輝，喧喧出帝畿。東鄰借山水，南陌駐驂騑。", "握手涼風至，當歌秋日微。高幨去勿緩，人吏待霜威。"]'),
('yuding-38','送陸侍禦餘慶北使','沈佺期','唐','御定全唐诗','yuding','','[]','古人貴將命，之子出輶軒。受委當不辱，隨時敢贈言。',48,'御定全唐詩/json/096.json','["古人貴將命，之子出輶軒。受委當不辱，隨時敢贈言。", "朔途際遼海，春思繞轘轅。安得回白日，留歡盡綠樽。"]'),
('yuding-39','洛州蕭司兵謁兄還赴洛成禮','沈佺期','唐','御定全唐诗','yuding','','[]','棠棣日光輝，高襟應序歸。來成鴻雁聚，去作鳳凰飛。',48,'御定全唐詩/json/096.json','["棠棣日光輝，高襟應序歸。來成鴻雁聚，去作鳳凰飛。", "細草承輕傳，驚花慘別衣。灞亭春有酒，岐路惜芬菲。"]'),
('yuding-40','餞高唐州詢','沈佺期','唐','御定全唐诗','yuding','','[]','弱冠相知早，中年不見多。生涯在王事，客鬢各蹉跎。',48,'御定全唐詩/json/096.json','["弱冠相知早，中年不見多。生涯在王事，客鬢各蹉跎。", "良守初分嶽，嘉聲即潤河。還從漢闕下，傾耳聽中和。"]'),
('yuding-41','餞唐郎中洛陽令','沈佺期','唐','御定全唐诗','yuding','','[]','一台推往妙，三史佇來修。應宰鳧還集，辭郎雉少留。',48,'御定全唐詩/json/096.json','["一台推往妙，三史佇來修。應宰鳧還集，辭郎雉少留。", "郊筵乘落景，亭傳理殘秋。願以弦歌暇，芝蘭想舊遊。"]'),
('yuding-42','樂城白鶴寺','沈佺期','唐','御定全唐诗','yuding','','[]','碧海開龍藏，青雲起雁堂。潮聲迎法鼓，雨氣濕天香。',48,'御定全唐詩/json/096.json','["碧海開龍藏，青雲起雁堂。潮聲迎法鼓，雨氣濕天香。", "樹接前山暗，溪承瀑水涼。無言謫居遠，清淨得空王。"]'),
('yuding-43','游少林寺','沈佺期','唐','御定全唐诗','yuding','','[]','長歌游寶地，徙倚對珠林。雁塔風霜古，龍池歲月深。',48,'御定全唐詩/json/096.json','["長歌游寶地，徙倚對珠林。雁塔風霜古，龍池歲月深。", "紺園澄夕霽，碧殿下秋陰。歸路煙霞晚，山蟬處處吟。"]'),
('yuding-44','岳館','沈佺期','唐','御定全唐诗','yuding','','[]','洞壑仙人館，孤峰玉女台。空蒙朝氣合，窈窕夕陽開。',48,'御定全唐詩/json/096.json','["洞壑仙人館，孤峰玉女台。空蒙朝氣合，窈窕夕陽開。", "流澗含輕雨，虛岩應薄雷。正逢鸞與鶴，歌舞出天來。"]'),
('yuding-45','早發平昌島','沈佺期','唐','御定全唐诗','yuding','','[]','解纜春風後，鳴榔曉漲前。陽烏出海樹，雲雁下江煙。',48,'御定全唐詩/json/096.json','["解纜春風後，鳴榔曉漲前。陽烏出海樹，雲雁下江煙。", "積氣沖長島，浮光溢大川。不能懷魏闕，心賞獨泠然。"]'),
('yuding-46','夜宿七盤嶺','沈佺期','唐','御定全唐诗','yuding','','[]','獨遊千裏外，高臥七盤西。曉月臨窗近，天河入戶低。',48,'御定全唐詩/json/096.json','["獨遊千裏外，高臥七盤西。曉月臨窗近，天河入戶低。", "芳春平仲綠，清夜子規啼。浮客空留聽，褒城聞曙雞。"]'),
('yuding-47','十三四時嘗從巫峽過他日偶然有思','沈佺期','唐','御定全唐诗','yuding','','[]','小度巫山峽，荊南春欲分。使君灘上草，神女館前雲。',48,'御定全唐詩/json/096.json','["小度巫山峽，荊南春欲分。使君灘上草，神女館前雲。", "樹悉江中見，猿多天外聞。別來如夢裏，一想一氛氳。"]'),
('yuding-48','初達驩州','沈佺期','唐','御定全唐诗','yuding','','[]','自昔聞銅柱，行來向一年。不知林邑地，猶隔道明天。',48,'御定全唐詩/json/096.json','["自昔聞銅柱，行來向一年。不知林邑地，猶隔道明天。", "雨露何時及，京華若個邊。思君無限淚，堪作日南泉。"]'),
('yuding-49','嶺表逢寒食','沈佺期','唐','御定全唐诗','yuding','','[]','嶺外無寒食，春來不見餳。洛陽新甲子，何日是清明。',48,'御定全唐詩/json/096.json','["嶺外無寒食，春來不見餳。洛陽新甲子，何日是清明。", "花柳爭朝發，軒車滿路迎。帝鄉遙可念，腸斷報親情。"]'),
('yuding-50','驩州南亭夜望','沈佺期','唐','御定全唐诗','yuding','','[]','昨夜南亭望，分明夢洛中。室家誰道別，兒女案嘗同。',48,'御定全唐詩/json/096.json','["昨夜南亭望，分明夢洛中。室家誰道別，兒女案嘗同。", "忽覺猶言是，沉思始悟空。肝腸餘幾寸，拭淚坐春風。"]'),
('yuding-51','少游荊湘因有是題','沈佺期','唐','御定全唐诗','yuding','','[]','峴北焚蛟浦，巴東射雉田。歲時宜楚俗，耆舊在襄川。',48,'御定全唐詩/json/096.json','["峴北焚蛟浦，巴東射雉田。歲時宜楚俗，耆舊在襄川。", "憶昨經過處，離今二十年。因君訪生死，相識幾人全。"]'),
('yuding-52','咸陽覽古','沈佺期','唐','御定全唐诗','yuding','','[]','咸陽秦帝居，千載坐盈虛。版築林光盡，壇場溜聽疏。',48,'御定全唐詩/json/096.json','["咸陽秦帝居，千載坐盈虛。版築林光盡，壇場溜聽疏。", "野橋疑望日，山火類焚書。唯有驪峰在，空聞厚葬餘。"]'),
('yuding-53','覽鏡','沈佺期','唐','御定全唐诗','yuding','','[]','霏霏日搖蕙，騷騷風灑蓮。時芳固相奪，俗態豈恒堅。',48,'御定全唐詩/json/096.json','["霏霏日搖蕙，騷騷風灑蓮。時芳固相奪，俗態豈恒堅。", "恍忽夜川裏，蹉跎朝鏡前。紅顏與壯志，太息此流年。"]'),
('yuding-54','題椰子樹','沈佺期','唐','御定全唐诗','yuding','','[]','日南椰子樹，香嫋出風塵。叢生調木首，圓實檳榔身。',48,'御定全唐詩/json/096.json','["日南椰子樹，香嫋出風塵。叢生調木首，圓實檳榔身。", "玉房九霄露，碧葉四時春。不及塗林果，移根隨漢臣。"]'),
('yuding-55','同獄者歎獄中無燕','沈佺期','唐','御定全唐诗','yuding','','[]','何許乘春燕，多知辨夏台。三時欲並盡，雙影未嘗來。',48,'御定全唐詩/json/096.json','["何許乘春燕，多知辨夏台。三時欲並盡，雙影未嘗來。", "食蕊嫌叢棘，銜泥怯死灰。不如黃雀語，能雪冶長猜。"]'),
('yuding-56','則天門赦改年','沈佺期','唐','御定全唐诗','yuding','','[]','聖人宥天下，幽鑰動圜狴。六甲迎黃氣，三元降紫泥。',48,'御定全唐詩/json/096.json','["聖人宥天下，幽鑰動圜狴。六甲迎黃氣，三元降紫泥。", "籠僮上西鼓，振迅廣陽雞。歌舞將金帛，汪洋被遠黎。"]'),
('yuding-57','喜赦','沈佺期','唐','御定全唐诗','yuding','','[]','去歲投荒客，今春肆眚歸。律通幽谷暖，盆舉太陽輝。',48,'御定全唐詩/json/096.json','["去歲投荒客，今春肆眚歸。律通幽谷暖，盆舉太陽輝。", "喜氣迎冤氣，青衣報白衣。還將合浦葉，俱向洛城飛。"]'),
('yuding-58','秦州薛都督挽詞','沈佺期','唐','御定全唐诗','yuding','','[]','十裏絳山幽，千年汾水流。碑傳門客建，劍是故人留。',48,'御定全唐詩/json/096.json','["十裏絳山幽，千年汾水流。碑傳門客建，劍是故人留。", "隴樹煙含夕，山門月對秋。古來鐘鼎盛，共盡一蒿丘。"]'),
('yuding-59','天官崔侍郎夫人盧氏挽歌','沈佺期','唐','御定全唐诗','yuding','','[]','偕老言何謬，香魂事永違。潘魚從此隔，陳鳳宛然飛。',48,'御定全唐詩/json/096.json','["偕老言何謬，香魂事永違。潘魚從此隔，陳鳳宛然飛。", "埋鏡泉中暗，藏鐙地下微。猶憑少君術，仿佛睹容輝。"]'),
('yuding-60','章懷太子靖妃挽詞','沈佺期','唐','御定全唐诗','yuding','','[]','彤史佳聲載，青宮懿範留。形將鸞鏡隱，魂伴鳳笙遊。',48,'御定全唐詩/json/096.json','["彤史佳聲載，青宮懿範留。形將鸞鏡隱，魂伴鳳笙遊。", "送馬嘶殘日，新螢落晚秋。不知蒿裏曙，空見隴雲愁。"]'),
('yuding-61','奉和立春遊苑迎春','沈佺期','唐','御定全唐诗','yuding','','[]','東郊暫轉迎春仗，上苑初飛行慶杯。風射蛟冰千片斷，',40,'御定全唐詩/json/096.json','["東郊暫轉迎春仗，上苑初飛行慶杯。風射蛟冰千片斷，", "歌吹銜恩歸路晚，棲烏半下鳳城來。"]'),
('yuding-62','人日重宴大明宮賜彩縷人勝應制','沈佺期','唐','御定全唐诗','yuding','','[]','拂旦雞鳴仙衛陳，憑高龍首帝城春。千官黼帳杯前壽，',40,'御定全唐詩/json/096.json','["拂旦雞鳴仙衛陳，憑高龍首帝城春。千官黼帳杯前壽，", "天文正應韶光轉，設報懸知用此辰。"]'),
('yuding-63','奉和春初幸太平公主南莊應制','沈佺期','唐','御定全唐诗','yuding','','[]','主家山第早春歸，禦輦春遊繞翠微。買地鋪金曾作埒，',40,'御定全唐詩/json/096.json','["主家山第早春歸，禦輦春遊繞翠微。買地鋪金曾作埒，", "自有神仙鳴鳳曲，並將歌舞報恩暉。"]'),
('yuding-64','奉和春日幸望春宮應制','沈佺期','唐','御定全唐诗','yuding','','[]','芳郊綠野散春晴，複道離宮煙霧生。楊柳千條花欲綻，',40,'御定全唐詩/json/096.json','["芳郊綠野散春晴，複道離宮煙霧生。楊柳千條花欲綻，", "定是風光牽宿醉，來晨複得幸昆明。"]'),
('yuding-65','侍宴安樂公主新宅應制','沈佺期','唐','御定全唐诗','yuding','','[]','皇家貴主好神仙，別業初開雲漢邊。山出盡如鳴鳳嶺，',40,'御定全唐詩/json/096.json','["皇家貴主好神仙，別業初開雲漢邊。山出盡如鳴鳳嶺，", "敬從乘輿來此地，稱觴獻壽樂鈞天。"]'),
('yuding-66','龍池篇','沈佺期','唐','御定全唐诗','yuding','','[]','龍池躍龍龍已飛，龍德先天天不違。池開天漢分黃道，',40,'御定全唐詩/json/096.json','["龍池躍龍龍已飛，龍德先天天不違。池開天漢分黃道，", "為報寰中百川水，來朝此地莫東歸。"]'),
('yuding-67','興慶池侍宴應制','沈佺期','唐','御定全唐诗','yuding','','[]','碧水澄潭映遠空，紫雲香駕禦微風。漢家城闕疑天上，',40,'御定全唐詩/json/096.json','["碧水澄潭映遠空，紫雲香駕禦微風。漢家城闕疑天上，", "古來徒羨橫汾賞，今日宸遊聖藻雄。"]'),
('yuding-68','從幸香山寺應制','沈佺期','唐','御定全唐诗','yuding','','[]','南山奕奕通丹禁，北闕峨峨連翠雲。嶺上樓臺千地起，',40,'御定全唐詩/json/096.json','["南山奕奕通丹禁，北闕峨峨連翠雲。嶺上樓臺千地起，", "願以醍醐參聖酒，還將祇苑當秋汾。"]'),
('yuding-69','紅樓院應制','沈佺期','唐','御定全唐诗','yuding','','[]','紅樓疑見白毫光，寺逼宸居福盛唐。支遁愛山情謾切，',40,'御定全唐詩/json/096.json','["紅樓疑見白毫光，寺逼宸居福盛唐。支遁愛山情謾切，", "誰謂此中難可到，自憐深院得徊翔。"]'),
('yuding-70','再入道場紀事應制','沈佺期','唐','御定全唐诗','yuding','','[]','南方歸去再生天，內殿今年異昔年。見辟乾坤新定位，',40,'御定全唐詩/json/096.json','["南方歸去再生天，內殿今年異昔年。見辟乾坤新定位，", "自喜恩深陪侍從，兩朝長在聖人前。"]'),
('yuding-71','嵩山石淙侍宴應制','沈佺期','唐','御定全唐诗','yuding','','[]','金輿旦下綠雲衢，彩殿晴臨碧澗隅。溪水泠泠雜行漏，',40,'御定全唐詩/json/096.json','["金輿旦下綠雲衢，彩殿晴臨碧澗隅。溪水泠泠雜行漏，", "自惜汾陽紆道駕，無如太室覽真圖。"]'),
('yuding-72','古意呈補闕喬知之','沈佺期','唐','御定全唐诗','yuding','','[]','盧家少婦郁金堂，海燕雙棲玳瑁梁。九月寒砧催木葉，',40,'御定全唐詩/json/096.json','["盧家少婦郁金堂，海燕雙棲玳瑁梁。九月寒砧催木葉，", "誰謂含愁獨不見，更教明月照流黃。"]'),
('yuding-73','遙同杜員外審言過嶺','沈佺期','唐','御定全唐诗','yuding','','[]','天長地闊嶺頭分，去國離家見白雲。洛浦風光何所似，',40,'御定全唐詩/json/096.json','["天長地闊嶺頭分，去國離家見白雲。洛浦風光何所似，", "兩地江山萬餘裏，何時重謁聖明君。"]'),
('yuding-74','和上巳連寒食有懷京洛','沈佺期','唐','御定全唐诗','yuding','','[]','天津禦柳碧遙遙，軒騎相從半下朝。行樂光輝寒食借，',40,'御定全唐詩/json/096.json','["天津禦柳碧遙遙，軒騎相從半下朝。行樂光輝寒食借，", "坐見司空掃西第，看君侍從落花朝。"]'),
('yuding-75','陪幸太平公主南莊詩','沈佺期','唐','御定全唐诗','yuding','','[]','主第山門起灞川，宸游風景入初年。鳳凰樓下交天仗，',40,'御定全唐詩/json/096.json','["主第山門起灞川，宸游風景入初年。鳳凰樓下交天仗，", "今朝扈蹕平陽館，不羨乘槎雲漢邊。"]'),
('yuding-76','守歲應制','沈佺期','唐','御定全唐诗','yuding','','[]','南渡輕冰解渭橋，東方樹色起招搖。天子迎春取今夜，',40,'御定全唐詩/json/096.json','["南渡輕冰解渭橋，東方樹色起招搖。天子迎春取今夜，", "宜將歲酒調神藥，聖祚千春萬國朝。"]'),
('yuding-0','陪幸韋嗣立山莊','沈佺期','唐','御定全唐诗','yuding','','[]','臺階好赤松，別業對青峰。茆室承三顧，花源接九重。',96,'御定全唐詩/json/097.json','["臺階好赤松，別業對青峰。茆室承三顧，花源接九重。", "虹旗縈秀木，鳳輦拂疏筇。徑直千官擁，溪長萬騎容。", "水堂開禹膳，山閣獻堯鐘。皇鑒清居遠，天文睿獎濃。", "岩泉他夕夢，漁釣往年逢。共榮丞相府，偏降逸人封。"]'),
('yuding-1','扈從出長安應制','沈佺期','唐','御定全唐诗','yuding','','[]','漢宅規模壯，周都景命隆。西賓讓東主，法駕幸天中。',132,'御定全唐詩/json/097.json','["漢宅規模壯，周都景命隆。西賓讓東主，法駕幸天中。", "太史占星應，春官奏日同。旌門起長樂，帳殿出新豐。", "翕習黃山下，紆徐清渭東。金麾張畫月，珠幰戴松風。", "是節嚴陰始，寒郊散野蓬。薄霜沾上路，殘雪繞離宮。", "賜帛矜耆老，褰旒問小童。複除恩載洽，望秩禮新崇。", "臣忝承明召，多慚獻賦雄。"]'),
('yuding-2','初冬從幸漢故青門應制','沈佺期','唐','御定全唐诗','yuding','','[]','漢王建都邑，渭水對青門。朝市俱東逝，墳陵共北原。',120,'御定全唐詩/json/097.json','["漢王建都邑，渭水對青門。朝市俱東逝，墳陵共北原。", "荒涼蕭相闕，蕪沒邵平園。全盛今何在，英雄難重論。", "故基仍嶽立，遺堞尚雲屯。當極土功壯，安知人力煩。", "天遊戒東首，懷昔駐龍軒。何必金湯固，無如道德藩。", "微臣諒多幸，參乘偶殊恩。預此陳古事，敢奏興亡言。"]'),
('yuding-3','昆明池侍宴應制','沈佺期','唐','御定全唐诗','yuding','','[]','武帝伐昆明，穿池習五兵。水同河漢在，館有豫章名。',96,'御定全唐詩/json/097.json','["武帝伐昆明，穿池習五兵。水同河漢在，館有豫章名。", "我後光天德，垂衣文教成。黷兵非帝念，勞物豈皇情。", "春仗過鯨沼，雲旗出鳳城。靈魚銜寶躍，仙女廢機迎。", "柳拂旌門暗，蘭依帳殿生。還如流水曲，日晚棹歌清。"]'),
('yuding-4','白蓮花亭侍宴應制','沈佺期','唐','御定全唐诗','yuding','','[]','九日陪天仗，三秋幸禁林。霜威變綠樹，雲氣落青岑。',72,'御定全唐詩/json/097.json','["九日陪天仗，三秋幸禁林。霜威變綠樹，雲氣落青岑。", "水殿黃花合，山亭絳葉深。朱旗夾小徑，寶馬駐清潯。", "苑吏收寒果，饔人膳野禽。承歡不覺暝，遙響素秋砧。"]'),
('yuding-5','仙萼池亭侍宴應制','沈佺期','唐','御定全唐诗','yuding','','[]','步輦尋丹嶂，行宮在翠微。川長看鳥滅，穀轉聽猿稀。',72,'御定全唐詩/json/097.json','["步輦尋丹嶂，行宮在翠微。川長看鳥滅，穀轉聽猿稀。", "天磴扶階迥，雲泉透戶飛。閑花開石竹，幽葉吐薔薇。", "徑狹難留騎，亭寒欲進衣。白龜來獻壽，仙吹返彤闈。"]'),
('yuding-6','奉和晦日駕幸昆明池應制','沈佺期','唐','御定全唐诗','yuding','','[]','法駕乘春轉，神池象漢回。雙星移舊石，孤月隱殘灰。',72,'御定全唐詩/json/097.json','["法駕乘春轉，神池象漢回。雙星移舊石，孤月隱殘灰。", "戰鷁逢時去，恩魚望幸來。山花緹綺繞，堤柳幔城開。", "思逸橫汾唱，歡留宴鎬杯。微臣雕朽質，羞睹豫章材。"]'),
('yuding-7','奉和聖制幸禮部尚書竇希玠宅','沈佺期','唐','御定全唐诗','yuding','','[]','北闕垂旒暇，南宮聽履回。天臨翔鳳轉，恩向躍龍開。',72,'御定全唐詩/json/097.json','["北闕垂旒暇，南宮聽履回。天臨翔鳳轉，恩向躍龍開。", "蘭氣熏仙帳，榴花引禦杯。水從金穴吐，雲是玉衣來。", "池影搖歌席，林香散舞臺。不知行漏晚，清蹕尚裴徊。"]'),
('yuding-8','釣竿篇','沈佺期','唐','御定全唐诗','yuding','','[]','朝日斂紅煙，垂竿向綠川。人疑天上坐，魚似鏡中懸。',72,'御定全唐詩/json/097.json','["朝日斂紅煙，垂竿向綠川。人疑天上坐，魚似鏡中懸。", "避楫時驚透，猜鉤每誤牽。湍危不理轄，潭靜欲留船。", "釣玉君徒尚，征金我未賢。為看芳餌下，貪得會無筌。"]'),
('yuding-9','和戶部岑尚書參跡樞揆','沈佺期','唐','御定全唐诗','yuding','','[]','大君制六合，良佐參萬機。大業永開泰，臣道日光輝。',120,'御定全唐詩/json/097.json','["大君制六合，良佐參萬機。大業永開泰，臣道日光輝。", "鹽梅和鼎食，家聲眾所歸。漢章題楚劍，鄭武襲緇衣。", "理識當朝遠，文華振古希。風雲神契合，舟楫道心微。", "廟堂喜容與，時物遞芳菲。禦柳垂仙掖，公槐覆禮闈。", "昔陪鵷鷺後，今望鶤鵬飛。徒禦清風頌，巴歌聊自揮。"]'),
('yuding-10','同李舍人冬日集安樂公主山池','沈佺期','唐','御定全唐诗','yuding','','[]','嘗聞天女貴，家即帝宮連。亭插宜春果，山沖太液泉。',96,'御定全唐詩/json/097.json','["嘗聞天女貴，家即帝宮連。亭插宜春果，山沖太液泉。", "橋低烏鵲夜，台起鳳凰年。故事猶如此，新圖更可憐。", "紫岩妝閣透，青嶂妓樓懸。峰奪香爐巧，池偷明鏡圓。", "梅花寒待雪，桂葉晚留煙。興盡方投轄，金聲還複傳。"]'),
('yuding-11','酬蘇員外味道夏晚寓直省中見贈','沈佺期','唐','御定全唐诗','yuding','','[]','並命登仙閣，分曹直禮闈。大官供宿膳，侍史護朝衣。',72,'御定全唐詩/json/097.json','["並命登仙閣，分曹直禮闈。大官供宿膳，侍史護朝衣。", "卷幔天河入，開窗月露微。小池殘暑退，高樹早涼歸。", "冠劍無時釋，軒車待漏飛。明朝題漢柱，三署有光輝。"]'),
('yuding-12','和韋舍人早朝','沈佺期','唐','御定全唐诗','yuding','','[]','閶闔連雲起，岩廊拂霧開。玉珂龍影度，珠履雁行來。',72,'御定全唐詩/json/097.json','["閶闔連雲起，岩廊拂霧開。玉珂龍影度，珠履雁行來。", "長樂宵鐘盡，明光曉奏催。一經推舊德，五字擢英才。", "儼若神仙去，紛從霄漢回。千春奉休曆，分禁喜趨陪。"]'),
('yuding-13','自考功員外授給事中','沈佺期','唐','御定全唐诗','yuding','','[]','南省推丹地，東曹拜瑣闈。惠移雙管筆，恩降五時衣。',120,'御定全唐詩/json/097.json','["南省推丹地，東曹拜瑣闈。惠移雙管筆，恩降五時衣。", "出入宜真選，遭逢每濫飛。器慚公理拙，才謝子雲微。", "案牘遺常禮，朋僚隔等威。上臺行揖讓，中禁動光輝。", "旭日千門起，初春八舍歸。贈蘭聞宿昔，談樹隱芳菲。", "何幸鹽梅處，唯憂對問機。省躬知任重，甯止冒榮非。"]'),
('yuding-14','和元舍人萬頃臨池玩月戲為新體','沈佺期','唐','御定全唐诗','yuding','','[]','春風搖碧樹，秋霧卷丹台。複有相宜夕，池清月正開。',120,'御定全唐詩/json/097.json','["春風搖碧樹，秋霧卷丹台。複有相宜夕，池清月正開。", "玉流含吹動，金魄度雲來。熠爚光如沸，翩翾景若摧。", "半環投積草，碎璧聚流杯。夜久平無煥，天晴皎未隤。", "鏡將池作匣，珠以岸為胎。有美司言暇，高興獨悠哉。", "揮翰初難擬，飛名豈易陪。夜光殊在握，了了見沉灰。"]'),
('yuding-15','酬楊給事兼見贈台中','沈佺期','唐','御定全唐诗','yuding','','[]','子雲推辨博，公理擅詞雄。始自尚書省，旋聞給事中。',96,'御定全唐詩/json/097.json','["子雲推辨博，公理擅詞雄。始自尚書省，旋聞給事中。", "言從溫室秘，籍向瑣闈通。顧我叨郎署，慚無草奏功。", "分曹八舍斷，解袂五時空。宿昔陪餘論，平生賴擊蒙。", "神仙應東掖，雲霧限南宮。忽枉瓊瑤贈，長歌蘭渚風。"]'),
('yuding-16','九真山淨居寺謁無礙上人','沈佺期','唐','御定全唐诗','yuding','','[]','大士生天竺，分身化日南。人中出煩惱，山下即伽藍。',120,'御定全唐詩/json/097.json','["大士生天竺，分身化日南。人中出煩惱，山下即伽藍。", "小澗香為刹，危峰石作龕。候禪青鴿乳，窺講白猿參。", "藤愛雲間壁，花憐石下潭。泉行幽供好，林掛浴衣堪。", "弟子哀無識，醫王惜未談。機疑聞不二，蒙昧即朝三。", "欲究因緣理，聊寬放棄慚。超然虎溪夕，雙樹下虛嵐。"]'),
('yuding-17','夜遊','沈佺期','唐','御定全唐诗','yuding','','[]','今夕重門啟，遊春得夜芳。月華連晝色，燈影雜星光。',72,'御定全唐詩/json/097.json','["今夕重門啟，遊春得夜芳。月華連晝色，燈影雜星光。", "南陌青絲騎，東鄰紅粉妝。管弦遙辨曲，羅綺暗聞香。", "人擁行歌路，車攢鬥舞場。經過猶未已，鐘鼓出長楊。"]'),
('yuding-18','登瀛州南城樓寄遠','沈佺期','唐','御定全唐诗','yuding','','[]','層城起麗譙，憑覽出重霄。茲地多形勝，中天宛寂寥。',84,'御定全唐詩/json/097.json','["層城起麗譙，憑覽出重霄。茲地多形勝，中天宛寂寥。", "四榮摩鸛鶴，百拱厲風飆。北際燕王館，東連秦帝橋。", "晴光七郡滿，春色兩河遙。傲睨非吾土，躊躇適遠囂。", "離居欲有贈，春草寄長謠。"]'),
('yuding-19','塞北二首','沈佺期','唐','御定全唐诗','yuding','','[]','虜障天驕起，秦城地脈分。柏壇飛五將，梅吹動三軍。',192,'御定全唐詩/json/097.json','["虜障天驕起，秦城地脈分。柏壇飛五將，梅吹動三軍。", "鋒刃奔濤色，旌旗焰火文。朔風吹汗漫，飄礫灑轒轀。", "海氣如秋雨，邊峰似夏雲。二庭無歲月，百戰有功勳。", "形影隨魚貫，音書在雁群。歸來拜天子，凱樂助南熏。", "胡騎犯邊埃，風從醜上來。五原烽火急，六郡羽書催。", "冰壯飛狐冷，霜濃候雁哀。將軍朝授鉞，戰士夜銜枚。", "紫塞金河裏，蔥山鐵勒隈。蓮花秋劍發，桂葉曉旗開。", "秘略三軍動，妖氛百戰摧。何言投筆去，終作勒銘回。"]'),
('yuding-20','李員外秦援宅觀妓','沈佺期','唐','御定全唐诗','yuding','','[]','盈盈粉署郎，五日宴春光。選客虛前館，征聲遍後堂。',72,'御定全唐詩/json/097.json','["盈盈粉署郎，五日宴春光。選客虛前館，征聲遍後堂。", "玉釵翠羽飾，羅袖鬱金香。拂黛隨時廣，挑鬟出意長。", "囀歌遙合態，度舞暗成行。巧落梅庭裏，斜光映曉妝。"]'),
('yuding-21','送韋商州弼','沈佺期','唐','御定全唐诗','yuding','','[]','會府應文昌，商山鎮國陽。聞君監郡史，暫罷尚書郎。',72,'御定全唐詩/json/097.json','["會府應文昌，商山鎮國陽。聞君監郡史，暫罷尚書郎。", "王事嗟相失，人情貴不忘。累年同畫省，四海接文場。", "點翰芳春色，傳杯明月光。故交從此去，遙憶紫芝香。"]'),
('yuding-22','夏日梁王席送張岐州','沈佺期','唐','御定全唐诗','yuding','','[]','秦雞常下雍，周鳳昔鳴岐。此地推雄撫，惟良寄在斯。',96,'御定全唐詩/json/097.json','["秦雞常下雍，周鳳昔鳴岐。此地推雄撫，惟良寄在斯。", "家傳七豹貴，人擅八龍奇。高傳生光彩，長林歎別離。", "天人開祖席，朝寀候征麾。翠帟當郊敞，彤幨向野披。", "芃芃秋麥盛，苒苒夏條垂。奏計何時入，臺階望羽儀。"]'),
('yuding-23','夏日都門送司馬員外逸客孫員外佺北征','沈佺期','唐','御定全唐诗','yuding','','[]','二庭追虜騎，六月動周師。廟略天人授，軍麾相國持。',72,'御定全唐詩/json/097.json','["二庭追虜騎，六月動周師。廟略天人授，軍麾相國持。", "複言征二妙，才命重當時。畫省連征橐，橫門共別詞。", "雲迎出塞馬，風卷度河旗。計日方夷寇，旋聞杕杜詩。"]'),
('yuding-24','送盧管記仙客北伐','沈佺期','唐','御定全唐诗','yuding','','[]','羽檄西北飛，交城日夜圍。廟堂盛征選，戎幕生光輝。',72,'御定全唐詩/json/097.json','["羽檄西北飛，交城日夜圍。廟堂盛征選，戎幕生光輝。", "雁行度函谷，馬首向金微。湛湛山川暮，蕭蕭涼氣稀。", "餞途予憫默，赴敵子英威。今日楊朱淚，無將灑鐵衣。"]'),
('yuding-25','移禁司刑','沈佺期','唐','御定全唐诗','yuding','','[]','疇昔參鄉賦，中年忝吏途。丹唇曾學史，白首不成儒。',288,'御定全唐詩/json/097.json','["疇昔參鄉賦，中年忝吏途。丹唇曾學史，白首不成儒。", "天子開昌籙，群生偶大爐。散材仍葺廈，弱羽遽摶扶。", "寵邁乘軒鶴，榮過食稻鳧。何功游畫省，何德理黃樞。", "吊影慚非據，傾心事遠圖。盜泉寧止渴，惡木匪投軀。", "任直翻多毀，安身遂少徒。一朝逢糾謬，三省竟無虞。", "白簡初心屈，黃紗始望孤。患平終不怒，持劾每相驅。", "埋劍誰當辨，偷金以自誣。誘言雖委答，流議亦真符。", "首夏方憂圄，高秋獨向隅。嚴城看熠耀，圜戶對蜘蛛。", "累餉唯妻子，披冤是友于。物情牽倚伏，人事限榮枯。", "門客心誰在，鄰交跡倘無。撫襟雙涕落，危坐日憂趨。", "聖旨垂明德，冤囚豈濫誅。會希恩免理，終望罪矜愚。", "司寇宜哀獄，台庭幸恤辜。漢皇虛詔上，容有報恩珠。"]'),
('yuding-26','入鬼門關','沈佺期','唐','御定全唐诗','yuding','','[]','昔傳瘴江路，今到鬼門關。土地無人老，流移幾客還。',72,'御定全唐詩/json/097.json','["昔傳瘴江路，今到鬼門關。土地無人老，流移幾客還。", "自從別京洛，頹鬢與衰顏。夕宿含沙裏，晨行岡路間。", "馬危千仞穀，舟險萬重灣。問我投何地，西南盡百蠻。"]'),
('yuding-27','三日獨坐驩州思憶舊游','沈佺期','唐','御定全唐诗','yuding','','[]','兩京多節物，三日最遨遊。麗日風徐卷，香塵雨暫收。',204,'御定全唐詩/json/097.json','["兩京多節物，三日最遨遊。麗日風徐卷，香塵雨暫收。", "紅桃初下地，綠柳半垂溝。童子成春服，宮人罷射韝。", "禊堂通漢苑，解席繞秦樓。束皙言談妙，張華史漢遒。", "無亭不駐馬，何浦不橫舟。舞鑰千門度，帷屏百道流。", "金丸向鳥落，芳餌接魚投。濯穢憐清淺，迎祥樂獻酬。", "靈芻陳欲棄，神藥曝應休。誰念招魂節，翻為禦魅囚。", "朋從天外盡，心賞日南求。銅柱威丹徼，朱崖鎮火陬。", "炎蒸連曉夕，瘴癘滿冬秋。西水何時貸，南方詎可留。", "無人對爐酒，寧緩去鄉憂。"]'),
('yuding-28','從驩州廨宅移住山間水亭贈蘇使君','沈佺期','唐','御定全唐诗','yuding','','[]','遇坎即乘流，西南到火洲。鬼門應苦夜，瘴浦不宜秋。',168,'御定全唐詩/json/097.json','["遇坎即乘流，西南到火洲。鬼門應苦夜，瘴浦不宜秋。", "歲貸胸穿老，朝飛鼻飲頭。死生離骨肉，榮辱間朋遊。", "棄置一身在，平生萬事休。鷹鸇遭誤逐，豺虎怯真投。", "憶昨京華子，傷今邊地囚。願陪鸚鵡樂，希並鷓鴣留。", "日月渝鄉思，煙花換客愁。幸逢蘇伯玉，回借水亭幽。", "山柏張青蓋，江蕉卷綠油。乘閑無火宅，因放有漁舟。", "適越心當是，居夷跡可求。古來堯禪舜，何必罪驩兜。"]'),
('yuding-29','赦到不得歸題江上石','沈佺期','唐','御定全唐诗','yuding','','[]','家住東京裏，身投南海西。風煙萬里隔，朝夕幾行啼。',288,'御定全唐詩/json/097.json','["家住東京裏，身投南海西。風煙萬里隔，朝夕幾行啼。", "聖主謳歌洽，賢臣法令齊。忽聞銅柱使，走馬報金雞。", "棄市沾皇渥，投荒漏紫泥。魂疲山鶴路，心醉跕鳶溪。", "天鑒誅元惡，宸慈恤遠黎。五方思寄刃，萬姓喜然臍。", "自幼輸丹懇，何嘗玷白圭。承言竄遐魅，雪枉間深狴。", "墳壟無由謁，京華豈重躋。炎方誰謂廣，地盡覺天低。", "百卉雜殊怪，昆蟲理賴暌。閉藏元不蟄，搖落反生荑。", "瘧瘴因茲苦，窮愁益複迷。火雲蒸毒霧，陽雨濯陰霓。", "周乘安交趾，王恭輯畫題。少寬窮涸鮒，猶湣觸藩羝。", "配宅鄰州廨，斑苗接野畦。山空聞鬥象，江靜見遊犀。", "翰墨思諸季，裁縫憶老妻。小兒應離褓，幼女未攀笄。", "夢蝶翻無定，蓍龜詎有倪。誰能竟此曲，曲盡氣酸嘶。"]'),
('yuding-30','答魑魅代書寄家人','沈佺期','唐','御定全唐诗','yuding','','[]','魑魅來相問，君何失帝鄉。龍鍾辭北闕，蹭蹬守南荒。',577,'御定全唐詩/json/097.json','["魑魅來相問，君何失帝鄉。龍鍾辭北闕，蹭蹬守南荒。", "覽鏡憐雙鬢，沾衣惜萬行。抱愁那去國，將老更垂裳。", "影答餘他歲，恩私宦洛陽。三春給事省，五載尚書郎。", "黃閣遊鸞署，青縑禦史香。扈巡行太液，陪宴坐明光。", "渭北升高苑，河南祓禊場。煙花恒獻賦，泉石每稱觴。", "暇日從休浣，高車映道傍。迎賓就丞相，選士謁昭王。", "侍寵言猶得，承歡謂不忘。一朝貽厚譴，五宅竟同防。", "凶豎曾驅策，權豪豈易當。款顏因侍從，接武在文章。", "且懼威非rP，寧知心是狼。身猶納履誤，情為覆盆傷。", "可歎緣成業，非關行昧藏。喜逢今改旦，正朔複歸唐。", "河讖隨龍馬，天書逐鳳凰。朝容欣舊則，宸化美初綱。", "告善雕旌建，收冤錦旆張。宰臣更獻納，郡守各明揚。", "禮樂移三統，舟車會八方。雲沙降白遂，秦隴獻燒當。", "三赦重天造，千推極國詳。大招思複楚，於役限維桑。", "漲海緣真臘，崇山壓古棠。雕題飛棟宇，儋耳間衣裳。", "伏枕神餘劣，加餐力未強。空庭遊翡翠，窮巷倚桄榔。", "緣體分殊昔，回眸宛異常。吉凶恒委鄭，年壽會詢唐。", "家本傳清白，官移重掛床。上京無薄產，故里絕窮莊。", "碧玉先時費，蒼頭此自將。興言歎家口，何處待贏糧。", "計吏從都出，傳聞大小康。降除沾二弟，離拆已三房。", "劍外懸銷骨，荊南預斷腸。音塵黃耳間，夢想白眉良。", "複此單棲鶴，銜雛願遠翔。何堪萬里外，雲海已溟茫。", "戚屬甘胡越，聲名任秕糠。由來休憤命，命也信蒼蒼。", "獨坐尋周易，清晨詠老莊。此中因悟道，無問入倡狂。"]'),
('yuding-31','度安海入龍編','沈佺期','唐','御定全唐诗','yuding','','[]','我來交趾郡，南與貫胸連。四氣分寒少，三光置日偏。',120,'御定全唐詩/json/097.json','["我來交趾郡，南與貫胸連。四氣分寒少，三光置日偏。", "尉佗曾馭國，翁仲久遊泉。邑屋遺甿在，魚鹽舊產傳。", "越人遙捧翟，漢將下看鳶。北斗崇山掛，南風漲海牽。", "別離頻破月，容鬢驟催年。昆弟推由命，妻孥割付緣。", "夢來魂尚擾，愁委疾空纏。虛道崩城淚，明心不應天。"]'),
('yuding-32','從崇山向越常','沈佺期','唐','御定全唐诗','yuding','','[]','朝發崇山下，暮坐越常陰。西從杉穀度，北上竹溪深。',96,'御定全唐詩/json/097.json','["朝發崇山下，暮坐越常陰。西從杉穀度，北上竹溪深。", "竹溪道明水，杉谷古崇岑。差池將不合，繚繞複相尋。", "桂葉藏金嶼，藤花閉石林。天窗虛的的，雲竇下沉沉。", "造化功偏厚，真仙跡每臨。豈徒探怪異，聊欲緩歸心。"]'),
('yuding-33','哭蘇眉州崔司業二公','沈佺期','唐','御定全唐诗','yuding','','[]','渙汗天中發，伶俜海外旋。長沙遇太守，問舊幾人全。',216,'御定全唐詩/json/097.json','["渙汗天中發，伶俜海外旋。長沙遇太守，問舊幾人全。", "國寶亡雙傑，天才喪兩賢。大名齊弱歲，高德並中年。", "禮樂羊叔子，文章王仲宣。相看尚玄鬢，相次入黃泉。", "流放蠻陬闊，鄉關帝裏偏。親朋雲霧擁，生死歲時傳。", "崔昔揮宸翰，蘇嘗濟巨川。絳衣陪下列，黃閣謬差肩。", "及此俱冥昧，雲誰敘播遷。隼輿懷舊轍，鱣館想虛筵。", "家愛方休杵，皇慈更撤縣。銘旌西蜀路，騎吹北邙田。", "隴樹應秋矣，江帆故杳然。罷琴明月夜，留劍白雲天。", "涕泗湘潭水，淒涼衡嶠煙。古來修短分，神理竟難筌。"]'),
('yuding-34','哭道士劉無得','沈佺期','唐','御定全唐诗','yuding','','[]','聞有玄都客，成仙不易祈。蓬萊向清淺，桃杏欲芳菲。',96,'御定全唐詩/json/097.json','["聞有玄都客，成仙不易祈。蓬萊向清淺，桃杏欲芳菲。", "縮地黃泉出，升天白日飛。少微星夜落，高掌露朝晞。", "吐甲龍應出，銜符鳥自歸。國人思負局，天子惜被衣。", "花月留丹洞，琴笙閣翠微。嗟來子桑扈，爾獨返於幾。"]'),
('yuding-35','寒食','沈佺期','唐','御定全唐诗','yuding','','[]','普天皆滅焰，匝地盡藏煙。不知何處火，來就客心然。',24,'御定全唐詩/json/097.json','["普天皆滅焰，匝地盡藏煙。不知何處火，來就客心然。"]'),
('yuding-36','回波詞','沈佺期','唐','御定全唐诗','yuding','','[]','回波爾時佺期，流向嶺外生歸。',28,'御定全唐詩/json/097.json','["回波爾時佺期，流向嶺外生歸。", "身名已蒙齒錄，袍笏未複牙緋。"]'),
('yuding-37','上巳日祓禊渭濱應制','沈佺期','唐','御定全唐诗','yuding','','[]','寶馬香車清渭濱，紅桃碧柳禊堂春。',32,'御定全唐詩/json/097.json','["寶馬香車清渭濱，紅桃碧柳禊堂春。", "皇情尚憶垂竿佐，天祚先呈捧劍人。"]'),
('yuding-38','奉和幸韋嗣立山莊應制','沈佺期','唐','御定全唐诗','yuding','','[]','東山朝日翠屏開，北闕晴空彩仗來。',32,'御定全唐詩/json/097.json','["東山朝日翠屏開，北闕晴空彩仗來。", "喜遇天文七曜動，少微今夜近三台。"]'),
('yuding-39','夜宴安樂公主宅','沈佺期','唐','御定全唐诗','yuding','','[]','濯龍門外主家親，鳴鳳樓中天上人。',32,'御定全唐詩/json/097.json','["濯龍門外主家親，鳴鳳樓中天上人。", "自有金杯迎甲夜，還將綺席代陽春。"]'),
('yuding-40','苑中遇雪應制','沈佺期','唐','御定全唐诗','yuding','','[]','北闕彤雲掩曙霞，東風吹雪舞仙家。',32,'御定全唐詩/json/097.json','["北闕彤雲掩曙霞，東風吹雪舞仙家。", "瓊章定少千人和，銀樹長芳六出花。"]'),
('yuding-41','餞唐永昌','沈佺期','唐','御定全唐诗','yuding','','[]','洛陽舊有神明宰，輦轂由來天地中。',32,'御定全唐詩/json/097.json','["洛陽舊有神明宰，輦轂由來天地中。", "餘邑政成何足貴，因君取則四方同。"]'),
('yuding-42','獄中聞駕幸長安二首','沈佺期','唐','御定全唐诗','yuding','','[]','傳聞聖旨向秦京，誰念羈囚滯洛城。',64,'御定全唐詩/json/097.json','["傳聞聖旨向秦京，誰念羈囚滯洛城。", "扈從由來是方朔，為申冤氣在長平。", "無事今朝來下獄，誰期十月是橫河。", "君看鷹隼俱堪擊，為報蜘蛛收網羅。"]'),
('yuding-43','邙山','沈佺期','唐','御定全唐诗','yuding','','[]','北邙山上列墳塋，萬古千秋對洛城。',32,'御定全唐詩/json/097.json','["北邙山上列墳塋，萬古千秋對洛城。", "城中日夕歌鐘起，山上唯聞松柏聲。"]'),
('yuding-44','句','沈佺期','唐','御定全唐诗','yuding','','[]','周原五稼起，雲海百川歸。願此零陵燕，長隨征旆飛。',24,'御定全唐詩/json/097.json','["周原五稼起，雲海百川歸。願此零陵燕，長隨征旆飛。"]'),
('yuding-0','陪張燕公登南樓','趙冬曦','唐','御定全唐诗','yuding','','[]','抑鬱何以歡，陰氛亦登望。孤島輕霧裏，行舟白波上。',48,'御定全唐詩/json/098.json','["抑鬱何以歡，陰氛亦登望。孤島輕霧裏，行舟白波上。", "目勞西北雲，心醉東南嶂。昔日青溪子，胡然此無狀。"]'),
('yuding-1','酬燕公出湖見寄','趙冬曦','唐','御定全唐诗','yuding','','[]','綸綍有成命，旌麾不可攀。湘川朝目斷，荊闕夕波還。',96,'御定全唐詩/json/098.json','["綸綍有成命，旌麾不可攀。湘川朝目斷，荊闕夕波還。", "果枉東瞻唱，興言夕放閑。攜琴仙洞中，置酒灉湖上。", "芳景恣行樂，謫居忽如忘。聚散本相因，離情自悲悵。", "鸞翮非常戢，鵬天會昭曠。永懷宛洛游，曾是彈冠望。"]'),
('yuding-2','奉和張燕公早霽南樓','趙冬曦','唐','御定全唐诗','yuding','','[]','方曙躋南樓，憑軒肆遐矚。物華蕩暄氣，春景媚晴旭。',120,'御定全唐詩/json/098.json','["方曙躋南樓，憑軒肆遐矚。物華蕩暄氣，春景媚晴旭。", "川霽湘山孤，林芳楚郊縟。列岩重疊翠，遠岸逶迤綠。", "風帆摩天垠，魚艇散彎曲。鴻歸鶴舞送，猿叫鶯聲續。", "群動皆熙熙，噫予獨羈束。常欽才子意，忌鵩傷蜷局。", "雅尚騷人文，懷沙何迫促。未知二賢意，去矣從所欲。"]'),
('yuding-3','灉湖作','趙冬曦','唐','御定全唐诗','yuding','','[]','三湖返入兩山間，畜作灉湖彎複彎。暑雨奔流潭正滿，',96,'御定全唐詩/json/098.json','["三湖返入兩山間，畜作灉湖彎複彎。暑雨奔流潭正滿，", "適來飛棹共迴旋，已複揚鞭恣行樂。道旁耆老步躚躚，", "君訝今時盡陵陸，我看明歲更淪漣。來今自昔無終始，", "初貞正喜固當然，往蹇來譽宜可俟。盈虛用舍輪輿旋，"]'),
('yuding-4','和燕公嶽州山城','趙冬曦','唐','御定全唐诗','yuding','','[]','為吏恩猶舊，投沙惠此蒙。江邊悠爾處，泗上宛然同。',48,'御定全唐詩/json/098.json','["為吏恩猶舊，投沙惠此蒙。江邊悠爾處，泗上宛然同。", "訪道精言合，論經大義通。鳴琴有真氣，況已沐清風。"]'),
('yuding-5','和尹懋秋夜遊灉湖二首','趙冬曦','唐','御定全唐诗','yuding','','[]','政理常多暇，方舟此溯洄。吹笙虛洞答，舉楫便風催。',96,'御定全唐詩/json/098.json','["政理常多暇，方舟此溯洄。吹笙虛洞答，舉楫便風催。", "山暗雲猶辨，潭幽月稍來。清溪無數曲，未盡莫先回。", "煙靄夕微蒙，幽灣賞未窮。艤舟待初月，褰幌招遠風。", "鶴聲聒前浦，漁火明暗叢。東山雲壑意，不謂爾來同。"]'),
('yuding-6','陪燕公遊灉湖上寺','趙冬曦','唐','御定全唐诗','yuding','','[]','江外多山水，招要步馬來。琴將天籟合，酒共鳥聲催。',48,'御定全唐詩/json/098.json','["江外多山水，招要步馬來。琴將天籟合，酒共鳥聲催。", "岩坐攀紅藥，溪行愛綠苔。所懷非此地，游望亦裴回。"]'),
('yuding-7','答張燕公翻著葛巾見呈之作','趙冬曦','唐','御定全唐诗','yuding','','[]','美酒值芳春，醒餘氣益真。降歡時倒履，乘興偶翻巾。',48,'御定全唐詩/json/098.json','["美酒值芳春，醒餘氣益真。降歡時倒履，乘興偶翻巾。", "徐榻思方建，左車理自均。傲然歌一曲，一醉濯纓人。"]'),
('yuding-8','奉答燕公','趙冬曦','唐','御定全唐诗','yuding','','[]','語別意淒淒，零陵湘水西。佳人金穀返，愛子洞庭迷。',48,'御定全唐詩/json/098.json','["語別意淒淒，零陵湘水西。佳人金穀返，愛子洞庭迷。", "舊館逢花發，他山值鳥啼。江天千里望，誰見綠蘋齊。"]'),
('yuding-9','奉和聖制同二相已下群官樂遊園宴','趙冬曦','唐','御定全唐诗','yuding','','[]','爽塏三秦地，芳華二月初。酺承奠璧罷，宴是合錢餘。',72,'御定全唐詩/json/098.json','["爽塏三秦地，芳華二月初。酺承奠璧罷，宴是合錢餘。", "柳翠垂堪結，桃紅卷欲舒。從容會鵷鷺，延曼戲龍魚。", "喜氣流雲物，歡聲浹裏閭。聖恩將報厚，請述記言書。"]'),
('yuding-10','奉和聖制答張說扈從南出雀鼠谷','趙冬曦','唐','御定全唐诗','yuding','','[]','軒轅應順動，力牧正趨陪。道合殷為礪，時行楚有材。',72,'御定全唐詩/json/098.json','["軒轅應順動，力牧正趨陪。道合殷為礪，時行楚有材。", "省方西禮設，振旅北京回。地理分中壤，天文照上臺。", "寒依汾穀去，春入晉郊來。竊比康衢者，長歌仰大哉。"]'),
('yuding-11','奉和聖制送張說上集賢學士賜宴賦得蓮字','趙冬曦','唐','御定全唐诗','yuding','','[]','淺術方觀海，深恩忽見天。學開丹殿籍，名與石渠賢。',72,'御定全唐詩/json/098.json','["淺術方觀海，深恩忽見天。學開丹殿籍，名與石渠賢。", "良輔膺休命，微生謬采甄。春餘仍哢鳥，夏近未舒蓮。", "箋劄來宸禁，衣冠集詔筵。史臣知醉德，欲記升中年。"]'),
('yuding-12','奉答燕公','趙冬曦','唐','御定全唐诗','yuding','','[]','誰道零陵守，東過此地遊。友僚同省閣，昆弟接荊州。',72,'御定全唐詩/json/098.json','["誰道零陵守，東過此地遊。友僚同省閣，昆弟接荊州。", "我逐江潭雁，君隨海上鷗。屢傷神氣阻，久別鬢毛秋。", "疑嶺春應遍，陽臺雨欲收。主人情未盡，高駕少淹留。"]'),
('yuding-13','陪張燕公行郡竹籬','趙冬曦','唐','御定全唐诗','yuding','','[]','良臣乃國寶，麾守去承明。外戶人無閉，浮江獸已行。',72,'御定全唐詩/json/098.json','["良臣乃國寶，麾守去承明。外戶人無閉，浮江獸已行。", "隨來晉盜逸，民化蜀風清。郛郭從彝典，州閭荷德聲。", "小人投天涯，流落巴丘城。所賴中和作，優遊鑿與耕。"]'),
('yuding-14','和燕公別灉湖','趙冬曦','唐','御定全唐诗','yuding','','[]','南湖美泉石，君子玩幽奇。灣澳陪臨泛，岩峿共踐窺。',72,'御定全唐詩/json/098.json','["南湖美泉石，君子玩幽奇。灣澳陪臨泛，岩峿共踐窺。", "秋風赬桂竦，春景綠楊垂。郢路委分竹，湘濱擁去麾。", "枉帆懷勝賞，留景惜差池。水木且不棄，情由良可知。"]'),
('yuding-15','奉酬燕公見歸田賦垂贈之作','趙冬曦','唐','御定全唐诗','yuding','','[]','窮鳥嬰籠綴，孤飛任播遷。鷦鷯王佐用，複此挫沖天。',84,'御定全唐詩/json/098.json','["窮鳥嬰籠綴，孤飛任播遷。鷦鷯王佐用，複此挫沖天。", "楚雲何掩郁，湘水亦回邅。懷哉愧木雁，忽爾枉蘭荃。", "愈疾同枚叔，銷憂比仲宣。歸途書可畏，弱操石猶堅。", "覆載雖雲廣，涔陽直塊然。"]'),
('yuding-16','和張燕公耗磨日飲','趙冬曦','唐','御定全唐诗','yuding','','[]','上月今朝減，流傳耗磨辰。還將不事事，同醉俗中人。',48,'御定全唐詩/json/098.json','["上月今朝減，流傳耗磨辰。還將不事事，同醉俗中人。", "春來半月度，俗忌一朝閑。不酌他鄉酒，無堪對楚山。"]'),
('yuding-17','奉陪張燕公登南樓','尹懋','唐','御定全唐诗','yuding','','[]','君子每垂眷，江山共流眄。水遠林外明，岩近霧中見。',48,'御定全唐詩/json/098.json','["君子每垂眷，江山共流眄。水遠林外明，岩近霧中見。", "終日西北望，何處是京縣。屢登高春台，徒使淚如霰。"]'),
('yuding-18','秋夜陪張丞相趙侍禦遊灉湖二首','尹懋','唐','御定全唐诗','yuding','','[]','熊軾巴陵地，鷁舟湘水潯。江山與勢遠，泉石自幽深。',96,'御定全唐詩/json/098.json','["熊軾巴陵地，鷁舟湘水潯。江山與勢遠，泉石自幽深。", "杳靄入天壑，冥茫見道心。超然無俗事，清宴有空林。", "江上饒奇山，巑羅雲水間。風和樹色雜，苔古石文斑。", "巴俗將千溠，灉湖凡幾灣。嬉遊竟不盡，乘月泛舟還。"]'),
('yuding-19','同燕公泛洞庭','尹懋','唐','御定全唐诗','yuding','','[]','風光淅淅草中飄，日彩熒熒水上搖。',32,'御定全唐詩/json/098.json','["風光淅淅草中飄，日彩熒熒水上搖。", "幸奏瀟湘雲壑意，山旁容與動仙橈。"]'),
('yuding-20','奉答燕公','王琚','唐','御定全唐诗','yuding','','[]','郡遠途且艱，宜悲良自得。胡為心獨爾，惠好在南國。',144,'御定全唐詩/json/098.json','["郡遠途且艱，宜悲良自得。胡為心獨爾，惠好在南國。", "亦既清顏披，冏然良願克。與君蘭時會，群物如藻飾。", "煙景惜歡賞，雲山起翰墨。接藝奇思微，偶談玄言直。", "永日不知倦，逾旬猶謂亟。如何酌離尊，移棹巴城側。", "浦口勞長望，舟中獨太息。疾風吹飛帆，倏忽南與北。", "目盡不復見，懷哉無終極。唯當衡峰上，遙辨湖水色。"]'),
('yuding-21','美女篇','王琚','唐','御定全唐诗','yuding','','[]','東鄰美女實名倡，絕代容華無比方。濃纖得中非短長，',96,'御定全唐詩/json/098.json','["東鄰美女實名倡，絕代容華無比方。濃纖得中非短長，", "屈曲屏風繞象床，萎蕤翠帳綴香囊。玉台龍鏡洞徹光，", "二八三五閨心切，褰簾卷幔迎春節。清歌始發詞怨咽，", "須臾破顏倏斂態，一悲一喜並相宜。何能見此不注心，"]'),
('yuding-22','自荊湖入朝至岳陽奉別張燕公','王琚','唐','御定全唐诗','yuding','','[]','五載朝天子，三湘逢舊僚。扁舟方輟棹，清論遂終朝。',48,'御定全唐詩/json/098.json','["五載朝天子，三湘逢舊僚。扁舟方輟棹，清論遂終朝。", "遠樹煙間沒，長江地際搖。帝城馳夢想，歸帆滿風飆。"]'),
('yuding-23','遊灉湖上寺','王琚','唐','御定全唐诗','yuding','','[]','春山臨遠壑，水木自幽清。夙昔懷微尚，茲焉一放情。',48,'御定全唐詩/json/098.json','["春山臨遠壑，水木自幽清。夙昔懷微尚，茲焉一放情。", "雲間聽弄鳥，煙上摘初英。地僻方無悶，逾知道思精。"]'),
('yuding-24','和張燕公湘中九日登高','陰行先','唐','御定全唐诗','yuding','','[]','重陽初啟節，無射正飛灰。寂寞風蟬至，連翩霜雁來。',48,'御定全唐詩/json/098.json','["重陽初啟節，無射正飛灰。寂寞風蟬至，連翩霜雁來。", "山棠紅葉下，岸菊紫花開。今日桓公座，多愧孟嘉才。"]'),
('yuding-25','奉別張嶽州說二首','王熊','唐','御定全唐诗','yuding','','[]','長沙辭舊國，洞庭逢故人。熏蘭敦久要，披霧轉相親。',96,'御定全唐詩/json/098.json','["長沙辭舊國，洞庭逢故人。熏蘭敦久要，披霧轉相親。", "歲月空嗟老，江山不惜春。忽聞黃鶴曲，更作白頭新。", "平生共風月，倏忽間山川。不期交淡水，暫得款忘年。", "興逸方罷釣，帆開欲解船。離心若危旆，朝夕為君懸。"]'),
('yuding-26','入朝別張燕公','梁知微','唐','御定全唐诗','yuding','','[]','華容佳山水，之子厭承明。符竹紆小郡，江湖被德聲。',96,'御定全唐詩/json/098.json','["華容佳山水，之子厭承明。符竹紆小郡，江湖被德聲。", "三年計吏入，路指巴丘城。鳧舟才結纜，騶駕已相迎。", "別離他鄉酒，委曲故人情。孤嶼早煙薄，長波晚氣清。", "辛勤方遠騖，勝賞屢難並。回瞻洞庭浦，日暮愁雲生。"]'),
('yuding-27','桐竹贈張燕公','李伯魚','唐','御定全唐诗','yuding','','[]','北竹青桐北，南桐綠竹南。竹林君早愛，桐樹我初貪。',48,'御定全唐詩/json/098.json','["北竹青桐北，南桐綠竹南。竹林君早愛，桐樹我初貪。", "鳳棲桐不愧，鳳食竹何慚。棲食更如此，餘非鳳所堪。"]'),
('yuding-28','正朝上左相張燕公','楊重玄','唐','御定全唐诗','yuding','','[]','歲去愁終在，春還命不來。長籲問丞相，東閣幾時開。',24,'御定全唐詩/json/098.json','["歲去愁終在，春還命不來。長籲問丞相，東閣幾時開。"]'),
('yuding-29','道峽似巫山','朱使欣','唐','御定全唐诗','yuding','','[]','江如曉天靜，石似暮雲張。征帆一流覽，宛若巫山陽。',48,'御定全唐詩/json/098.json','["江如曉天靜，石似暮雲張。征帆一流覽，宛若巫山陽。", "楚客思歸路，秦人謫異鄉。猿鳴孤月夜，再使淚沾裳。"]'),
('yuding-0','巫山高','張循之','唐','御定全唐诗','yuding','','[]','巫山高不極，合遝狀奇新。暗谷疑風雨，陰崖若鬼神。',48,'御定全唐詩/json/099.json','["巫山高不極，合遝狀奇新。暗谷疑風雨，陰崖若鬼神。", "月明三峽曉，潮滿九江春。為問陽臺客，應知入夢人。"]'),
('yuding-1','送泉州李使君之任','張循之','唐','御定全唐诗','yuding','','[]','傍海皆荒服，分符重漢臣。雲山百越路，市井十洲人。',48,'御定全唐詩/json/099.json','["傍海皆荒服，分符重漢臣。雲山百越路，市井十洲人。", "執玉來朝遠，還珠入貢頻。連年不見雪，到處即行春。"]'),
('yuding-2','長門怨','張循之','唐','御定全唐诗','yuding','','[]','長門落景盡，洞房秋月明。玉階草露積，金屋網塵生。',48,'御定全唐詩/json/099.json','["長門落景盡，洞房秋月明。玉階草露積，金屋網塵生。", "妾妒今應改，君恩惜未平。寄語臨邛客，何時作賦成。"]'),
('yuding-3','巫山','張循之','唐','御定全唐诗','yuding','','[]','流景一何速，年華不可追。解佩安所贈，怨咽空自悲。',24,'御定全唐詩/json/099.json','["流景一何速，年華不可追。解佩安所贈，怨咽空自悲。"]'),
('yuding-4','送王汶宰江陰','張循之','唐','御定全唐诗','yuding','','[]','郡北乘流去，花間竟日行。海魚朝滿市，江鳥夜喧城。',48,'御定全唐詩/json/099.json','["郡北乘流去，花間竟日行。海魚朝滿市，江鳥夜喧城。", "讓酒非關病，援琴不在聲。應緣五斗米，數日滯淵明。"]'),
('yuding-5','婺州留別鄧使君','張循之','唐','御定全唐诗','yuding','','[]','西掖馳名久，東陽出守時。江山婺女分，風月隱侯詩。',48,'御定全唐詩/json/099.json','["西掖馳名久，東陽出守時。江山婺女分，風月隱侯詩。", "別恨雙溪急，留歡五馬遲。回舟映沙嶼，未遠剩相思。"]'),
('yuding-6','祭汾陰樂章：太和','王晙','唐','御定全唐诗','yuding','','[]','于穆聖皇，六葉重光。太原刻頌，後土疏場。',40,'御定全唐詩/json/099.json','["于穆聖皇，六葉重光。太原刻頌，後土疏場。", "寶鼎呈符，歊雲孕祥。禮樂備矣，降福穰穰。"]'),
('yuding-7','大堤曲','張柬之','唐','御定全唐诗','yuding','','[]','南國多佳人，莫若大堤女。玉床翠羽帳，寶襪蓮花距。',48,'御定全唐詩/json/099.json','["南國多佳人，莫若大堤女。玉床翠羽帳，寶襪蓮花距。", "魂處自目成，色授開心許。迢迢不可見，日暮空愁予。"]'),
('yuding-8','東飛伯勞歌','張柬之','唐','御定全唐诗','yuding','','[]','青田白鶴丹山鳳，婺女姮娥兩相送。誰家絕世綺帳前，',48,'御定全唐詩/json/099.json','["青田白鶴丹山鳳，婺女姮娥兩相送。誰家絕世綺帳前，", "絕世三五愛紅妝，冶袖長裙蘭麝香。春去花枝俄易改，"]'),
('yuding-9','出塞','張柬之','唐','御定全唐诗','yuding','','[]','俠客重恩光，驄馬飾金裝。瞥聞傳羽檄，馳突救邊荒。',132,'御定全唐詩/json/099.json','["俠客重恩光，驄馬飾金裝。瞥聞傳羽檄，馳突救邊荒。", "歙野山川動，囂天旌旆揚。吳鉤明似月，楚劍利如霜。", "電斷沖胡塞，風飛出洛陽。轉戰磨笄俗，橫行戴鬥鄉。", "手擒郅支長，面縛谷蠡王。將軍占太白，小婦怨流黃。", "騕褭青絲騎，娉婷紅粉妝。三春鶯度曲，八月雁成行。", "誰堪坐愁思，羅袖拂空床。"]'),
('yuding-10','與國賢良夜歌二首','張柬之','唐','御定全唐诗','yuding','','[]','柳台臨新堰，樓堞相重複。窈窕鳳凰姝，傾城複傾國。',48,'御定全唐詩/json/099.json','["柳台臨新堰，樓堞相重複。窈窕鳳凰姝，傾城複傾國。", "杏間花照灼，樓上月裴回。帶嬌移玉柱，含笑捧金杯。"]'),
('yuding-11','詠屏風','袁恕己','唐','御定全唐诗','yuding','','[]','綺閣雲霞滿，芳林草樹新。鳥驚疑欲曙，花笑不關春。',48,'御定全唐詩/json/099.json','["綺閣雲霞滿，芳林草樹新。鳥驚疑欲曙，花笑不關春。", "山對彈琴客，溪留垂釣人。請看車馬客，行處有風塵。"]'),
('yuding-12','書懷','劉幽求','唐','御定全唐诗','yuding','','[]','心為明時盡，君門尚不容。田園迷徑路，歸去欲何從。',24,'御定全唐詩/json/099.json','["心為明時盡，君門尚不容。田園迷徑路，歸去欲何從。"]'),
('yuding-13','流所贈張錫','章玄同','唐','御定全唐诗','yuding','','[]','黃葉因風下，甘從洛浦隈。白雲何所為，還出帝鄉來。',24,'御定全唐詩/json/099.json','["黃葉因風下，甘從洛浦隈。白雲何所為，還出帝鄉來。"]'),
('yuding-14','臨高臺','王易從','唐','御定全唐诗','yuding','','[]','漢主事祁連，良人在高闕。空台寂已暮，愁坐變容發。',48,'御定全唐詩/json/099.json','["漢主事祁連，良人在高闕。空台寂已暮，愁坐變容發。", "泛豔春幌風，裴回秋戶月。可憐軍書斷，空使流芳歇。"]'),
('yuding-15','初出京邑有懷舊林','盧僎','唐','御定全唐诗','yuding','','[]','賦生期獨得，素業守微班。外忝文學知，鴻漸鵷鷺間。',144,'御定全唐詩/json/099.json','["賦生期獨得，素業守微班。外忝文學知，鴻漸鵷鷺間。", "內傾水木趣，築室依近山。晨趨天日晏，夕臥江海閑。", "松風生坐隅，仙禽舞亭灣。曙雲林下客，霽月池上顏。", "雖曰坐郊園，靜默非人寰。時步蒼龍闕，甯異白雲關。", "語濟豈時顧，默善忘世攀。世網余何觸，天涯謫南蠻。", "回首思洛陽，喟然悲貞艱。舊林日夜遠，孤雲何時還。"]'),
('yuding-16','稍秋曉坐閣，遇舟東下揚州，即事寄上族父江陽令','盧僎','唐','御定全唐诗','yuding','','[]','虎嘯山城晚，猿鳴江樹秋。紅林架落照，青峽送歸流。',288,'御定全唐詩/json/099.json','["虎嘯山城晚，猿鳴江樹秋。紅林架落照，青峽送歸流。", "歸流赴淮海，征帆下揚州。族父江陽令，盛業繼前修。", "文掩崔亭伯，德齊陳太丘。時哉惜未與，千載且為儔。", "憶昔山陽會，長懷東上游。稱觴阮林下，賦雪謝庭幽。", "道濃禮自略，氣舒文轉遒。高情薄雲漢，酣態坐芳洲。", "接席複連軫，出入陪華輈。獨善與兼濟，語默奉良籌。", "歲月歡無已，風雨暗颼颼。掌憲時持節，為邦邈海頭。", "子人惠雖樹，蒼生望且留。微躬趨直道，神甸忝清猷。", "仙台適西步，蠻徼忽南浮。宇內皆安樂，天涯獨遠投。", "忠信徒堅仗，神明豈默酬。觀生海漫漫，稽命天悠悠。", "雲昏巴子峽，月遠吳王樓。懷昔明不寐，悲令歲屬周。", "喟無排雲翮，暫得抒離憂。空灑沾紅淚，萬里逐行舟。"]'),
('yuding-17','讓帝挽歌詞二首','盧僎','唐','御定全唐诗','yuding','','[]','泰伯玄風遠，延州德讓行。闔棺追大節，樹羽冊鴻名。',96,'御定全唐詩/json/099.json','["泰伯玄風遠，延州德讓行。闔棺追大節，樹羽冊鴻名。", "地戶迎天仗，皇階失帝兄。還聞漢明主，遺劍泣東平。", "朝天馳馬絕，冊帝□宮祖。恍惚陵廟新，蕭條池館古。", "萬化一朝空，哀樂此路同。西園有明月，修竹韻悲風。"]'),
('yuding-18','十月梅花書贈','盧僎','唐','御定全唐诗','yuding','','[]','君不見巴鄉氣候與華別，年年十月梅花發。',115,'御定全唐詩/json/099.json','["君不見巴鄉氣候與華別，年年十月梅花發。", "上苑今應雪作花，寧知此地花為雪。自從遷播落黔巴，", "花情縱似河陽好，客心倍傷邊候早。春候颯驚樓上梅，", "一向花前看白髮，幾回夢裏憶紅顏。紅顏白髮雲泥改，", "空心吊影向誰陳，雲台仙閣舊遊人。儻知巴樹連冬發，"]'),
('yuding-19','歲晚還京台望城闕成口號先贈交親','盧僎','唐','御定全唐诗','yuding','','[]','紫陌開行樹，朱城出晚霞。猶憐慣去國，疑是夢還家。',48,'御定全唐詩/json/099.json','["紫陌開行樹，朱城出晚霞。猶憐慣去國，疑是夢還家。", "風弱知催柳，林青覺待花。交親望歸騎，幾處擁年華。"]'),
('yuding-20','送蘇八給事出牧徐州用芳韻','盧僎','唐','御定全唐诗','yuding','','[]','金鼎屬元方，瑣闈連季常。畏盈聊出守，分命乃維良。',48,'御定全唐詩/json/099.json','["金鼎屬元方，瑣闈連季常。畏盈聊出守，分命乃維良。", "曉騎辭朝遠，春帆向楚常。賢哉謙自牧，天下詠餘芳。"]'),
('yuding-21','上幸皇太子新院應制','盧僎','唐','御定全唐诗','yuding','','[]','佳氣曉蔥蔥，幹行入震宮。前星迎北極，少海被南風。',72,'御定全唐詩/json/099.json','["佳氣曉蔥蔥，幹行入震宮。前星迎北極，少海被南風。", "視膳銅樓下，吹笙玉座中。訓深家以正，義舉俗為公。", "父子成釗合，君臣禹啟同。仰天歌聖道，猶愧乏雕蟲。"]'),
('yuding-22','奉和李令扈從溫泉宮賜游驪山韋侍郎別業','盧僎','唐','御定全唐诗','yuding','','[]','風後軒皇佐，雲峰謝客居。承恩來翠嶺，締賞出丹除。',96,'御定全唐詩/json/099.json','["風後軒皇佐，雲峰謝客居。承恩來翠嶺，締賞出丹除。", "飛蓋松溪寂，清笳玉洞虛。窺岩詳霧豹，過水略泉魚。", "鄉入無何有，時還上古初。伊皋羞過狹，魏丙服粗疏。", "白雪緣情降，青霞落卷舒。多慚郎署在，輒繼國風餘。"]'),
('yuding-23','季冬送戶部郎中使黔府選補','盧僎','唐','御定全唐诗','yuding','','[]','握鏡均荒服，分衡得大同。征賢一臺上，補吏五溪中。',72,'御定全唐詩/json/099.json','["握鏡均荒服，分衡得大同。征賢一臺上，補吏五溪中。", "雨露將天澤，文章播國風。漢庭暌直諒，楚峽望清通。", "馬逐霜鴻漸，帆沿曉月空。還期鳳池拜，照耀列星宮。"]'),
('yuding-24','途中口號','盧僎','唐','御定全唐诗','yuding','','[]','抱玉三朝楚，懷書十上秦。年年洛陽陌，花鳥弄歸人。',24,'御定全唐詩/json/099.json','["抱玉三朝楚，懷書十上秦。年年洛陽陌，花鳥弄歸人。"]'),
('yuding-25','南望樓','盧僎','唐','御定全唐诗','yuding','','[]','去國三巴遠，登樓萬里春。傷心江上客，不是故鄉人。',24,'御定全唐詩/json/099.json','["去國三巴遠，登樓萬里春。傷心江上客，不是故鄉人。"]'),
('yuding-26','臨川送別','盧僎','唐','御定全唐诗','yuding','','[]','秋郊日半隱，野樹煙初映。風水正蕭條，那甚動離詠。',24,'御定全唐詩/json/099.json','["秋郊日半隱，野樹煙初映。風水正蕭條，那甚動離詠。"]'),
('yuding-27','題殿前桂葉','盧僎','唐','御定全唐诗','yuding','','[]','桂樹生南海，芳香隔楚山。今朝天上見，疑是月中攀。',24,'御定全唐詩/json/099.json','["桂樹生南海，芳香隔楚山。今朝天上見，疑是月中攀。"]'),
('yuding-28','奉和受圖溫洛應制','牛鳳及','唐','御定全唐诗','yuding','','[]','八神扶玉輦，六羽警瑤溪。戒道伊川北，通津澗水西。',60,'御定全唐詩/json/099.json','["八神扶玉輦，六羽警瑤溪。戒道伊川北，通津澗水西。", "禦圖開洛匱，刻石與天齊。瑞日波中上，仙禽霧裏低。", "微臣矯羽翮，抃舞接鸞鷖。"]'),
('yuding-0','雅琴篇','司馬逸客','唐','御定全唐诗','yuding','','[]','亭亭嶧陽樹，落落千萬尋。獨抱出雲節，孤生不作林。',228,'御定全唐詩/json/100.json','["亭亭嶧陽樹，落落千萬尋。獨抱出雲節，孤生不作林。", "影搖綠波水，彩絢丹霞岑。直幹思有托，雅志期所任。", "匠者果留盼，雕斫為雅琴。文以楚山玉，錯以昆吾金。", "虯鳳吐奇狀，商征含清音。清音雅調感君子，", "馬卿臺上應蕪沒，阮籍帷前空已矣。山情水意君不知，", "隴水悲風已嗚咽，離鶤別鶴更淒清。將軍塞外多奇操，", "自言幽隱乏先容，不道人物知音寡。誰能一奏和天地，", "歲歲汾川事簫鼓，朝朝伊水聽笙簧。窈窕樓臺臨上路，", "猶憐雅歌淡無味，淥水白雲誰相貴。還將逸詞賞幽心，", "願持東武宮商韻，長奉南熏億萬年。"]'),
('yuding-1','三婦豔','王紹宗','唐','御定全唐诗','yuding','','[]','大婦能調瑟，中婦詠新詩。小婦獨無事，花庭曳履綦。',36,'御定全唐詩/json/100.json','["大婦能調瑟，中婦詠新詩。小婦獨無事，花庭曳履綦。", "上客且安坐，春日正遲遲。"]'),
('yuding-2','別離怨','鄭遂初','唐','御定全唐诗','yuding','','[]','蕩子戍遼東，連年信不通。塵生錦步障，花送玉屏風。',48,'御定全唐詩/json/100.json','["蕩子戍遼東，連年信不通。塵生錦步障，花送玉屏風。", "只怨紅顏改，寧辭玉簟空。系書春雁足，早晚到雲中。"]'),
('yuding-3','寒食','李崇嗣','唐','御定全唐诗','yuding','','[]','普天皆滅焰，匝地盡藏煙。不知何處火，來就客心然。',24,'御定全唐詩/json/100.json','["普天皆滅焰，匝地盡藏煙。不知何處火，來就客心然。"]'),
('yuding-4','覽鏡','李崇嗣','唐','御定全唐诗','yuding','','[]','歲去紅顏盡，愁來白髮新。今朝開鏡匣，疑是別逢人。',24,'御定全唐詩/json/100.json','["歲去紅顏盡，愁來白髮新。今朝開鏡匣，疑是別逢人。"]'),
('yuding-5','獨愁','李崇嗣','唐','御定全唐诗','yuding','','[]','聞道成都酒，無錢亦可求。不知將幾鬥，銷得此來愁。',24,'御定全唐詩/json/100.json','["聞道成都酒，無錢亦可求。不知將幾鬥，銷得此來愁。"]'),
('yuding-6','昭君怨三首','東方虯','唐','御定全唐诗','yuding','','[]','漢道方全盛，朝廷足武臣。何須薄命妾，辛苦事和親。',72,'御定全唐詩/json/100.json','["漢道方全盛，朝廷足武臣。何須薄命妾，辛苦事和親。", "掩淚辭丹鳳，銜悲向白龍。單于浪驚喜，無復舊時容。", "胡地無花草，春來不似春。自然衣帶緩，非是為腰身。"]'),
('yuding-7','春雪','東方虯','唐','御定全唐诗','yuding','','[]','春雪滿空來，觸處似花開。不知園裏樹，若個是真梅。',24,'御定全唐詩/json/100.json','["春雪滿空來，觸處似花開。不知園裏樹，若個是真梅。"]'),
('yuding-8','逸人歌贈李山人','張楚金','唐','御定全唐诗','yuding','','[]','上有堯兮下有由，眠松陽兮漱潁流。其貌古，其心幽，',24,'御定全唐詩/json/100.json','["上有堯兮下有由，眠松陽兮漱潁流。其貌古，其心幽，"]'),
('yuding-9','謫南海過始興廣勝寺果上人房','房融','唐','御定全唐诗','yuding','','[]','零落嗟殘命，蕭條托勝因。方燒三界火，遽洗六情塵。',48,'御定全唐詩/json/100.json','["零落嗟殘命，蕭條托勝因。方燒三界火，遽洗六情塵。", "隔嶺天花發，淩空月殿新。誰令鄉國夢，終此學分身。"]'),
('yuding-10','詠院中叢竹','呂太一','唐','御定全唐诗','yuding','','[]','擢擢當軒竹，青青重歲寒。心貞徒見賞，籜小未成竿。',24,'御定全唐詩/json/100.json','["擢擢當軒竹，青青重歲寒。心貞徒見賞，籜小未成竿。"]'),
('yuding-11','和呂禦史詠院中叢竹','張紘','唐','御定全唐诗','yuding','','[]','聞君庭竹詠，幽意歲寒多。歎息為冠小，良工將奈何。',24,'御定全唐詩/json/100.json','["聞君庭竹詠，幽意歲寒多。歎息為冠小，良工將奈何。"]'),
('yuding-12','《閨怨','張紘','唐','御定全唐诗','yuding','','[]','去年離別雁初歸，今夜裁縫螢已飛。',32,'御定全唐詩/json/100.json','["去年離別雁初歸，今夜裁縫螢已飛。", "征客近來音信斷，不知何處寄寒衣。"]'),
('yuding-13','行路難','張紘','唐','御定全唐诗','yuding','','[]','君不見溫家玉鏡臺，提攜抱握九重來。',98,'御定全唐詩/json/100.json','["君不見溫家玉鏡臺，提攜抱握九重來。", "君不見相如綠綺琴，一撫一拍鳳凰音。", "人生意氣須及早，莫負當年行樂心。荊王奏曲楚妃歎，", "當春對酒不須疑，視日相看能幾時。春風吹盡燕初至，", "人生翻覆何常定，誰保容顏無是非。"]'),
('yuding-14','別親朋','鄭蜀賓','唐','御定全唐诗','yuding','','[]','畏途方萬里，生涯近百年。不知將白首，何處入黃泉。',24,'御定全唐詩/json/100.json','["畏途方萬里，生涯近百年。不知將白首，何處入黃泉。"]'),
('yuding-0','海上作','宋務光','唐','御定全唐诗','yuding','','[]','曠哉潮汐池，大矣乾坤力。浩浩去無際，沄沄深不測。',192,'御定全唐詩/json/101.json','["曠哉潮汐池，大矣乾坤力。浩浩去無際，沄沄深不測。", "崩騰翕眾流，泱漭環中國。鱗介錯殊品，氛霞饒詭色。", "天波混莫分，島樹遙難識。漢主探靈怪，秦王恣遊陟。", "搜奇大壑東，竦望成山北。方術徒相誤，蓬萊安可得。", "吾君略仙道，至化孚淳默。驚浪晏窮溟，飛航通絕域。", "馬韓底厥貢，龍伯修其職。粵我遘休明，匪躬期正直。", "敢輸鷹隼執，以間豺狼忒。海路行已殫，輶軒未皇息。", "勞歌玄月暮，旅睇滄浪極。魏闕渺雲端，馳心附歸冀。"]'),
('yuding-1','回波辭','李景伯','唐','御定全唐诗','yuding','','[]','回波爾時酒卮，微臣職在箴規。',28,'御定全唐詩/json/101.json','["回波爾時酒卮，微臣職在箴規。", "侍宴既過三爵，喧嘩竊恐非儀。"]'),
('yuding-2','秋晚度廢關','李行言','唐','御定全唐诗','yuding','','[]','秦郊平舊險，周德眷遺黎。始聞清夜柝，俄見落封泥。',72,'御定全唐詩/json/101.json','["秦郊平舊險，周德眷遺黎。始聞清夜柝，俄見落封泥。", "物色來無限，津途去不迷。空亭誰問馬，閑戍但鳴雞。", "山月寒彌淨，河風曉更淒。贈言楊伯起，非複是關西。"]'),
('yuding-3','上元','郭利貞','唐','御定全唐诗','yuding','','[]','九陌連燈影，千門度月華。傾城出寶騎，匝路轉香車。',48,'御定全唐詩/json/101.json','["九陌連燈影，千門度月華。傾城出寶騎，匝路轉香車。", "爛熳惟愁曉，周遊不問家。更逢清管發，處處落梅花。"]'),
('yuding-4','贈皇甫侍禦赴都八首','元希聲','唐','御定全唐诗','yuding','','[]','東南之美，生於會稽。牛鬥之氣，蓄於昆溪。',310,'御定全唐詩/json/101.json','["東南之美，生於會稽。牛鬥之氣，蓄於昆溪。", "有瑤者玉，連城是齊。有威者鳳，非梧不棲。", "猗嗟眾珍，以況君子。公侯之胄，必複其始。", "利器長材，溫儀峻峙。", "道心惟微，厥用允塞。德輝不泯，而映邦國。", "靜以有神，動而作則。九皋千里，其聲不忒。", "粵在古昔，分官厥初。刺邪矯枉，非賢勿居。", "棱棱直指，烈烈方書。蒼玉鳴佩，繡衣登車。", "綽綽夫君，是膺柱下。準繩有望，名器無假。", "寵蓋伯山，氣雄公雅。立朝正色，俟我能者。", "載懷朋情，嘗接閑宴。好洽昆弟，官聯州縣。", "如彼松竹，春榮冬蒨。柯葉藹然，下渝霜霰。", "會合非我，關山坐違。離鴻曉引，別葉秋飛。", "騑驂徐動，尊餞相依。遠情超忽，岐路光輝。", "金石其心，芝蘭其室。言語方間，音徽自溢。", "肅子風威，嚴子霜質。贈言歲暮，以保貞吉。"]'),
('yuding-5','秋庭夜月有懷','李澄之','唐','御定全唐诗','yuding','','[]','遊客三江外，單棲百慮違。山川憶處近，形影夢中歸。',48,'御定全唐詩/json/101.json','["遊客三江外，單棲百慮違。山川憶處近，形影夢中歸。", "夜月明虛帳，秋風入擣衣。從來不慣別，況屬雁南飛。"]'),
('yuding-6','明月','李如璧','唐','御定全唐诗','yuding','','[]','三五月華流炯光，可憐懷歸郢路長。逾江越漢津無梁，',72,'御定全唐詩/json/101.json','["三五月華流炯光，可憐懷歸郢路長。逾江越漢津無梁，", "胡人琵琶彈北風，漢家音信絕南鴻。昭君此時怨畫工，", "逐臣戀主心愈恪，棄妻思君情不薄。已悲芳歲徒淪落，"]'),
('yuding-7','嚴陵祠','洪子輿','唐','御定全唐诗','yuding','','[]','漢主召子陵，歸宿洛陽殿。客星今安在，隱跡猶可見。',96,'御定全唐詩/json/101.json','["漢主召子陵，歸宿洛陽殿。客星今安在，隱跡猶可見。", "水石空潺湲，松篁尚蔥蒨。岸深翠陰合，川回白雲遍。", "幽徑滋蕪沒，荒祠冪霜霰。垂釣想遺芳，掇蘋羞野薦。", "高風激終古，語理忘榮賤。方驗道可尊，山林情不變。"]'),
('yuding-8','度塗山','寇泚','唐','御定全唐诗','yuding','','[]','小年弄文墨，不識戎旅難。一朝事鞞鼓，策馬度塗山。',72,'御定全唐詩/json/101.json','["小年弄文墨，不識戎旅難。一朝事鞞鼓，策馬度塗山。", "塗山橫地軸，萬里留荒服。悠悠正旆遠，騑驂一何速。", "流月揮金戈，驚風折寒木。行聞漢飛將，還向皋蘭宿。"]'),
('yuding-9','永泰公主挽歌二首','吳兢','唐','御定全唐诗','yuding','','[]','穠華從婦道，厘降適諸侯。河漢天孫合，瀟湘帝子遊。',96,'御定全唐詩/json/101.json','["穠華從婦道，厘降適諸侯。河漢天孫合，瀟湘帝子遊。", "關雎方作訓，鳴鳳自相求。可歎淩波跡，東川遂不流。", "舜華徂北渚，宸思結南陽。盭綬哀榮備，遊軒寵悼彰。", "三川謀遠日，八水宅連岡。無複秦樓上，吹簫下鳳凰。"]'),
('yuding-0','妾薄命','武平一','唐','御定全唐诗','yuding','','[]','有女妖且麗，裴回湘水湄。水湄蘭杜芳，采之將寄誰。',144,'御定全唐詩/json/102.json','["有女妖且麗，裴回湘水湄。水湄蘭杜芳，采之將寄誰。", "瓠犀發皓齒，雙蛾顰翠眉。紅臉如開蓮，素膚若凝脂。", "綽約多逸態，輕盈不自持。嘗矜絕代色，複恃傾城姿。", "子夫前入侍，飛燕複當時。正悅掌中舞，寧哀團扇詩。", "洛川昔雲遇，高唐今尚違。幽閣禽雀噪，閑階草露滋。", "流景一何速，年華不可追。解佩安所贈，怨咽空自悲。"]'),
('yuding-1','奉和登驪山高頂寓目應制','武平一','唐','御定全唐诗','yuding','','[]','鑾輿上碧天，翠帟拖晴煙。絕崿紆仙徑，層岩敞禦筵。',48,'御定全唐詩/json/102.json','["鑾輿上碧天，翠帟拖晴煙。絕崿紆仙徑，層岩敞禦筵。", "雲披丹鳳闕，日下黑龍川。更睹南熏奏，流聲入管弦。"]'),
('yuding-2','幸梨園觀打球應制','武平一','唐','御定全唐诗','yuding','','[]','令節重遨遊，分鑣應彩球。驂驔回上苑，蹀躞繞通溝。',48,'御定全唐詩/json/102.json','["令節重遨遊，分鑣應彩球。驂驔回上苑，蹀躞繞通溝。", "影就紅塵沒，光隨赭汗流。賞闌清景暮，歌舞樂時休。"]'),
('yuding-3','奉和幸白鹿觀應制','武平一','唐','御定全唐诗','yuding','','[]','玉府淩三曜，金壇駐六龍。彩旒懸倒景，羽蓋偃喬松。',48,'御定全唐詩/json/102.json','["玉府淩三曜，金壇駐六龍。彩旒懸倒景，羽蓋偃喬松。", "玄圃靈芝秀，華池瑞液濃。謬因沾舜渥，長願奉堯封。"]'),
('yuding-4','侍宴安樂公主新宅應制','武平一','唐','御定全唐诗','yuding','','[]','紫漢秦樓敞，黃山魯館開。簪裾分上席，歌舞列平臺。',48,'御定全唐詩/json/102.json','["紫漢秦樓敞，黃山魯館開。簪裾分上席，歌舞列平臺。", "馬既如龍至，人疑學鳳來。幸茲聯棣萼，何以接鄒枚。"]'),
('yuding-5','送金城公主適西蕃','武平一','唐','御定全唐诗','yuding','','[]','廣化三邊靜，通煙四海安。還將膝下愛，特副域中歡。',48,'御定全唐詩/json/102.json','["廣化三邊靜，通煙四海安。還將膝下愛，特副域中歡。", "聖念飛玄藻，仙儀下白蘭。日斜征蓋沒，歸騎動鳴鸞。"]'),
('yuding-6','奉和幸新豐溫泉宮應制','武平一','唐','御定全唐诗','yuding','','[]','秦王登碣石，周後襲昆侖。何必在遐遠，方稱萬宇尊。',168,'御定全唐詩/json/102.json','["秦王登碣石，周後襲昆侖。何必在遐遠，方稱萬宇尊。", "我皇順時豫，星駕動軒轅。雄戟交馳道，清笳度國門。", "回輿長樂觀，校獵上林園。行漏移三象，連營總八屯。", "旌搖鸚鵡穀，騎轉鳳凰原。絕壁蒼苔古，靈泉碧溜溫。", "參差開水殿，窈窕敞岩軒。豐邑模猶在，驪宮跡尚存。", "煙松銜翠幄，雪徑繞花源。侍從推玄草，文章召虎賁。", "深仁浹夷夏，洪造溢乾坤。謬忝王枚列，多慚雨露恩。"]'),
('yuding-7','奉和幸韋嗣立山莊侍宴應制','武平一','唐','御定全唐诗','yuding','','[]','三光回鬥極，萬騎肅鉤陳。地若游汾水，畋疑曆渭濱。',96,'御定全唐詩/json/102.json','["三光回鬥極，萬騎肅鉤陳。地若游汾水，畋疑曆渭濱。", "圓塘冰寫鏡，遙樹露成春。弦奏魚聽曲，機忘鳥狎人。", "築岩思感夢，磻石想垂綸。落景搖紅壁，層陰結翠筠。", "素風紛可尚，玄澤藹無垠。薄暮清笳動，天文煥紫宸。"]'),
('yuding-8','興慶池侍宴應制','武平一','唐','御定全唐诗','yuding','','[]','鑾輿羽駕直城隈，帳殿旌門此地開。皎潔靈潭圖日月，',40,'御定全唐詩/json/102.json','["鑾輿羽駕直城隈，帳殿旌門此地開。皎潔靈潭圖日月，", "願奉聖情歡不極，長游雲漢幾昭回。"]'),
('yuding-9','奉和立春內出彩花樹應制','武平一','唐','御定全唐诗','yuding','','[]','鑾輅青旗下帝台，東郊上苑望春來。黃鶯未解林間囀，',40,'御定全唐詩/json/102.json','["鑾輅青旗下帝台，東郊上苑望春來。黃鶯未解林間囀，", "欣逢睿藻光韶律，更促霞觴畏景催。"]'),
('yuding-10','奉和正旦賜宰臣柏葉應制','武平一','唐','御定全唐诗','yuding','','[]','綠葉迎春綠，寒枝曆歲寒。願持柏葉壽，長奉萬年歡。',24,'御定全唐詩/json/102.json','["綠葉迎春綠，寒枝曆歲寒。願持柏葉壽，長奉萬年歡。"]'),
('yuding-11','遊涇川琴溪','武平一','唐','御定全唐诗','yuding','','[]','環潭澄曉色，疊嶂照秋影。幽致欣所逢，紛慮自茲屏。',24,'御定全唐詩/json/102.json','["環潭澄曉色，疊嶂照秋影。幽致欣所逢，紛慮自茲屏。"]'),
('yuding-12','夜宴安樂公主宅','武平一','唐','御定全唐诗','yuding','','[]','王孫帝女下仙台，金榜珠簾入夜開。',32,'御定全唐詩/json/102.json','["王孫帝女下仙台，金榜珠簾入夜開。", "遽惜瓊筵歡正洽，唯愁銀箭曉相催。"]'),
('yuding-13','奉和聖制幸韋嗣立山莊應制','武平一','唐','御定全唐诗','yuding','','[]','鳴鑾赫奕下重樓，羽蓋逍遙向一丘。',32,'御定全唐詩/json/102.json','["鳴鑾赫奕下重樓，羽蓋逍遙向一丘。", "漢日唯聞白衣寵，唐年更睹赤松遊。"]'),
('yuding-14','餞唐永昌','武平一','唐','御定全唐诗','yuding','','[]','聞君墨綬出丹墀，雙舄飛來佇有期。',32,'御定全唐詩/json/102.json','["聞君墨綬出丹墀，雙舄飛來佇有期。", "寄謝銅街攀柳日，無忘粉署握蘭時。"]'),
('yuding-0','奉和聖制立春日侍宴內殿出剪綵花應制','趙彥昭','唐','御定全唐诗','yuding','','[]','剪綵迎初候，攀條故寫真。花隨紅意發，葉就綠情新。',48,'御定全唐詩/json/103.json','["剪綵迎初候，攀條故寫真。花隨紅意發，葉就綠情新。", "嫩色驚銜燕，輕香誤采人。應為熏風拂，能令芳樹春。"]'),
('yuding-1','奉和人日清暉閣宴群臣遇雪應制','趙彥昭','唐','御定全唐诗','yuding','','[]','出震乘東陸，憑高禦北辰。祥雲應早歲，瑞雪候初旬。',48,'御定全唐詩/json/103.json','["出震乘東陸，憑高禦北辰。祥雲應早歲，瑞雪候初旬。", "庭樹千花發，階蓂七葉新。幸承今日宴，長奉萬年春。"]'),
('yuding-2','奉和七夕兩儀殿會宴應制','趙彥昭','唐','御定全唐诗','yuding','','[]','青女三秋節，黃姑七日期。星橋度玉佩，雲閣掩羅帷。',48,'御定全唐詩/json/103.json','["青女三秋節，黃姑七日期。星橋度玉佩，雲閣掩羅帷。", "河氣通仙掖，天文入睿詞。今宵望靈漢，應得見蛾眉。"]'),
('yuding-3','奉和九日幸臨渭亭登高應制','趙彥昭','唐','御定全唐诗','yuding','','[]','秋豫凝仙覽，宸游轉翠華。呼鷹下鳥路，戲馬出龍沙。',48,'御定全唐詩/json/103.json','["秋豫凝仙覽，宸游轉翠華。呼鷹下鳥路，戲馬出龍沙。", "紫菊宜新壽，丹萸辟舊邪。須陪長久宴，歲歲奉吹花。"]'),
('yuding-4','奉和九月九日登慈恩寺浮屠應制','趙彥昭','唐','御定全唐诗','yuding','','[]','出豫乘秋節，登高陟梵宮。皇心滿塵界，佛跡現虛空。',48,'御定全唐詩/json/103.json','["出豫乘秋節，登高陟梵宮。皇心滿塵界，佛跡現虛空。", "日月宜長壽，人天得大通。喜聞題寶偈，受記莫由同。"]'),
('yuding-5','安樂公主移入新宅侍宴應制同用開字','趙彥昭','唐','御定全唐诗','yuding','','[]','雲物中京曉，天人外館開。飛橋象河漢，懸榜學蓬萊。',48,'御定全唐詩/json/103.json','["雲物中京曉，天人外館開。飛橋象河漢，懸榜學蓬萊。", "北闕臨仙檻，南山送壽杯。一窺輪奐畢，慚恧棟樑材。"]'),
('yuding-6','奉和送金城公主適西蕃應制','趙彥昭','唐','御定全唐诗','yuding','','[]','聖後經綸遠，謀臣計畫多。受降追漢策，築館許戎和。',48,'御定全唐詩/json/103.json','["聖後經綸遠，謀臣計畫多。受降追漢策，築館許戎和。", "俗化烏孫壘，春生積石河。六龍今出餞，雙鶴願為歌。"]'),
('yuding-7','奉和聖制登驪山高頂寓目應制','趙彥昭','唐','御定全唐诗','yuding','','[]','皇情遍九垓，禦輦駐昭回。路若隨天轉，人疑近日來。',48,'御定全唐詩/json/103.json','["皇情遍九垓，禦輦駐昭回。路若隨天轉，人疑近日來。", "河看大禹鑿，山見巨靈開。願扈登封駕，常持薦壽杯。"]'),
('yuding-8','奉和幸白鹿觀應制','趙彥昭','唐','御定全唐诗','yuding','','[]','雲驂驅半景，星蹕坐中天。國誕玄宗聖，家尋碧落仙。',48,'御定全唐詩/json/103.json','["雲驂驅半景，星蹕坐中天。國誕玄宗聖，家尋碧落仙。", "玉杯鸞薦壽，寶算鶴知年。一睹光華旦，欣承道德篇。"]'),
('yuding-9','哭僕射鄂公楊再思','趙彥昭','唐','御定全唐诗','yuding','','[]','兩揆光天秩，三朝奉帝熙。何言集大鳥，忽此喪元龜。',48,'御定全唐詩/json/103.json','["兩揆光天秩，三朝奉帝熙。何言集大鳥，忽此喪元龜。", "坐歎公槐落，行聞宰樹悲。壑舟今已去，寧有濟川期。"]'),
('yuding-10','人日侍宴大明宮應制','趙彥昭','唐','御定全唐诗','yuding','','[]','寶契無為屬聖人，雕輿出幸玩芳辰。平樓半入南山霧，',40,'御定全唐詩/json/103.json','["寶契無為屬聖人，雕輿出幸玩芳辰。平樓半入南山霧，", "處處風光今日好，年年願奉屬車塵。"]'),
('yuding-11','奉和初春幸太平公主南莊應制','趙彥昭','唐','御定全唐诗','yuding','','[]','主第岩扃駕鵲橋，天門閶闔降鸞鑣。曆亂旌旗轉雲樹，',40,'御定全唐詩/json/103.json','["主第岩扃駕鵲橋，天門閶闔降鸞鑣。曆亂旌旗轉雲樹，", "已陪沁水追歡日，行奉茅山訪道朝。"]'),
('yuding-12','奉和幸安樂公主山莊應制','趙彥昭','唐','御定全唐诗','yuding','','[]','六龍齊軫禦朝曦，雙鷁維舟下綠池。飛觀仰看雲外聳，',40,'御定全唐詩/json/103.json','["六龍齊軫禦朝曦，雙鷁維舟下綠池。飛觀仰看雲外聳，", "幸願一生同草樹，年年歲歲樂於斯。"]'),
('yuding-13','奉和幸大薦福寺','趙彥昭','唐','御定全唐诗','yuding','','[]','寶地龍飛後，金身佛現時。千花開國界，萬善累皇基。',72,'御定全唐詩/json/103.json','["寶地龍飛後，金身佛現時。千花開國界，萬善累皇基。", "北闕承行幸，西園屬住持。天衣拂舊石，王舍起新祠。", "刹鳳迎雕輦，幡虹駐彩旗。同沾小雨潤，竊仰大風詩。"]'),
('yuding-14','奉和幸長安故城未央宮應制','趙彥昭','唐','御定全唐诗','yuding','','[]','夙駕移天蹕，憑軒覽漢都。寒煙收紫禁，春色繞黃圖。',72,'御定全唐詩/json/103.json','["夙駕移天蹕，憑軒覽漢都。寒煙收紫禁，春色繞黃圖。", "舊史遺陳跡，前王失霸符。山河寸土盡，宮觀尺椽無。", "崇高惟在德，壯麗豈為謨。茨室留皇鑒，熏歌盛有虞。"]'),
('yuding-15','奉和幸韋嗣立山莊侍燕應制','趙彥昭','唐','御定全唐诗','yuding','','[]','賢族唯題裏，儒門但署鄉。何如表岩洞，宸翰發輝光。',96,'御定全唐詩/json/103.json','["賢族唯題裏，儒門但署鄉。何如表岩洞，宸翰發輝光。", "地在茲山曲，家臨合水陽。六龍駐旌罕，四牡耀旗常。", "北斗臨台座，東山入廟堂。天高羽翼近，主聖股肱良。", "野竹池亭氣，村花澗穀香。縱然懷豹隱，空愧躡鵷行。"]'),
('yuding-16','奉和元日賜群臣柏葉應制','趙彥昭','唐','御定全唐诗','yuding','','[]','器乏雕梁器，材非構廈材。但將千歲葉，常奉萬年杯。',24,'御定全唐詩/json/103.json','["器乏雕梁器，材非構廈材。但將千歲葉，常奉萬年杯。"]'),
('yuding-17','苑中人日遇雪應制','趙彥昭','唐','御定全唐诗','yuding','','[]','始見青雲幹律呂，俄逢瑞雪應陽春。',32,'御定全唐詩/json/103.json','["始見青雲幹律呂，俄逢瑞雪應陽春。", "今日回看上林樹，梅花柳絮一時新。"]'),
('yuding-18','奉和聖制幸韋嗣立山莊應制','趙彥昭','唐','御定全唐诗','yuding','','[]','廊廟心存岩壑中，鑾輿矚在灞城東。',32,'御定全唐詩/json/103.json','["廊廟心存岩壑中，鑾輿矚在灞城東。", "逍遙自在蒙莊子，漢主徒言河上公。"]'),
('yuding-19','秋朝木芙蓉','趙彥昭','唐','御定全唐诗','yuding','','[]','水面芙蓉秋已衰，繁條偏是著花遲。',32,'御定全唐詩/json/103.json','["水面芙蓉秋已衰，繁條偏是著花遲。", "平明露滴垂紅臉，似有朝愁暮落時。"]'),
('yuding-20','侍宴桃花園詠桃花應制','趙彥昭','唐','御定全唐诗','yuding','','[]','紅萼競燃春苑曙，粉茸新吐禦筵開。',32,'御定全唐詩/json/103.json','["紅萼競燃春苑曙，粉茸新吐禦筵開。", "長年願奉西王母，近侍慚無東朔才。"]'),
('yuding-0','奉和九日幸臨渭亭登高應制得餘字','蕭至忠','唐','御定全唐诗','yuding','','[]','望幸三秋暮，登高九日初。朱旗巡漢苑，翠帟俯秦墟。',48,'御定全唐詩/json/104.json','["望幸三秋暮，登高九日初。朱旗巡漢苑，翠帟俯秦墟。", "寵極萸房遍，恩深菊酎餘。承歡何以答，萬億奉宸居。"]'),
('yuding-1','奉和九月九日登慈恩寺浮圖應制','蕭至忠','唐','御定全唐诗','yuding','','[]','天蹕三乘啟，星輿六轡行。登高淩寶塔，極目遍王城。',48,'御定全唐詩/json/104.json','["天蹕三乘啟，星輿六轡行。登高淩寶塔，極目遍王城。", "神衛空中繞，仙歌雲外清。重陽千萬壽，率舞頌升平。"]'),
('yuding-2','奉和幸安樂公主山莊應制','蕭至忠','唐','御定全唐诗','yuding','','[]','西郊窈窕鳳凰台，北渚平明法駕來。匝地金聲初度曲，',40,'御定全唐詩/json/104.json','["西郊窈窕鳳凰台，北渚平明法駕來。匝地金聲初度曲，", "微臣此時承宴樂，仿佛疑從星漢回。"]'),
('yuding-3','送張亶赴朔方應制','蕭至忠','唐','御定全唐诗','yuding','','[]','命將擇耆年，圖功勝必全。光輝萬乘餞，威武二庭宣。',72,'御定全唐詩/json/104.json','["命將擇耆年，圖功勝必全。光輝萬乘餞，威武二庭宣。", "中衢橫鼓角，曠野蔽旌旃。推食天廚至，投醪禦酒傳。", "涼風過雁苑，殺氣下雞田。分閫恩何極，臨岐動睿篇。"]'),
('yuding-4','陪幸長寧公主林亭','蕭至忠','唐','御定全唐诗','yuding','','[]','公主林亭地，清晨降玉輿。畫橋飛渡水，仙閣迥臨虛。',48,'御定全唐詩/json/104.json','["公主林亭地，清晨降玉輿。畫橋飛渡水，仙閣迥臨虛。", "新晴看蛺蝶，早夏摘芙蕖。文酒娛游盛，忻叨侍從餘。"]'),
('yuding-5','陪幸五王宅','蕭至忠','唐','御定全唐诗','yuding','','[]','北斗樞機任，西京肺腑親。疇昔王門下，今茲制幸晨。',72,'御定全唐詩/json/104.json','["北斗樞機任，西京肺腑親。疇昔王門下，今茲制幸晨。", "恩來山水被，聖作管弦新。繞座熏紅藥，當軒暗綠筠。", "摘荷才早夏，聽鳥尚餘春。行漏金徒曉，風煙是觀津。"]'),
('yuding-6','三會寺應制','蕭至忠','唐','御定全唐诗','yuding','','[]','岧嶢倉史台，敞朗紺園開。戒旦壺人警，翻霜羽騎來。',72,'御定全唐詩/json/104.json','["岧嶢倉史台，敞朗紺園開。戒旦壺人警，翻霜羽騎來。", "下輦登三襲，褰旒望九垓。林披館陶榜，水浸昆明灰。", "網戶飛花綴，幡竿度鳥回。豫遊仙唱動，瀟灑出塵埃。"]'),
('yuding-7','薦福寺應制','蕭至忠','唐','御定全唐诗','yuding','','[]','地靈傳景福，天駕儼鉤陳。佳哉藩邸舊，赫矣梵宮新。',72,'御定全唐詩/json/104.json','["地靈傳景福，天駕儼鉤陳。佳哉藩邸舊，赫矣梵宮新。", "香塔魚山下，禪堂雁水濱。珠幡映白日，鏡殿寫青春。", "甚歡延故吏，大覺拯生人。幸承歌頌末，長奉屬車塵。"]'),
('yuding-8','陪游上苑遇雪','蕭至忠','唐','御定全唐诗','yuding','','[]','龍驂曉入望春宮，正逢春雪舞春風。',32,'御定全唐詩/json/104.json','["龍驂曉入望春宮，正逢春雪舞春風。", "花光並在天文上，寒氣行銷禦酒中。"]'),
('yuding-9','奉和九日幸臨渭亭登高應制得風字','李迥秀','唐','御定全唐诗','yuding','','[]','重九臨商節，登高出漢宮。正逢萸實滿，還對菊花叢。',48,'御定全唐詩/json/104.json','["重九臨商節，登高出漢宮。正逢萸實滿，還對菊花叢。", "霽雲開就日，仙藻麗秋風。微臣預在鎬，竊抃遂無窮。"]'),
('yuding-10','奉和九月九日登慈恩寺浮圖應制','李迥秀','唐','御定全唐诗','yuding','','[]','沙界人王塔，金繩梵帝遊。言從祇樹賞，行玩菊叢秋。',48,'御定全唐詩/json/104.json','["沙界人王塔，金繩梵帝遊。言從祇樹賞，行玩菊叢秋。", "禦酒調甘露，天花拂彩旒。堯年將佛日，同此慶時休。"]'),
('yuding-11','奉和幸安樂公主山莊應制','李迥秀','唐','御定全唐诗','yuding','','[]','詰旦重門聞警蹕，傳言太主奏山林。是日回輿羅萬騎，',40,'御定全唐詩/json/104.json','["詰旦重門聞警蹕，傳言太主奏山林。是日回輿羅萬騎，", "手舞足蹈方無已，萬年千歲奉熏琴。"]'),
('yuding-12','夜宴安樂公主宅','李迥秀','唐','御定全唐诗','yuding','','[]','金榜岧嶢雲裏開，玉簫參差天際回。',32,'御定全唐詩/json/104.json','["金榜岧嶢雲裏開，玉簫參差天際回。", "莫驚側弁還歸路，只為平陽歌舞催。"]'),
('yuding-13','奉和九日幸臨渭亭登高應制得亭字','楊廉','唐','御定全唐诗','yuding','','[]','遠目瞰秦坰，重陽坐灞亭。既開黃菊酒，還降紫微星。',48,'御定全唐詩/json/104.json','["遠目瞰秦坰，重陽坐灞亭。既開黃菊酒，還降紫微星。", "簫鼓諳仙曲，山河入畫屏。幸茲陪宴喜，無以效丹青。"]'),
('yuding-14','奉和九月九日登慈恩寺浮圖應制','楊廉','唐','御定全唐诗','yuding','','[]','萬乘臨真境，重陽眺遠空。慈雲浮雁塔，定水映龍宮。',48,'御定全唐詩/json/104.json','["萬乘臨真境，重陽眺遠空。慈雲浮雁塔，定水映龍宮。", "寶鐸含飆響，仙輪帶日紅。天文將瑞色，輝煥滿寰中。"]'),
('yuding-15','奉和九日幸臨渭亭登高應制得枝字','韋安石','唐','御定全唐诗','yuding','','[]','重九開秋節，得一動宸儀。金風飄菊蕊，玉露泫萸枝。',48,'御定全唐詩/json/104.json','["重九開秋節，得一動宸儀。金風飄菊蕊，玉露泫萸枝。", "睿覽八紘外，天文七曜披。臨深應在即，居高豈忘危。"]'),
('yuding-16','侍宴旋師喜捷應制','韋安石','唐','御定全唐诗','yuding','','[]','蜂蟻屯夷落，熊羆逐漢飛。忘軀百戰後，屈指一年歸。',48,'御定全唐詩/json/104.json','["蜂蟻屯夷落，熊羆逐漢飛。忘軀百戰後，屈指一年歸。", "厚眷紓天藻，深慈解禦衣。興酣歌舞出，朝野歎光輝。"]'),
('yuding-17','梁王宅侍宴應制同用風字','韋安石','唐','御定全唐诗','yuding','','[]','梁園開勝景，軒駕動宸衷。早荷承湛露，修竹引熏風。',48,'御定全唐詩/json/104.json','["梁園開勝景，軒駕動宸衷。早荷承湛露，修竹引熏風。", "九醞傾鐘石，百獸協絲桐。小臣陪宴鎬，獻壽奉維嵩。"]'),
('yuding-18','奉和九日幸臨渭亭登高應制得明字','竇希玠','唐','御定全唐诗','yuding','','[]','鑾輿巡上苑，鳳駕瞰層城。御座丹烏麗，宸居白鶴驚。',48,'御定全唐詩/json/104.json','["鑾輿巡上苑，鳳駕瞰層城。御座丹烏麗，宸居白鶴驚。", "玉旗縈桂葉，金杯泛菊英。九晨陪聖膳，萬歲奉承明。"]'),
('yuding-19','奉和九日幸臨渭亭登高應制得臣字','陸景初','唐','御定全唐诗','yuding','','[]','九秋光順豫，重節霽良辰。登高識漢苑，問道侍軒臣。',48,'御定全唐詩/json/104.json','["九秋光順豫，重節霽良辰。登高識漢苑，問道侍軒臣。", "菊花浮秬鬯，萸房插縉紳。聖化邊陲謐，長洲鴻雁賓。"]'),
('yuding-20','奉和九日幸臨渭亭登高應制得日字','鄭南金','唐','御定全唐诗','yuding','','[]','重陽玉律應，萬乘金輿出。風起韻虞弦，雲開吐堯日。',48,'御定全唐詩/json/104.json','["重陽玉律應，萬乘金輿出。風起韻虞弦，雲開吐堯日。", "菊花浮聖酒，茱香掛衰質。欲知恩煦多，順動觀秋實。"]'),
('yuding-21','奉和九日幸臨渭亭登高應制得直字','李咸','唐','御定全唐诗','yuding','','[]','重陽乘令序，四野開晴色。日月數初並，乾坤聖登極。',48,'御定全唐詩/json/104.json','["重陽乘令序，四野開晴色。日月數初並，乾坤聖登極。", "菊黃迎酒泛，松翠淩霜直。遊海難為深，負山徒倦力。"]'),
('yuding-22','奉和九日幸臨渭亭登高應制得花字','趙彥伯','唐','御定全唐诗','yuding','','[]','九日報仙家，三秋轉歲華。呼鷹下鳥路，戲馬出龍沙。',48,'御定全唐詩/json/104.json','["九日報仙家，三秋轉歲華。呼鷹下鳥路，戲馬出龍沙。", "簪掛丹萸蕊，杯浮紫菊花。所願同微物，年年共辟邪。"]'),
('yuding-23','從宴桃花園詠桃花應制','趙彥伯','唐','御定全唐诗','yuding','','[]','紅萼競燃春苑曙，zv茸新吐禦筵開。',33,'御定全唐詩/json/104.json','["紅萼競燃春苑曙，zv茸新吐禦筵開。", "長年願奉西王宴，近侍慚無東朔才。"]'),
('yuding-24','苑中遇雪應制','趙彥伯','唐','御定全唐诗','yuding','','[]','千鐘聖酒禦筵披，六出祥英亂繞枝。',32,'御定全唐詩/json/104.json','["千鐘聖酒禦筵披，六出祥英亂繞枝。", "即此神仙對瓊圃，何煩轍跡向瑤池。"]'),
('yuding-25','奉和九日幸臨渭亭登高應制得樽字','於經野','唐','御定全唐诗','yuding','','[]','禦氣三秋節，登高九曲門。桂筵羅玉俎，菊醴溢芳樽。',48,'御定全唐詩/json/104.json','["禦氣三秋節，登高九曲門。桂筵羅玉俎，菊醴溢芳樽。", "遵渚歸鴻度，承雲舞鶴鶱。微臣濫陪賞，空荷聖明恩。"]'),
('yuding-26','奉和九日幸臨渭亭登高應制得還字','盧懷慎','唐','御定全唐诗','yuding','','[]','時和素秋節，宸豫紫機關。鶴似聞琴至，人疑宴鎬還。',48,'御定全唐詩/json/104.json','["時和素秋節，宸豫紫機關。鶴似聞琴至，人疑宴鎬還。", "曠望臨平野，潺湲俯暝灣。無因酬大德，空此愧崇班。"]'),
('yuding-27','奉和聖制龍池篇','盧懷慎','唐','御定全唐诗','yuding','','[]','代邸東南龍躍泉，清漪碧浪遠浮天。樓臺影就波中出，',40,'御定全唐詩/json/104.json','["代邸東南龍躍泉，清漪碧浪遠浮天。樓臺影就波中出，", "大川既濟慚為楫，報德空思奉細涓。"]'),
('yuding-0','奉和九月九日登慈恩寺浮圖應制','辛替否','唐','御定全唐诗','yuding','','[]','洪慈均動植，至德俯深玄。出豫從初地，登高適梵天。',48,'御定全唐詩/json/105.json','["洪慈均動植，至德俯深玄。出豫從初地，登高適梵天。", "白雲飛禦藻，慧日暖皇編。別有秋原藿，長傾雨露緣。"]'),
('yuding-1','奉和九月九日登慈恩寺浮圖應制','王景','唐','御定全唐诗','yuding','','[]','玉輦移中禁，珠梯覽四禪。重階清漢接，飛竇紫霄懸。',48,'御定全唐詩/json/105.json','["玉輦移中禁，珠梯覽四禪。重階清漢接，飛竇紫霄懸。", "綴葉披天藻，吹花散禦筵。無因鑾蹕暇，俱舞鶴林前。"]'),
('yuding-2','奉和九月九日登慈恩寺浮圖應制','畢幹泰','唐','御定全唐诗','yuding','','[]','鸚林花塔啟，鳳輦順時遊。重九昭皇慶，大千揚帝休。',48,'御定全唐詩/json/105.json','["鸚林花塔啟，鳳輦順時遊。重九昭皇慶，大千揚帝休。", "耆闍妙法闡，王舍睿文流。至德覃無極，小臣歌詎酬。"]'),
('yuding-3','奉和九月九日登慈恩寺浮圖應制','麹瞻','唐','御定全唐诗','yuding','','[]','扈蹕游玄地，陪仙瞰紫微。似邁銖衣劫，將同羽化飛。',48,'御定全唐詩/json/105.json','["扈蹕游玄地，陪仙瞰紫微。似邁銖衣劫，將同羽化飛。", "雕戈秋日麗，寶劍曉霜霏。獻觴乘菊序，長願奉天暉。"]'),
('yuding-4','奉和九月九日登慈恩寺浮圖應制','樊忱','唐','御定全唐诗','yuding','','[]','淨境重陽節，仙游萬乘來。插萸登鷲嶺，把菊坐蜂台。',48,'御定全唐詩/json/105.json','["淨境重陽節，仙游萬乘來。插萸登鷲嶺，把菊坐蜂台。", "十地祥雲合，三天瑞景開。秋風詞更遠，竊抃樂康哉。"]'),
('yuding-5','奉和九月九日登慈恩寺浮圖應制','孫佺','唐','御定全唐诗','yuding','','[]','應節萸房滿，初寒菊圃新。龍旗煥辰極，鳳駕儼香闉。',48,'御定全唐詩/json/105.json','["應節萸房滿，初寒菊圃新。龍旗煥辰極，鳳駕儼香闉。", "蓮井偏宜夏，梅梁更若春。一忻陪雁塔，還似得天身。"]'),
('yuding-6','奉和九月九日登慈恩寺浮圖應制','李從遠','唐','御定全唐诗','yuding','','[]','九月從時豫，三乘為法開。中霄日天子，半座寶如來。',48,'御定全唐詩/json/105.json','["九月從時豫，三乘為法開。中霄日天子，半座寶如來。", "摘果珠盤獻，攀萸玉輦回。願將塵露點，遙奉光明台。"]'),
('yuding-7','奉和九月九日登慈恩寺浮圖應制','周利用','唐','御定全唐诗','yuding','','[]','山豫乘金節，飛文煥日宮。萸房開聖酒，杏苑被玄功。',48,'御定全唐詩/json/105.json','["山豫乘金節，飛文煥日宮。萸房開聖酒，杏苑被玄功。", "塔向三天迥，禪收八解空。叨恩奉蘭藉，終愧洽熏風。"]'),
('yuding-8','奉和九月九日登慈恩寺浮圖應制','張景源','唐','御定全唐诗','yuding','','[]','飛塔淩霄起，宸遊一屆焉。金壺新泛菊，寶座即披蓮。',48,'御定全唐詩/json/105.json','["飛塔淩霄起，宸遊一屆焉。金壺新泛菊，寶座即披蓮。", "就日搖香輦，憑雲出梵天。祥氛與佳色，相伴雜爐煙。"]'),
('yuding-9','奉和九月九日登慈恩寺浮圖應制','李恒','唐','御定全唐诗','yuding','','[]','寶地鄰丹掖，香台瞰碧雲。河山天外出，城闕樹中分。',48,'御定全唐詩/json/105.json','["寶地鄰丹掖，香台瞰碧雲。河山天外出，城闕樹中分。", "睿藻蘭英秀，仙杯菊蕊熏。願將今日樂，長奉聖明君。"]'),
('yuding-10','奉和九月九日登慈恩寺浮圖應制','張錫','唐','御定全唐诗','yuding','','[]','九秋霜景淨，千門曉望通。仙游光禦路，瑞塔迥淩空。',48,'御定全唐詩/json/105.json','["九秋霜景淨，千門曉望通。仙游光禦路，瑞塔迥淩空。", "菊彩揚堯日，萸香繞舜風。天文麗辰象，竊抃仰層穹。"]'),
('yuding-11','晦日宴高文學林亭','張錫','唐','御定全唐诗','yuding','','[]','雪盡銅駝路，花照石崇家。年光開柳色，池影泛雲華。',48,'御定全唐詩/json/105.json','["雪盡銅駝路，花照石崇家。年光開柳色，池影泛雲華。", "賞洽情方遠，春歸景未賒。欲知多暇日，尊酒漬澄霞。"]'),
('yuding-12','奉和九月九日登慈恩寺浮圖應制','解琬','唐','御定全唐诗','yuding','','[]','瑞塔臨初地，金輿幸上方。空邊有清淨，覺處無馨香。',48,'御定全唐詩/json/105.json','["瑞塔臨初地，金輿幸上方。空邊有清淨，覺處無馨香。", "雨霽微塵斂，風秋定水涼。茲辰采仙菊，薦壽慶重陽。"]'),
('yuding-13','晦日宴高氏林亭','解琬','唐','御定全唐诗','yuding','','[]','主第簪裾出，王畿春照華。山亭一以眺，城闕帶煙霞。',48,'御定全唐詩/json/105.json','["主第簪裾出，王畿春照華。山亭一以眺，城闕帶煙霞。", "橫堤列錦帳，傍浦駐香車。歡娛屬晦節，酩酊未還家。"]'),
('yuding-0','侍宴長寧公主東莊應制','鄭愔','唐','御定全唐诗','yuding','','[]','公門襲漢環，主第稱秦玉。池架祥鱣序，山吹鳴鳳曲。',48,'御定全唐詩/json/106.json','["公門襲漢環，主第稱秦玉。池架祥鱣序，山吹鳴鳳曲。", "拂席蘿薜垂，回舟芰荷觸。平陽妙舞處，日暮清歌續。"]'),
('yuding-1','採蓮曲','鄭愔','唐','御定全唐诗','yuding','','[]','錦dh沙棠艦，羅帶石榴裙。綠潭采荷芰，清江日稍曛。',49,'御定全唐詩/json/106.json','["錦dh沙棠艦，羅帶石榴裙。綠潭采荷芰，清江日稍曛。", "魚鳥爭唼喋，花葉相芬氳。不覺芳洲暮，菱歌處處聞。"]'),
('yuding-2','夜遊曲','鄭愔','唐','御定全唐诗','yuding','','[]','漢室歡娛盛，魏國文雅遒。許史多暮宿，應陳從夜遊。',48,'御定全唐詩/json/106.json','["漢室歡娛盛，魏國文雅遒。許史多暮宿，應陳從夜遊。", "西園宴公子，北裏召王侯。詎似將軍獵，空嗟亭尉留。"]'),
('yuding-3','少年行','鄭愔','唐','御定全唐诗','yuding','','[]','潁川豪橫客，咸陽輕薄兒。田竇方貴幸，趙李新相知。',48,'御定全唐詩/json/106.json','["潁川豪橫客，咸陽輕薄兒。田竇方貴幸，趙李新相知。", "軒蓋終朝集，笙竽此夜吹。黃金盈篋笥，白日忽西馳。"]'),
('yuding-4','中宗降誕日長寧公主滿月侍宴應制','鄭愔','唐','御定全唐诗','yuding','','[]','春殿猗蘭美，仙階柏樹榮。地逢芳節應，時睹聖人生。',48,'御定全唐詩/json/106.json','["春殿猗蘭美，仙階柏樹榮。地逢芳節應，時睹聖人生。", "月滿增祥莢，天長髮瑞靈。南山遙可獻，常願奉皇明。"]'),
('yuding-5','奉和幸上官昭容院獻詩四首','鄭愔','唐','御定全唐诗','yuding','','[]','地軸樓居遠，天臺闕路賒。何如遊帝宅，即此對仙家。',192,'御定全唐詩/json/106.json','["地軸樓居遠，天臺闕路賒。何如遊帝宅，即此對仙家。", "座拂金壺電，池搖玉酒霞。無雲秦漢隔，別訪武陵花。", "堯茨姑射近，漢苑建章連。十五蓂知月，三千桃紀年。", "鸞歌隨鳳吹，鶴舞向鶤弦。更覓瓊妃伴，來過玉女泉。", "宮掖賢才重，山林高尚難。不言辭輦地，更有結廬歡。", "池棟清溫燠，岩窗起冱寒。幽亭有仙桂，聖主萬年看。", "槎流天上轉，茅宇禁中開。河鵲填橋至，山熊避檻來。", "庭花采菉蓐，岩石步莓苔。願奉輿圖泰，長開錦翰裁。"]'),
('yuding-6','送金城公主適西蕃應制','鄭愔','唐','御定全唐诗','yuding','','[]','下嫁戎庭遠，和親漢禮優。笳聲出虜塞，簫曲背秦樓。',48,'御定全唐詩/json/106.json','["下嫁戎庭遠，和親漢禮優。笳聲出虜塞，簫曲背秦樓。", "貴主悲黃鶴，征人怨紫騮。皇情眷億兆，割念俯懷柔。"]'),
('yuding-7','奉和幸望春宮送朔方大總管張仁亶','鄭愔','唐','御定全唐诗','yuding','','[]','禦蹕下都門，軍麾出塞垣。長楊跨武騎，細柳接戎軒。',48,'御定全唐詩/json/106.json','["禦蹕下都門，軍麾出塞垣。長楊跨武騎，細柳接戎軒。", "睿曲風雲動，邊威鼓吹喧。坐帷將閫外，俱是報明恩。"]'),
('yuding-8','奉和九月九日登慈恩寺浮圖應制','鄭愔','唐','御定全唐诗','yuding','','[]','湧霄開寶塔，倒影駐仙輿。雁子乘堂處，龍王起藏初。',48,'御定全唐詩/json/106.json','["湧霄開寶塔，倒影駐仙輿。雁子乘堂處，龍王起藏初。", "秋風聖主曲，佳氣史官書。願獻重陽壽，承歡萬歲餘。"]'),
('yuding-9','銅雀妓','鄭愔','唐','御定全唐诗','yuding','','[]','日斜漳浦望，風起鄴台寒。玉座平生晚，金尊妓吹闌。',48,'御定全唐詩/json/106.json','["日斜漳浦望，風起鄴台寒。玉座平生晚，金尊妓吹闌。", "舞餘依帳泣，歌罷向陵看。蕭索松風暮，愁煙入井闌。"]'),
('yuding-10','胡笳曲','鄭愔','唐','御定全唐诗','yuding','','[]','漢將留邊朔，遙遙歲序深。誰堪牧馬思，正是胡笳吟。',48,'御定全唐詩/json/106.json','["漢將留邊朔，遙遙歲序深。誰堪牧馬思，正是胡笳吟。", "曲斷關山月，聲悲雨雪陰。傳書問蘇武，陵也獨何心。"]'),
('yuding-11','折楊柳','鄭愔','唐','御定全唐诗','yuding','','[]','青柳映紅顏，黃雲蔽紫關。忽聞邊使出，枝葉為君攀。',48,'御定全唐詩/json/106.json','["青柳映紅顏，黃雲蔽紫關。忽聞邊使出，枝葉為君攀。", "舞腰愁欲斷，春心望不還。風花滾成雪，羅綺亂斑斑。"]'),
('yuding-12','秋閨','鄭愔','唐','御定全唐诗','yuding','','[]','征客向輪台，幽閨寂不開。音書秋雁斷，機杼夜蛩催。',48,'御定全唐詩/json/106.json','["征客向輪台，幽閨寂不開。音書秋雁斷，機杼夜蛩催。", "虛幌風吹葉，閑階露濕苔。自憐愁思影，常共月裴回。"]'),
('yuding-13','人日重宴大明宮恩賜彩縷人勝應制','鄭愔','唐','御定全唐诗','yuding','','[]','瓊殿含光映早輪，玉鸞嚴蹕望初晨。池開凍水仙宮麗，',40,'御定全唐詩/json/106.json','["瓊殿含光映早輪，玉鸞嚴蹕望初晨。池開凍水仙宮麗，", "良時荷澤皆迎勝，窮谷晞陽猶未春。"]'),
('yuding-14','奉和春日幸望春宮','鄭愔','唐','御定全唐诗','yuding','','[]','晨蹕淩高轉翠旌，春樓望遠背朱城。忽排花上游天苑，',40,'御定全唐詩/json/106.json','["晨蹕淩高轉翠旌，春樓望遠背朱城。忽排花上游天苑，", "幸同葵藿傾陽早，願比盤根應候榮。"]'),
('yuding-15','奉和幸三會寺應制','鄭愔','唐','御定全唐诗','yuding','','[]','鳥籀遺新閣，龍旗訪古台。造書臣頡往，觀跡帝羲來。',72,'御定全唐詩/json/106.json','["鳥籀遺新閣，龍旗訪古台。造書臣頡往，觀跡帝羲來。", "睿覽山川匝，宸心宇宙該。梵音隨駐輦，天步接乘杯。", "舊苑經寒露，殘池問劫灰。散花將捧日，俱喜聖慈開。"]'),
('yuding-16','奉和幸大薦福寺','鄭愔','唐','御定全唐诗','yuding','','[]','舊邸三乘辟，佳辰萬騎留。蘭圖奉葉偈，芝蓋拂花樓。',72,'御定全唐詩/json/106.json','["舊邸三乘辟，佳辰萬騎留。蘭圖奉葉偈，芝蓋拂花樓。", "國會人王法，宮還天帝遊。紫雲成寶界，白水作禪流。", "雁塔昌基遠，鸚林睿藻抽。欣承大風曲，竊預小童謳。"]'),
('yuding-17','同韋舍人早朝','鄭愔','唐','御定全唐诗','yuding','','[]','瑞闕龍居峻，宸庭鳳掖深。才良寄天綍，趨拜侶朝簪。',72,'御定全唐詩/json/106.json','["瑞闕龍居峻，宸庭鳳掖深。才良寄天綍，趨拜侶朝簪。", "飛馬看來影，喧車識駐音。重軒輕霧入，洞戶落花侵。", "聞有題新翰，依然想舊林。同聲慚卞玉，謬此托韋金。"]'),
('yuding-18','塞外三首','鄭愔','唐','御定全唐诗','yuding','','[]','塞外蕭條望，征人此路賒。邊聲亂朔馬，秋色引胡笳。',216,'御定全唐詩/json/106.json','["塞外蕭條望，征人此路賒。邊聲亂朔馬，秋色引胡笳。", "遙嶂侵歸日，長城帶晚霞。斷蓬飛古戍，連雁聚寒沙。", "海暗雲無葉，山春雪作花。丈夫期報主，萬里獨辭家。", "荒壘三秋夕，窮郊萬里平。海陰凝獨樹，日氣下連營。", "戎旆霜旋重，邊裘夜更輕。將軍猶轉戰，都尉不成名。", "折柳悲春曲，吹笳斷夜聲。明年漢使返，須築受降城。", "陽鳥南飛夜，陰山北地寒。漢家征戍客，年歲在樓蘭。", "玉塞朔風起，金河秋月團。邊聲入鼓吹，霜氣下旌竿。", "海外歸書斷，天涯旅鬢殘。子卿猶奉使，常向節旄看。"]'),
('yuding-19','春怨','鄭愔','唐','御定全唐诗','yuding','','[]','春朝物候妍，愁婦鏡臺前。風吹數蝶亂，露洗百花鮮。',60,'御定全唐詩/json/106.json','["春朝物候妍，愁婦鏡臺前。風吹數蝶亂，露洗百花鮮。", "試出褰羅幌，還來著錦筵。曲中愁夜夜，樓上別年年。", "不及隨蕭史，高飛向紫煙。"]'),
('yuding-20','貶降至汝州廣城驛','鄭愔','唐','御定全唐诗','yuding','','[]','近郊憑汝海，遐服指江幹。尚憶趨朝貴，方知失路難。',168,'御定全唐詩/json/106.json','["近郊憑汝海，遐服指江幹。尚憶趨朝貴，方知失路難。", "曙宮平樂遠，秋澤廣城寒。岸葦新花白，山梨晚葉丹。", "鄉關千里暮，歲序四時闌。函塞雲間別，旋門霧裏看。", "夙年追騄驥，暮節仰鵷鸞。疲駑勞垂耳，騫騰詎矯翰。", "將調梅鉉實，不正李園冠。荊玉終無玷，隨珠忽已彈。", "曉裝違鞏洛，夕夢在長安。北上頻傷阮，西征未學潘。", "傾車無共轍，同派有殊瀾。去去懷知己，何由報一餐。"]'),
('yuding-21','哭郎著作','鄭愔','唐','御定全唐诗','yuding','','[]','詩禮康成學，文章賈誼才。巳年人得夢，庚日鳥為災。',72,'御定全唐詩/json/106.json','["詩禮康成學，文章賈誼才。巳年人得夢，庚日鳥為災。", "書草藏天閣，琴聲入夜台。荒階羅駁蘚，虛座網浮埃。", "白馬賓徒散，青烏隴隧開。空憐門下客，懷舊幾遲回。"]'),
('yuding-22','詠黃鶯兒','鄭愔','唐','御定全唐诗','yuding','','[]','欲轉聲猶澀，將飛羽未調。高風不借便，何處得遷喬。',24,'御定全唐詩/json/106.json','["欲轉聲猶澀，將飛羽未調。高風不借便，何處得遷喬。"]'),
('yuding-23','百舌','鄭愔','唐','御定全唐诗','yuding','','[]','百舌鳴高樹，弄音無常則。借問聲何煩，末俗不尚默。',24,'御定全唐詩/json/106.json','["百舌鳴高樹，弄音無常則。借問聲何煩，末俗不尚默。"]'),
('yuding-0','奉和聖制送張說上集賢學士賜宴','源幹曜','唐','御定全唐诗','yuding','','[]','盛業光書府，征人盡國英。絲綸賢得相，群俊學為名。',72,'御定全唐詩/json/107.json','["盛業光書府，征人盡國英。絲綸賢得相，群俊學為名。", "寵命垂天錫，崇恩發睿情。熏風清禁籞，文殿述皇明。", "日霽庭陰出，池曛水氣生。歡娛此無限，詩酒自相迎。"]'),
('yuding-1','奉和禦制幹曜與張說宋璟同日上官命宴都堂賜詩','源幹曜','唐','御定全唐诗','yuding','','[]','睿作超千古，湛恩育萬人。遞遷俱荷澤，同拜忽為鄰。',96,'御定全唐詩/json/107.json','["睿作超千古，湛恩育萬人。遞遷俱荷澤，同拜忽為鄰。", "道合徽音暢，芳辰景命新。鼓鐘崇享禮，鵷鷺集朝倫。", "竊位思官謗，凋容謝木春。慚多無以敘，拙備實難陳。", "進綬懷三少，承光盡百身。自當歸第日，何幸列宮臣。"]'),
('yuding-2','奉和聖制送張尚書巡邊','源幹曜','唐','御定全唐诗','yuding','','[]','匈奴邇河朔，漢地須戎旅。天子擇英才，朝端出監撫。',120,'御定全唐詩/json/107.json','["匈奴邇河朔，漢地須戎旅。天子擇英才，朝端出監撫。", "流星下閶闔，寶鉞專公輔。禮物生光輝，宸章備恩詡。", "有征視矛戟，制勝唯樽俎。彼美何壯哉，桓桓擅斯舉。", "聲華振台閣，功德標文武。奉國知命輕，忘家以身許。", "安人在勤恤，保大殫襟腑。此外無異言，同情報明主。"]'),
('yuding-3','禪社首樂章','源幹曜','唐','御定全唐诗','yuding','','[]','靈具醉，杳熙熙。靈將往，眇禗禗。願明德，吐正詞。',32,'御定全唐詩/json/107.json','["靈具醉，杳熙熙。靈將往，眇禗禗。願明德，吐正詞。", "爛遺光，流禎祺。"]'),
('yuding-4','奉和聖制送張說赴集賢院學士賜宴賦得虛字','徐堅','唐','御定全唐诗','yuding','','[]','崇文德化洽，新殿集賢初。庸菲參高選，首濫承明廬。',72,'御定全唐詩/json/107.json','["崇文德化洽，新殿集賢初。庸菲參高選，首濫承明廬。", "殊私光輔弼，榮送列簪裾。座引中廚饌，杯錫上尊餘。", "翠葉濃丹苑，晴空卷碧虛。忝同文史地，願草登封書。"]'),
('yuding-5','奉和聖制送張說巡邊','徐堅','唐','御定全唐诗','yuding','','[]','至德撫遐荒，神兵赴朔方。帝思元帥重，爰擇股肱良。',120,'御定全唐詩/json/107.json','["至德撫遐荒，神兵赴朔方。帝思元帥重，爰擇股肱良。", "累相承安世，深籌協子房。寄崇專斧鉞，禮備設壇場。", "鼙鼓喧雷電，戈劍凜風霜。四騑將戒道，十乘啟先行。", "聖錫加恒數，天文耀寵光。出郊開帳飲，寅餞盛離章。", "雨濯梅林潤，風清麥野涼。燕山應勒頌，麟閣佇名揚。"]'),
('yuding-6','奉和送金城公主適西蕃應制','徐堅','唐','御定全唐诗','yuding','','[]','星漢下天孫，車服降殊蕃。匣中詞易切，馬上曲虛繁。',48,'御定全唐詩/json/107.json','["星漢下天孫，車服降殊蕃。匣中詞易切，馬上曲虛繁。", "關塞移朱帳，風塵暗錦軒。簫聲去日遠，萬里望河源。"]'),
('yuding-7','餞許州宋司馬赴任','徐堅','唐','御定全唐诗','yuding','','[]','舊許星車轉，神京祖帳開。斷煙傷別望，零雨送離杯。',48,'御定全唐詩/json/107.json','["舊許星車轉，神京祖帳開。斷煙傷別望，零雨送離杯。", "辭燕依空繞，賓鴻入聽哀。分襟與秋氣，日夕共悲哉。"]'),
('yuding-8','餞唐永昌','徐堅','唐','御定全唐诗','yuding','','[]','郎官出宰赴伊瀍，征傳駸駸灞水前。',32,'御定全唐詩/json/107.json','["郎官出宰赴伊瀍，征傳駸駸灞水前。", "此時悵望新豐道，握手相看共黯然。"]'),
('yuding-9','送考功武員外學士使嵩山置舍利塔歌','徐堅','唐','御定全唐诗','yuding','','[]','伊川別騎，灞岸分筵。對三春之花月，覽千里之風煙。',45,'御定全唐詩/json/107.json','["伊川別騎，灞岸分筵。對三春之花月，覽千里之風煙。", "望青山兮分地，見白雲兮在天。寄愁心於樽酒，"]'),
('yuding-10','棹歌行','徐堅','唐','御定全唐诗','yuding','','[]','棹女飾銀鉤，新妝下翠樓。霜絲青桂楫，蘭枻紫霞舟。',108,'御定全唐詩/json/107.json','["棹女飾銀鉤，新妝下翠樓。霜絲青桂楫，蘭枻紫霞舟。", "水落金陵曙，風起洞庭秋。扣舷過曲浦，飛帆越回流。", "影入桃花浪，香飄杜若洲。洲長殊未返，蕭散雲霞晚。", "日下大江平，煙生歸岸遠。岸遠聞潮波，爭途遊戲多。", "因聲趙津女，來聽采菱歌。"]'),
('yuding-11','送武進鄭明府','徐堅','唐','御定全唐诗','yuding','','[]','弦歌試宰日，城闕賞心違。北謝蒼龍去，南隨黃鵠飛。',48,'御定全唐詩/json/107.json','["弦歌試宰日，城闕賞心違。北謝蒼龍去，南隨黃鵠飛。", "夏雲海中出，吳山江上微。甿謠豈雲遠，從此慶緇衣。"]'),
('yuding-12','儀坤廟樂章','徐堅','唐','御定全唐诗','yuding','','[]','于穆清廟，肅雍嚴祀。合福受厘，介以繁祉。',20,'御定全唐詩/json/107.json','["于穆清廟，肅雍嚴祀。合福受厘，介以繁祉。"]'),
('yuding-13','祭汾陰樂章','源光裕','唐','御定全唐诗','yuding','','[]','方丘既膳，嘉饗載謐。齋敬畢誠，陶匏貴質。',40,'御定全唐詩/json/107.json','["方丘既膳，嘉饗載謐。齋敬畢誠，陶匏貴質。", "秀畢豐薦，芳俎盈實。永永福流，其升如日。"]'),
('yuding-0','奉和聖制送張說上集賢學士賜宴','李元紘','唐','御定全唐诗','yuding','','[]','碩儒延鳳沼，金馬被鴻私。饌玉趨丹禁，箋花降紫墀。',72,'御定全唐詩/json/108.json','["碩儒延鳳沼，金馬被鴻私。饌玉趨丹禁，箋花降紫墀。", "銜恩傾旨酒，鼓舞詠康時。暫覯群書緝，逾昭盛業丕。", "接筵欣有命，搦管愧無詞。自驚一何幸，太陽還及葵。"]'),
('yuding-1','綠墀怨','李元紘','唐','御定全唐诗','yuding','','[]','征馬噪金珂，嫖姚向北河。綠苔行跡少，紅粉淚痕多。',48,'御定全唐詩/json/108.json','["征馬噪金珂，嫖姚向北河。綠苔行跡少，紅粉淚痕多。", "寶屋粘花絮，銀箏覆網羅。別君如昨日，青海雁頻過。"]'),
('yuding-2','相思怨','李元紘','唐','御定全唐诗','yuding','','[]','望月思氛氳，朱衾懶更熏。春生翡翠帳，花點石榴裙。',48,'御定全唐詩/json/108.json','["望月思氛氳，朱衾懶更熏。春生翡翠帳，花點石榴裙。", "燕語時驚妾，鶯啼轉憶君。交河一萬里，仍隔數重雲。"]'),
('yuding-3','奉和聖制送張說上集賢學士賜宴','裴漼','唐','御定全唐诗','yuding','','[]','問道圖書盛，尊儒禮教興。石渠因學廣，金殿為賢升。',72,'御定全唐詩/json/108.json','["問道圖書盛，尊儒禮教興。石渠因學廣，金殿為賢升。", "日月恩光照，風雲寵命膺。謀謨言可範，舟楫事斯憑。", "宴喜明時洽，光輝湛露凝。大哉堯作主，天下頌歌稱。"]'),
('yuding-4','奉和禦制旋師喜捷','裴漼','唐','御定全唐诗','yuding','','[]','殊類驕無長，王師示有征。中軍才受律，妖寇已亡精。',48,'御定全唐詩/json/108.json','["殊類驕無長，王師示有征。中軍才受律，妖寇已亡精。", "斬虜還遮塞，綏降更築城。從來攻必克，天策振奇兵。"]'),
('yuding-5','奉和禦制平胡','裴漼','唐','御定全唐诗','yuding','','[]','玄漠聖恩通，由來書軌同。忽聞窺月滿，相聚寇雲中。',96,'御定全唐詩/json/108.json','["玄漠聖恩通，由來書軌同。忽聞窺月滿，相聚寇雲中。", "廟略占黃氣，神兵出絳宮。將軍行逐虜，使者亦和戎。", "一舉轒轀滅，再麾沙漠空。直將威禁暴，非用武為雄。", "飲至明軍禮，酬勳錫武功。干戈還載戢，文德在唐風。"]'),
('yuding-6','奉和聖制龍池篇','裴漼','唐','御定全唐诗','yuding','','[]','乾坤啟聖吐龍泉，泉水年年勝一年。始看魚躍方成海，',40,'御定全唐詩/json/108.json','["乾坤啟聖吐龍泉，泉水年年勝一年。始看魚躍方成海，", "休氣榮光恒不散，懸知此地是神仙。"]'),
('yuding-7','奉和聖制送張說上集賢學士賜宴','劉升','唐','御定全唐诗','yuding','','[]','圖書應明主，策府宴嘉賓。台曜臨東壁，幹光自北辰。',72,'御定全唐詩/json/108.json','["圖書應明主，策府宴嘉賓。台曜臨東壁，幹光自北辰。", "網羅窮象系，述作究天人。聖酒千鐘洽，仙廚百味陳。", "成山徒可仰，涉海詎知津。幸逢文教盛，還睹頌聲新。"]'),
('yuding-8','奉和聖制送張說上集賢學士賜宴','蕭嵩','唐','御定全唐诗','yuding','','[]','帝曰簡才能，旌賢在股肱。文章禮一變，禮樂道逾弘。',72,'御定全唐詩/json/108.json','["帝曰簡才能，旌賢在股肱。文章禮一變，禮樂道逾弘。", "芸閣英華入，賓門鵷鷺登。恩筵過所望，聖澤實超恒。", "夏葉開紅藥，餘花發紫藤。微臣亦何幸，叨此預文朋。"]'),
('yuding-9','奉和御製左丞相說右丞相璟太子少傅乾曜同日上官命宴都堂賜詩','蕭嵩','唐','御定全唐诗','yuding','','[]','審官思共理，多士屬惟唐。曆選台庭舊，來熙帝業昌。',96,'御定全唐詩/json/108.json','["審官思共理，多士屬惟唐。曆選台庭舊，來熙帝業昌。", "入朝師百辟，論道協三光。垂拱咨元老，親賢輔少陽。", "登庸崇禮送，寵德耀宸章。禦酒飛觴洽，仙闈雅樂張。", "荷恩思有報，陳力愧無良。願罄公忠節，同心奉我皇。"]'),
('yuding-10','奉和聖制送張說上集賢學士賜宴','韋抗','唐','御定全唐诗','yuding','','[]','廣庭臨璧沼，多士侍金閨。英宰文儒葉，明君日月齊。',72,'御定全唐詩/json/108.json','["廣庭臨璧沼，多士侍金閨。英宰文儒葉，明君日月齊。", "集賢光首拜，改殿發新題。早夏初移律，餘花尚拂溪。", "壺觴接雲上，經術引關西。聖德鴻名遠，將陪玉檢泥。"]'),
('yuding-11','奉和聖制送張說上集賢學士賜宴','李暠','唐','御定全唐诗','yuding','','[]','偃武堯風接，崇文漢道恢。集賢更內殿，清選自中台。',72,'御定全唐詩/json/108.json','["偃武堯風接，崇文漢道恢。集賢更內殿，清選自中台。", "佐命留侯業，詞華博物才。天廚千品降，禦酒百壺催。", "鵷鷺方成列，神仙喜暫陪。複欣同拜首，叨此頌良哉。"]'),
('yuding-12','奉和聖制送張說上集賢學士賜宴','韋述','唐','御定全唐诗','yuding','','[]','修文中禁啟，改字令名加。台座征人傑，書坊應國華。',72,'御定全唐詩/json/108.json','["修文中禁啟，改字令名加。台座征人傑，書坊應國華。", "賦詩開廣宴，賜酒酌流霞。雲散明金闕，池開照玉沙。", "掖垣留宿鳥，溫樹落餘花。謬此天光及，銜恩醉日斜。"]'),
('yuding-13','晚渡伊水','韋述','唐','御定全唐诗','yuding','','[]','悠悠涉伊水，伊水清見石。是時春向深，兩岸草如積。',120,'御定全唐詩/json/108.json','["悠悠涉伊水，伊水清見石。是時春向深，兩岸草如積。", "迢遞望洲嶼，逶迤亙津陌。新樹落疏紅，遙原上深碧。", "回瞻洛陽苑，遽有長山隔。煙霧猶辨家，風塵已為客。", "登陟多異趣，往來見行役。雲起早已昏，鳥飛日將夕。", "光陰逝不借，超然慕疇昔。遠遊亦何為，歸來存竹帛。"]'),
('yuding-14','春日山莊','韋述','唐','御定全唐诗','yuding','','[]','初歲開韶月，田家喜載陽。晚晴搖水態，遲景蕩山光。',48,'御定全唐詩/json/108.json','["初歲開韶月，田家喜載陽。晚晴搖水態，遲景蕩山光。", "浦淨漁舟遠，花飛樵路香。自然成野趣，都使俗情忘。"]'),
('yuding-15','廣陵送別宋員外佐越鄭舍人還京','韋述','唐','御定全唐诗','yuding','','[]','朱紱臨秦望，皇華赴洛橋。文章南渡越，書奏北歸朝。',48,'御定全唐詩/json/108.json','["朱紱臨秦望，皇華赴洛橋。文章南渡越，書奏北歸朝。", "樹入江雲盡，城銜海月遙。秋風將客思，川上晚蕭蕭。"]'),
('yuding-16','奉和聖制送張說上集賢學士賜宴','陸堅','唐','御定全唐诗','yuding','','[]','聖主崇文教，層霄降德音。尊賢澤既厚，式宴寵逾深。',72,'御定全唐詩/json/108.json','["聖主崇文教，層霄降德音。尊賢澤既厚，式宴寵逾深。", "複有夔龍相，良哉簡帝心。得人惟邁昔，多士諒推今。", "書殿榮光滿，儒門喜氣臨。顧惟誠濫吹，徒此接衣簪。"]'),
('yuding-17','句','陸堅','唐','御定全唐诗','yuding','','[]','風移覃土宇，雲上浹群臣。',12,'御定全唐詩/json/108.json','["風移覃土宇，雲上浹群臣。"]'),
('yuding-18','奉和聖制送張說上集賢學士賜宴','程行諶','唐','御定全唐诗','yuding','','[]','聖主崇文化，鏘鏘得盛才。相因歸夢立，殿以集賢開。',72,'御定全唐詩/json/108.json','["聖主崇文化，鏘鏘得盛才。相因歸夢立，殿以集賢開。", "象系微言闡，詩書至道該。堯尊承帝澤，禹膳自天來。", "禮洽歡逾長，風恬暑更回。國朝將舜頌，同是一康哉。"]'),
('yuding-19','奉和聖制送張說上集賢學士賜宴','褚琇','唐','御定全唐诗','yuding','','[]','講習延東觀，趨陪盛北宮。惟師恢帝則，敷教葉天工。',72,'御定全唐詩/json/108.json','["講習延東觀，趨陪盛北宮。惟師恢帝則，敷教葉天工。", "宣室恩嘗異，金華禮更崇。洞門清永日，華綬接微風。", "萐降堯廚翠，榴開舜酒紅。文思光萬宇，高議待升中。"]'),
('yuding-20','奉和御製左丞相說右丞相璟太子少傅乾曜同日上官命都堂賜詩','裴光庭','唐','御定全唐诗','yuding','','[]','樂賢聞往誥，褒德偶茲辰。端揆升元老，師謀擇累仁。',96,'御定全唐詩/json/108.json','["樂賢聞往誥，褒德偶茲辰。端揆升元老，師謀擇累仁。", "紫庭崇讓畢，粉署禮容陳。既荷恩榮舊，俱承寵命新。", "天文懸瑞色，聖酒泛華茵。雜遝喧簫鼓，歡娛洽搢紳。", "掖垣招近侍，虛薄廁清塵。共保堅貞節，常期雨露均。"]'),
('yuding-21','奉和聖製左丞相說右丞相璟太子少傅乾曜同日上官命宴都堂賜詩','宇文融','唐','御定全唐诗','yuding','','[]','申甫生周日，宣慈舉舜年。何如偶昌運，比德邁前賢。',96,'御定全唐詩/json/108.json','["申甫生周日，宣慈舉舜年。何如偶昌運，比德邁前賢。", "寵獲元良密，榮瞻端揆遷。職優三事老，位在百僚先。", "北極回宸渥，南宮飾禦筵。飛文瑤劄降，賜酒玉杯傳。", "謬列台衡重，俱承雨露偏。誓將同竭力，相與郊塵涓。"]'),
('yuding-22','奉和聖制同二相已下群官樂遊園宴','崔沔','唐','御定全唐诗','yuding','','[]','五日酺才畢，千年樂未央。複承天所賜，終宴國之陽。',72,'御定全唐詩/json/108.json','["五日酺才畢，千年樂未央。複承天所賜，終宴國之陽。", "地勝春逾好，恩深樂更張。落花飛廣座，垂柳拂行觴。", "庶尹陪三史，諸侯具萬方。酒酣同抃躍，歌舞詠時康。"]'),
('yuding-23','奉和聖制同二相已下群臣樂遊園宴','崔尚','唐','御定全唐诗','yuding','','[]','春日照長安，皇恩寵庶官。合錢承罷宴，賜帛複追歡。',72,'御定全唐詩/json/108.json','["春日照長安，皇恩寵庶官。合錢承罷宴，賜帛複追歡。", "供帳憑高列，城池入迥寬。花催相國醉，鳥和樂人彈。", "北闕雲中見，南山樹杪看。樂遊宜締賞，舞詠惜將闌。"]'),
('yuding-24','奉和聖制同二相以下群官樂遊園宴','胡皓','唐','御定全唐诗','yuding','','[]','五酺終宴集，三錫又歡娛。仙阜崇高異，神州眺覽殊。',72,'御定全唐詩/json/108.json','["五酺終宴集，三錫又歡娛。仙阜崇高異，神州眺覽殊。", "南山臨皓雪，北闕對明珠。廣座鵷鴻滿，昌庭駟馬趨。", "綺羅含草樹，絲竹吐郊衢。銜杯不能罷，歌舞樂唐虞。"]'),
('yuding-25','奉和聖制送張尚書巡邊','胡皓','唐','御定全唐诗','yuding','','[]','燕公為漢將，武德奉文思。利用經戎莽，英圖葉聖詒。',120,'御定全唐詩/json/108.json','["燕公為漢將，武德奉文思。利用經戎莽，英圖葉聖詒。", "塞沙制長策，窮石卷搖旗。萬里要相賀，三邊又在茲。", "棱威方逐逐，談笑坐怡怡。寵餞紛郊道，充廚竭禦司。", "嘗醪企行邁，聽樂罷漣洏。袞旒垂翰墨，纓蕤迭賦詩。", "金山無積阻，玉樹有華滋。請迨炎風暮，歸旌候此時。"]'),
('yuding-26','和宋之問寒食題臨江驛','胡皓','唐','御定全唐诗','yuding','','[]','聞道山陰會，仍為火忌辰。途中甘棄日，江上苦傷春。',48,'御定全唐詩/json/108.json','["聞道山陰會，仍為火忌辰。途中甘棄日，江上苦傷春。", "流水翻催淚，寒灰更伴人。丹心終不改，白髮為誰新。"]'),
('yuding-27','出峽','胡皓','唐','御定全唐诗','yuding','','[]','巴東三峽盡，曠望九江開。楚塞雲中出，荊門水上來。',48,'御定全唐詩/json/108.json','["巴東三峽盡，曠望九江開。楚塞雲中出，荊門水上來。", "魚龍潛嘯雨，鳧雁動成雷。南國秋風晚，客思幾悠哉。"]'),
('yuding-28','同蔡孚起居詠鸚鵡','胡皓','唐','御定全唐诗','yuding','','[]','鸚鵡殊姿致，鸞皇得比肩。常尋金殿裏，每話玉階前。',48,'御定全唐詩/json/108.json','["鸚鵡殊姿致，鸞皇得比肩。常尋金殿裏，每話玉階前。", "賈誼才方達，揚雄老未遷。能言既有地，何惜為聞天。"]'),
('yuding-29','大漠行','胡皓','唐','御定全唐诗','yuding','','[]','單于犯薊壖，虜騎略蕭邊。南山木葉飛下地，',172,'御定全唐詩/json/108.json','["單于犯薊壖，虜騎略蕭邊。南山木葉飛下地，", "三軍遙倚伏，萬里相馳逐。旌旆悠悠靜潮源，", "馬蹄凍溜石，胡毳暖生冰。雲沙泱漭天光閉，", "近見行人畏白龍，遙聞公主愁黃鶴。陽春半，岐路間；", "瑤台苑，玉門關。百花芳樹紅將歇，二月蘭皋綠未還。", "陣雲不散魚龍水，雨雪猶飛鴻鵠山。山嶂綿連那可極，", "漢將紛紜攻戰盈，胡寇蕭條幽朔清。韓昌拜節偏知送，", "但得將軍能百勝，不須天子築長城。"]'),
('yuding-0','朝退','李適之','唐','御定全唐诗','yuding','','[]','朱門長不閉，親友恣相過。年今將半百，不樂複如何。',24,'御定全唐詩/json/109.json','["朱門長不閉，親友恣相過。年今將半百，不樂複如何。"]'),
('yuding-1','罷相作','李適之','唐','御定全唐诗','yuding','','[]','避賢初罷相，樂聖且銜杯。為問門前客，今朝幾個來。',24,'御定全唐詩/json/109.json','["避賢初罷相，樂聖且銜杯。為問門前客，今朝幾個來。"]'),
('yuding-2','題漢州西湖','房管','唐','御定全唐诗','yuding','','[]','高流纏峻隅，城下緬丘墟。決渠信浩蕩，潭島成江湖。',120,'御定全唐詩/json/109.json','["高流纏峻隅，城下緬丘墟。決渠信浩蕩，潭島成江湖。", "結宇依回渚，水中信可居。三伏氣不蒸，四達暑自徂。", "同人千里駕，鄰國五馬車。月出共登舟，風生隨所如。", "舉麾指極浦，欲極更盤紆。繚繞各殊致，夜盡情有餘。", "遭亂意不開，即理還暫祛。安得長晤語，使我憂更除。"]'),
('yuding-3','詠方圓動靜','李泌','唐','御定全唐诗','yuding','','[]','方如行義，圓如用智。動如逞才，靜如遂意。',20,'御定全唐詩/json/109.json','["方如行義，圓如用智。動如逞才，靜如遂意。"]'),
('yuding-4','長歌行','李泌','唐','御定全唐诗','yuding','','[]','天覆吾，地載吾，天地生吾有意無。不然絕粒升天衢，',48,'御定全唐詩/json/109.json','["天覆吾，地載吾，天地生吾有意無。不然絕粒升天衢，", "一丈夫兮一丈夫，千生氣志是良圖。請君看取百年事，"]'),
('yuding-5','奉和聖制中和節曲江宴百僚','李泌','唐','御定全唐诗','yuding','','[]','風俗時有變，中和節惟新。軒車雙闕下，宴會曲江濱。',61,'御定全唐詩/json/109.json','["風俗時有變，中和節惟新。軒車雙闕下，宴會曲江濱。", "金石何鏗鏘，簪纓亦紛綸。皇恩降自天，品物感知春。", "慈恩匝寰瀛，歌詠同君臣。。"]'),
('yuding-6','奉和聖制，重陽賜會聊示所懷','李泌','唐','御定全唐诗','yuding','','[]','大唐造昌運，品物荷時成。乘秋逢令節，錫宴觀群情。',61,'御定全唐詩/json/109.json','["大唐造昌運，品物荷時成。乘秋逢令節，錫宴觀群情。", "俯臨秦山川，高會漢公卿。。", "未追赤松子，且泛黃菊英。賡歌聖人作，海內同休明。"]'),
('yuding-7','句','李泌','唐','御定全唐诗','yuding','','[]','青青東門柳，歲晏複憔悴。',40,'御定全唐詩/json/109.json','["青青東門柳，歲晏複憔悴。", "良弓摧折久，誰識是龍韜。", "旋沫翻成碧玉池，添酥散出琉璃眼。"]'),
('yuding-8','享太廟樂章：廣運舞','郭子儀','唐','御定全唐诗','yuding','','[]','于赫皇祖，昭明有融。惟文之德，惟武之功。',40,'御定全唐詩/json/109.json','["于赫皇祖，昭明有融。惟文之德，惟武之功。", "河海靜謐，車書混同。虔恭孝饗，穆穆玄風。"]'),
('yuding-9','享太廟樂章：保大舞','郭子儀','唐','御定全唐诗','yuding','','[]','于穆文考，聖神昭彰。簫勺群慝，含光遠方。',40,'御定全唐詩/json/109.json','["于穆文考，聖神昭彰。簫勺群慝，含光遠方。", "萬物茂遂，九夷賓王。愔愔雲韶，德音不忘。"]'),
('yuding-0','百子池','張諤','唐','御定全唐诗','yuding','','[]','舊聞百子漢家池，漢家淥水今逶迤。宮女厭鏡笑窺池，',24,'御定全唐詩/json/110.json','["舊聞百子漢家池，漢家淥水今逶迤。宮女厭鏡笑窺池，"]'),
('yuding-1','東封山下宴群臣','張諤','唐','御定全唐诗','yuding','','[]','萬里扈封巒，群公遇此歡。幔城連夜靜，霜仗滿空寒。',48,'御定全唐詩/json/110.json','["萬里扈封巒，群公遇此歡。幔城連夜靜，霜仗滿空寒。", "輦路宵煙合，旌門曉月殘。明朝陪聖主，山下禮圓壇。"]'),
('yuding-2','三日岐王宅','張諤','唐','御定全唐诗','yuding','','[]','玉女貴妃生，嫛婗始發聲。金盆浴未了，繃子繡初成。',48,'御定全唐詩/json/110.json','["玉女貴妃生，嫛婗始發聲。金盆浴未了，繃子繡初成。", "翡翠雕芳縟，真珠帖小纓。何時學健步，鬥取落花輕。"]'),
('yuding-3','滿月','張諤','唐','御定全唐诗','yuding','','[]','社金流茂祉，庭玉表奇才。竹似因談植，蘭疑入夢栽。',48,'御定全唐詩/json/110.json','["社金流茂祉，庭玉表奇才。竹似因談植，蘭疑入夢栽。", "烏將八子去，鳳逐九雛來。今夜明珠色，當隨滿月開。"]'),
('yuding-4','岐王山亭','張諤','唐','御定全唐诗','yuding','','[]','王家傍綠池，春色正相宜。豈有樓臺好，兼看草樹奇。',48,'御定全唐詩/json/110.json','["王家傍綠池，春色正相宜。豈有樓臺好，兼看草樹奇。", "石榴天上葉，椰子日南枝。出入千門裏，年年樂未移。"]'),
('yuding-5','岐王席上詠美人','張諤','唐','御定全唐诗','yuding','','[]','半額畫雙蛾，盈盈燭下歌。玉杯寒意少，金屋夜情多。',48,'御定全唐詩/json/110.json','["半額畫雙蛾，盈盈燭下歌。玉杯寒意少，金屋夜情多。", "香豔王分帖，裙嬌敕賜羅。平陽莫相妒，喚出不如他。"]'),
('yuding-6','還京','張諤','唐','御定全唐诗','yuding','','[]','朱紱臨秦望，皇華赴洛橋。文章南渡越，書奏北歸朝。',48,'御定全唐詩/json/110.json','["朱紱臨秦望，皇華赴洛橋。文章南渡越，書奏北歸朝。", "樹入江雲盡，城銜海月遙。秋風將客思，川上晚蕭蕭。"]'),
('yuding-7','贈吏部孫員外濟','張諤','唐','御定全唐诗','yuding','','[]','天子愛賢才，星郎入拜來。明光朝半下，建禮直初回。',48,'御定全唐詩/json/110.json','["天子愛賢才，星郎入拜來。明光朝半下，建禮直初回。", "名帶含香發，文隨綺幕開。披雲自有鏡，從此照仙台。"]'),
('yuding-8','送李著作倅杭州','張諤','唐','御定全唐诗','yuding','','[]','輟史空三署，題輿佐一方。祖筵開霽景，征陌直朝光。',48,'御定全唐詩/json/110.json','["輟史空三署，題輿佐一方。祖筵開霽景，征陌直朝光。", "水陸風煙隔，秦吳道路長。佇聞敷善政，邦國詠惟康。"]'),
('yuding-9','九日','張諤','唐','御定全唐诗','yuding','','[]','秋來林下不知春，一種佳遊事也均。絳葉從朝飛著夜，',40,'御定全唐詩/json/110.json','["秋來林下不知春，一種佳遊事也均。絳葉從朝飛著夜，", "城遠登高並九日，茱萸凡作幾年新。"]'),
('yuding-10','延平門高齋亭子應岐王教','張諤','唐','御定全唐诗','yuding','','[]','花源藥嶼鳳城西，翠幕紗窗鶯亂啼。昨夜蒲萄初上架，',40,'御定全唐詩/json/110.json','["花源藥嶼鳳城西，翠幕紗窗鶯亂啼。昨夜蒲萄初上架，", "請語東風催後騎，並將歌舞向前溪。"]'),
('yuding-11','九日宴','張諤','唐','御定全唐诗','yuding','','[]','秋葉風吹黃颯颯，晴雲日照白鱗鱗。',32,'御定全唐詩/json/110.json','["秋葉風吹黃颯颯，晴雲日照白鱗鱗。", "歸來得問茱萸女，今日登高醉幾人。"]'),
('yuding-12','從軍','劉庭琦','唐','御定全唐诗','yuding','','[]','朔風吹寒塞，胡沙千萬里。陳雲出岱山，孤月生海水。',48,'御定全唐詩/json/110.json','["朔風吹寒塞，胡沙千萬里。陳雲出岱山，孤月生海水。", "決勝方求敵，銜恩本輕死。蕭蕭牧馬鳴，中夜拔劍起。"]'),
('yuding-13','奉和聖制瑞雪篇','劉庭琦','唐','御定全唐诗','yuding','','[]','紫宸飛雪曉裴回，層閣重門雪照開。九衢皛耀浮埃盡，',96,'御定全唐詩/json/110.json','["紫宸飛雪曉裴回，層閣重門雪照開。九衢皛耀浮埃盡，", "埋雲翳景無窮已，因風落地吹還起。先過翡翠寶房中，", "羅衣點著渾是花，玉手摶來半成水。奕奕紛紛何所如，", "姑射山中符聖壽，芙蓉闕下降神車。願隨睿澤流無限，"]'),
('yuding-14','詠木槿樹題武進文明府廳','劉庭琦','唐','御定全唐诗','yuding','','[]','物情良可見，人事不勝悲。莫恃朝榮好，君看暮落時。',24,'御定全唐詩/json/110.json','["物情良可見，人事不勝悲。莫恃朝榮好，君看暮落時。"]'),
('yuding-15','銅雀台','劉庭琦','唐','御定全唐诗','yuding','','[]','銅台宮觀委灰塵，魏主園林漳水濱。',32,'御定全唐詩/json/110.json','["銅台宮觀委灰塵，魏主園林漳水濱。", "即今西望猶堪思，況複當時歌舞人。"]'),
('yuding-16','失白鷹','鄭繇','唐','御定全唐诗','yuding','','[]','白錦文章亂，丹霄羽翮齊。雲中呼暫下，雪裏放還迷。',48,'御定全唐詩/json/110.json','["白錦文章亂，丹霄羽翮齊。雲中呼暫下，雪裏放還迷。", "梁苑驚池鶩，陳倉拂野雞。不知寥廓外，何處獨依棲。"]'),
('yuding-17','經慈澗題','鄭繇','唐','御定全唐诗','yuding','','[]','岸與恩同廣，波將慈共深。涓涓勞日夜，長似下流心。',24,'御定全唐詩/json/110.json','["岸與恩同廣，波將慈共深。涓涓勞日夜，長似下流心。"]'),
('yuding-0','奉和禦制平胡','韓休','唐','御定全唐诗','yuding','','[]','南牧正紛紛，長河起塞氛。玉符征選士，金鉞拜將軍。',96,'御定全唐詩/json/111.json','["南牧正紛紛，長河起塞氛。玉符征選士，金鉞拜將軍。", "疊鼓搖邊吹，連旌暗朔雲。祅星乘夜落，害氣入朝分。", "始見幽烽警，俄看烈火焚。功成奏凱樂，戰罷策歸勳。", "盛德陳清廟，神謨屬大君。叨榮逢偃羽，率舞詠時文。"]'),
('yuding-1','奉和聖制送張說巡邊','韓休','唐','御定全唐诗','yuding','','[]','一德光台象，三軍掌夏卿。來威申廟略，出總葉師貞。',120,'御定全唐詩/json/111.json','["一德光台象，三軍掌夏卿。來威申廟略，出總葉師貞。", "受鉞辭金殿，憑軒去鼎城。曙光搖組甲，疏吹繞雲旌。", "左律方先凱，中鼙即訓兵。定功彰武事，陳頌紀天聲。", "祖宴初留賞，宸章更寵行。車徒零雨送，林野夕陰生。", "路極河流遠，川長朔氣平。東轅遲返旆，歸奏謁承明。"]'),
('yuding-2','祭汾陰樂章','韓休','唐','御定全唐诗','yuding','','[]','于穆浚哲，維清緝熙。肅事昭配，永言孝思。',40,'御定全唐詩/json/111.json','["于穆浚哲，維清緝熙。肅事昭配，永言孝思。", "滌濯靜嘉，馨香在茲。神之聽之，用受福厘。"]'),
('yuding-3','征君宅','許景先','唐','御定全唐诗','yuding','','[]','征君昔嘉遁，抗跡遺俗塵。了心悟有物，乘化遊無垠。',168,'御定全唐詩/json/111.json','["征君昔嘉遁，抗跡遺俗塵。了心悟有物，乘化遊無垠。", "道喪曆千載，複存潁陽真。上虞佳山水，晚歲耽隱淪。", "內史既解綬，支公亦相親。儒道匪遠理，意勝聊自欣。", "洄沿南溪夕，流浪東山春。石壁踐丹景，金潭冒綠蘋。", "探煉備海嶠，賞心寓情人。奈何靈仙骨，鍬翮瑤池津。", "寥寥虛白宇，夙創招提因。家風緬多尚，玄德謝無鄰。", "謬陪金門彥，矯跡侍紫宸。皇恩竟已矣，遺烈庶不泯。"]'),
('yuding-4','折柳篇','許景先','唐','御定全唐诗','yuding','','[]','春色東來度渭橋，青門垂柳百千條。長楊西連建章路，',72,'御定全唐詩/json/111.json','["春色東來度渭橋，青門垂柳百千條。長楊西連建章路，", "春樓初日照南隅，柔條垂綠掃金鋪。寶釵新梳倭墮髻，", "芳樹朝催玉管新，春風夜染羅衣薄。城頭楊柳已如絲，"]'),
('yuding-5','奉和禦制春台望','許景先','唐','御定全唐诗','yuding','','[]','睿德在青陽，高居視中縣。秦城連鳳闕，漢寢疏龍殿。',132,'御定全唐詩/json/111.json','["睿德在青陽，高居視中縣。秦城連鳳闕，漢寢疏龍殿。", "文物照光輝，郊畿鬱蔥蒨。千門望成錦，八水明如練。", "複道曉光披，宸遊出禁移。瑞氣朝浮五雲閣，", "秦漢生人凋力役，阿房甘泉構雲碧。汾祠雍畤望通天，", "明主卑宮誡前失，輔德欽賢政惟一。昆蟲不夭在春搜，", "豫奉北辰齊七政，長歌東武抃千春。"]'),
('yuding-6','陽春怨','許景先','唐','御定全唐诗','yuding','','[]','紅樹曉鶯啼，春風暖翠閨。雕籠熏繡被，珠履踏金堤。',48,'御定全唐詩/json/111.json','["紅樹曉鶯啼，春風暖翠閨。雕籠熏繡被，珠履踏金堤。", "芍藥花初吐，菖蒲葉正齊。槁砧當此日，行役向遼西。"]'),
('yuding-7','奉和聖制送張尚書巡邊','許景先','唐','御定全唐诗','yuding','','[]','文武承邦式，風雲感國禎。王師親賦政，廟略久論兵。',120,'御定全唐詩/json/111.json','["文武承邦式，風雲感國禎。王師親賦政，廟略久論兵。", "漢主知三傑，周官統六卿。四方分閫受，千里坐謀成。", "介胄辭前殿，壺觴宿左營。賞延頒賜重，宸贈出車榮。", "龍武三軍氣，魚鈴五校名。郊雲駐旌羽，邊吹引金鉦。", "訓旅方稱德，安人更克貞。佇看銘石罷，同聽凱歌聲。"]'),
('yuding-8','詠史','王丘','唐','御定全唐诗','yuding','','[]','高潔非養正，盛名亦險艱。偉哉謝安石，攜妓入東山。',96,'御定全唐詩/json/111.json','["高潔非養正，盛名亦險艱。偉哉謝安石，攜妓入東山。", "雲岩響金奏，空水灩朱顏。蘭露滋香澤，松風鳴佩環。", "歌聲入空盡，舞影到池閑。杳眇同天上，繁華非代間。", "卷舒混名跡，縱誕無憂患。何必蘇門子，冥然閉清關。"]'),
('yuding-9','奉和聖制答張說扈從南出鼠雀穀之作','王丘','唐','御定全唐诗','yuding','','[]','襟帶三秦接，旗常萬乘過。陽原淑氣早，陰穀冱寒多。',72,'御定全唐詩/json/111.json','["襟帶三秦接，旗常萬乘過。陽原淑氣早，陰穀冱寒多。", "花縟前茅仗，霜嚴後殿戈。代雲開晉嶺，江雁入汾河。", "北土分堯俗，南風動舜歌。一聞天樂唱，恭逐萬人和。"]'),
('yuding-10','奉和聖制送張尚書巡邊','王丘','唐','御定全唐诗','yuding','','[]','德業蘊時宗，幽符夢象通。台司計祈父，師律總元戎。',108,'御定全唐詩/json/111.json','["德業蘊時宗，幽符夢象通。台司計祈父，師律總元戎。", "出入敷能政，謀猷體至公。贈行光睿什，宴別感宸衷。", "文炳高天曜，恩垂湛露融。建牙之塞表，鳴鼓接雲中。", "策密鬼神秘，威成劍騎雄。朔門正炎月，兵氣已秋風。", "肅殺從此始，方知胡運窮。"]'),
('yuding-11','過賈六','蘇晉','唐','御定全唐诗','yuding','','[]','主人病且閑，客來情彌適。一酌複一笑，不知日將夕。',48,'御定全唐詩/json/111.json','["主人病且閑，客來情彌適。一酌複一笑，不知日將夕。", "昨來屬歡游，於今盡成昔。努力持所趣，空名定何益。"]'),
('yuding-12','奉和聖制送張說巡邊','蘇晉','唐','御定全唐诗','yuding','','[]','方漢比周年，興王合在宣。亟聞降虜拜，複睹出師篇。',120,'御定全唐詩/json/111.json','["方漢比周年，興王合在宣。亟聞降虜拜，複睹出師篇。", "祈父萬邦式，英猷三略傳。算車申夏政，茇舍啟戎田。", "嚴問盟胡苑，軍容濟洛川。皇情悵關旆，詔餞列郊筵。", "路接禁園草，池分禦井蓮。離聲軫去角，居念斷歸蟬。", "三捷豈云爾，七擒良信然。具僚誠寄望，奏凱秋風前。"]'),
('yuding-13','奉和聖制送張說巡邊','崔禹錫','唐','御定全唐诗','yuding','','[]','供帳何煌煌，公其撫朔方。群僚咸餞酌，明主降離章。',120,'御定全唐詩/json/111.json','["供帳何煌煌，公其撫朔方。群僚咸餞酌，明主降離章。", "關塞重門下，郊岐禁苑傍。練兵宜雨洗，臥鼓候風涼。", "炎景寧雲憚，神謀肅所將。旌搖天月迥，騎入塞雲長。", "赫赫皇威振，油油聖澤滂。非惟按車甲，兼以正封疆。", "叱吒陰山道，澄清瀚海陽。虜垣行決勝，台座佇為光。"]'),
('yuding-14','恩敕尚書省僚宴昆明池應制','張嘉貞','唐','御定全唐诗','yuding','','[]','靈沼初開漢，神池舊浴堯。昔人徒習武，明代此聞韶。',72,'御定全唐詩/json/111.json','["靈沼初開漢，神池舊浴堯。昔人徒習武，明代此聞韶。", "地脈山川勝，天恩雨露饒。時光牽利舸，春淑覆柔條。", "芳醞酲千日，華箋落九霄。幸承歡賚重，不覺醉歸遙。"]'),
('yuding-15','奉和早登太行山中言志應制','張嘉貞','唐','御定全唐诗','yuding','','[]','明發扈山巔，飛龍高在天。山南平對鞏，山北遠通燕。',96,'御定全唐詩/json/111.json','["明發扈山巔，飛龍高在天。山南平對鞏，山北遠通燕。", "瞻彼岡巒峻，憑茲士馬妍。九圻行若砥，萬穀輾如川。", "羅網開三面，閭閻問百年。澤將春雪比，文共曉星連。", "徯後逢今聖，登臺謝曩賢。唯餘事君節，不讓古人先。"]'),
('yuding-16','奉和聖制送張說巡邊','張嘉貞','唐','御定全唐诗','yuding','','[]','天錫我宗盟，元戎付夏卿。多才兼將相，必勇獨橫行。',120,'御定全唐詩/json/111.json','["天錫我宗盟，元戎付夏卿。多才兼將相，必勇獨橫行。", "經緯稱人傑，文章作代英。山川看是陣，草木想為兵。", "不待河冰合，猶防塞月明。有謀當系醜，無戰且綏氓。", "閫外傳三略，雲中冀一平。感恩同義激，悵別屢魂驚。", "直視前旌掣，遙聞後騎鳴。還期方定日，複此出郊迎。"]'),
('yuding-17','句','張嘉貞','唐','御定全唐诗','yuding','','[]','河魚未上凍，江蟄已聞雷。',12,'御定全唐詩/json/111.json','["河魚未上凍，江蟄已聞雷。"]'),
('yuding-18','奉和聖制送張說巡邊','盧從願','唐','御定全唐诗','yuding','','[]','上將發文昌，中軍靜朔方。占星引旌節，擇日拜壇場。',120,'御定全唐詩/json/111.json','["上將發文昌，中軍靜朔方。占星引旌節，擇日拜壇場。", "禮樂臨軒送，威聲出塞揚。安邊俟帷幄，制勝在岩廊。", "作鼓將軍氣，投醪壯士觴。戒途遵六月，離贈動三光。", "槐路清梅暑，蘅皋起麥涼。時文仰雄伯，耀武震遐荒。", "衽席知無戰，兵戈示不忘。佇聞歌杕杜，凱入系名王。"]'),
('yuding-19','祭汾陰樂章','盧從願','唐','御定全唐诗','yuding','','[]','坤元載物，陽樂發生。播植資始，品匯咸亨。',40,'御定全唐詩/json/111.json','["坤元載物，陽樂發生。播植資始，品匯咸亨。", "列俎棋布，方壇砥平。神歆禋祀，後德惟明。"]'),
('yuding-20','長門怨','袁暉','唐','御定全唐诗','yuding','','[]','早知君愛歇，本自無縈妒。誰使恩情深，今來反相誤。',48,'御定全唐詩/json/111.json','["早知君愛歇，本自無縈妒。誰使恩情深，今來反相誤。", "愁眠羅帳曉，泣坐金閨暮。獨有夢中魂，猶言意如故。"]'),
('yuding-21','銅雀妓','袁暉','唐','御定全唐诗','yuding','','[]','君愛本相饒，從來似舞腰。那堪攀玉座，腸斷望陵朝。',48,'御定全唐詩/json/111.json','["君愛本相饒，從來似舞腰。那堪攀玉座，腸斷望陵朝。", "怨著情無主，哀凝曲不調。況臨松日暮，悲吹坐蕭蕭。"]'),
('yuding-22','正月閨情','袁暉','唐','御定全唐诗','yuding','','[]','正月金閨裏，微風繡戶間。曉魂憐別夢，春思逼啼顏。',48,'御定全唐詩/json/111.json','["正月金閨裏，微風繡戶間。曉魂憐別夢，春思逼啼顏。", "繞砌梅堪折，當軒樹未攀。歲華庭北上，何日度陽關。"]'),
('yuding-23','二月閨情','袁暉','唐','御定全唐诗','yuding','','[]','二月韶光好，春風香氣多。園中花巧笑，林裏鳥能歌。',48,'御定全唐詩/json/111.json','["二月韶光好，春風香氣多。園中花巧笑，林裏鳥能歌。", "有恨離琴瑟，無情著綺羅。更聽春燕語，妾亦不如他。"]'),
('yuding-24','三月閨情','袁暉','唐','御定全唐诗','yuding','','[]','三月春將盡，空房妾獨居。蛾眉愁自結，鬢髮沒情梳。',48,'御定全唐詩/json/111.json','["三月春將盡，空房妾獨居。蛾眉愁自結，鬢髮沒情梳。", "□□□□□，□□□□□。□□□□□，□□□□□。"]'),
('yuding-25','七月閨情','袁暉','唐','御定全唐诗','yuding','','[]','七月坐涼宵，金波滿麗譙。容華芳意改，枕席怨情饒。',48,'御定全唐詩/json/111.json','["七月坐涼宵，金波滿麗譙。容華芳意改，枕席怨情饒。", "錦字沾愁淚，羅裙緩細腰。不如銀漢女，歲歲鵲成橋。"]'),
('yuding-26','奉和聖制答張說扈從南出雀鼠穀之作','袁暉','唐','御定全唐诗','yuding','','[]','魏國山河險，周王警蹕回。九旗雲際出，萬騎穀中來。',72,'御定全唐詩/json/111.json','["魏國山河險，周王警蹕回。九旗雲際出，萬騎穀中來。", "石路行將盡，煙郊望忽開。賞矜垂柳報，春畏落花催。", "興逸橫汾什，恩褒作頌才。小臣瞻日月，延首詠康哉。"]'),
('yuding-27','奉和聖制送張尚書巡邊','袁暉','唐','御定全唐诗','yuding','','[]','出師宣九命，分閫用三台。始應幕中畫，言從天上來。',120,'御定全唐詩/json/111.json','["出師宣九命，分閫用三台。始應幕中畫，言從天上來。", "丹青不獨任，韜略遂雙該。坐見威棱洽，彌彰事業恢。", "旌旗曉雲送，鞞鼓朔風催。虜氣消殘月，邊聲韻落梅。", "羽書雄北地，龍漠寢南垓。寵戰黃金盡，輸誠白日回。", "離章宸翰發，祖宴國門開。欲識恩華盛，平生文武材。"]'),
('yuding-28','奉和聖制答張說扈從南出雀鼠谷','王光庭','唐','御定全唐诗','yuding','','[]','省俗恩將遍，巡方路稍回。寒隨汾穀盡，春逐晉郊來。',72,'御定全唐詩/json/111.json','["省俗恩將遍，巡方路稍回。寒隨汾穀盡，春逐晉郊來。", "雲騎傳行漏，煙旄引從台。惠風初應律，和氣正調梅。", "雅頌通宸詠，天文接曙台。灞陵桃李色，應待日華開。"]'),
('yuding-29','奉和聖制送張說巡邊','王光庭','唐','御定全唐诗','yuding','','[]','賢相德符充，朝推文武雄。海波先若鏡，關草豫從風。',120,'御定全唐詩/json/111.json','["賢相德符充，朝推文武雄。海波先若鏡，關草豫從風。", "鉞助將軍勇，威成天子功。瓊章九霄發，錫宴五衢通。", "玉輾龍盤帶，金裝鳳勒驄。虎貔紛儗儗，河洛振熊熊。", "戈劍千霜白，旌旗萬火紅。示刑夷夏變，流惠鬼方同。", "寇息軍容偃，塵銷朔野空。用師敷禮樂，非是為獯戎。"]'),
('yuding-30','奉和聖制送張說巡邊','徐知仁','唐','御定全唐诗','yuding','','[]','聖德膺三統，皇恩被八埏。大明均照物，小丑未甯邊。',120,'御定全唐詩/json/111.json','["聖德膺三統，皇恩被八埏。大明均照物，小丑未甯邊。", "國相台衡重，元戎廟略宣。紫泥方受命，黃石乃推賢。", "問罪陰山下，安人屬國前。度關行照月，乘障坐消煙。", "北闕紆宸藻，南橋列祖筵。耀威當夏日，殺氣指秋天。", "鞞鼓黿鼉振，旌旗鳥獸懸。由來詞翰手，今見勒燕然。"]'),
('yuding-31','奉和敕賜公主鏡','席豫','唐','御定全唐诗','yuding','','[]','令節頒龍鏡，仙輝下鳳台。含靈萬象入，寫照百花開。',48,'御定全唐詩/json/111.json','["令節頒龍鏡，仙輝下鳳台。含靈萬象入，寫照百花開。", "色與皇明散，光隨聖澤來。妍媸冰鑒裏，從此愧非才。"]'),
('yuding-32','江行紀事二首','席豫','唐','御定全唐诗','yuding','','[]','飄颻任舟楫，回合傍江津。後浦情猶在，前山賞更新。',96,'御定全唐詩/json/111.json','["飄颻任舟楫，回合傍江津。後浦情猶在，前山賞更新。", "樹深煙冪冪，灘淺石磷磷。川路南行遠，淹留惜此辰。", "江汛春風勢，山樓曙月輝。猿攀紫岩飲，鳥拂清潭飛。", "古樹崩沙岸，新苔覆石磯。津途賞無限，征客暫忘歸。"]'),
('yuding-33','奉和聖制答張說南出雀鼠谷','席豫','唐','御定全唐诗','yuding','','[]','鳴鑾初幸代，旋蓋欲橫汾。山盡千旗出，郊平五校分。',72,'御定全唐詩/json/111.json','["鳴鑾初幸代，旋蓋欲橫汾。山盡千旗出，郊平五校分。", "前林已暄景，後壑尚寒氛。風送簫韶曲，花鋪黼黻文。", "鹽梅推上宰，禮樂統中軍。獻賦紆天劄，飄颻飛白雲。"]'),
('yuding-34','奉和聖制送張說巡邊','席豫','唐','御定全唐诗','yuding','','[]','聖主重兵權，分符屬大賢。中軍仍執政，丞相複巡邊。',120,'御定全唐詩/json/111.json','["聖主重兵權，分符屬大賢。中軍仍執政，丞相複巡邊。", "翕習戎裝動，張惶廟略宣。朝榮承睿劄，野餞轉行旃。", "亭障東緣海，沙場北際天。春冬見岩雪，朝夕候烽煙。", "已勒封山記，猶聞遣戍篇。五營將月合，八陣與雲連。", "經略圖方遠，懷柔道更全。歸來畫麟閣，藹藹武功傳。"]'),
('yuding-35','祭汾陰樂章','韓思複','唐','御定全唐诗','yuding','','[]','大樂和暢，殷薦明神。一降通感，八變必臻。',40,'御定全唐詩/json/111.json','["大樂和暢，殷薦明神。一降通感，八變必臻。", "有求斯應，無德不親。降靈醉止，休征萬人。"]'),
('yuding-36','祭汾陰樂章','劉晃','唐','御定全唐诗','yuding','','[]','大君出震，有事郊禋。齋戒既肅，馨香畢陳。',40,'御定全唐詩/json/111.json','["大君出震，有事郊禋。齋戒既肅，馨香畢陳。", "樂和禮備，候暖風春。恭惟降福，實賴明神。"]'),
('yuding-0','唐禪社首樂章：順和','賀知章','唐','御定全唐诗','yuding','','[]','至哉含柔德，萬物資以生。常順稱厚載，流謙通變盈。',48,'御定全唐詩/json/112.json','["至哉含柔德，萬物資以生。常順稱厚載，流謙通變盈。", "聖心事能察，增廣陳厥誠。黃祇僾如在，泰折俟咸亨。"]'),
('yuding-1','唐禪社首樂章：太和','賀知章','唐','御定全唐诗','yuding','','[]','肅我成命，于昭黃祇。裘冕而祀，陟降在斯。',40,'御定全唐詩/json/112.json','["肅我成命，于昭黃祇。裘冕而祀，陟降在斯。", "五音克備，八變聿施。緝熙肆靖，厥心匪離。"]'),
('yuding-2','唐禪社首樂章：肅和','賀知章','唐','御定全唐诗','yuding','','[]','黃祇是祗，我其夙夜。夤畏誠絜，匪遑寧舍。',40,'御定全唐詩/json/112.json','["黃祇是祗，我其夙夜。夤畏誠絜，匪遑寧舍。", "禮以琮玉，薦厥茅藉。念茲降康，胡寧克暇。"]'),
('yuding-3','唐禪社首樂章：雍和','賀知章','唐','御定全唐诗','yuding','','[]','夙夜宥密，不敢寧宴。五齊既陳，八音在縣。',40,'御定全唐詩/json/112.json','["夙夜宥密，不敢寧宴。五齊既陳，八音在縣。", "粢盛以絜，房俎斯薦。惟德惟馨，尚茲克遍。"]'),
('yuding-4','唐禪社首樂章：壽和','賀知章','唐','御定全唐诗','yuding','','[]','惟以明發，有懷載殷。樂盈而反，禮順其禋。',40,'御定全唐詩/json/112.json','["惟以明發，有懷載殷。樂盈而反，禮順其禋。", "立清以獻，薦欲是親。于穆不已，裒對斯臻。"]'),
('yuding-5','唐禪社首樂章：福和','賀知章','唐','御定全唐诗','yuding','','[]','穆穆天子，告成岱宗。大裘如濡，執珽有顒。',40,'御定全唐詩/json/112.json','["穆穆天子，告成岱宗。大裘如濡，執珽有顒。", "樂以平志，禮以和容。上帝臨我，雲胡肅邕。"]'),
('yuding-6','唐禪社首樂章：太和','賀知章','唐','御定全唐诗','yuding','','[]','昭昭有唐，天俾萬國。列祖應命，四宗順則。',40,'御定全唐詩/json/112.json','["昭昭有唐，天俾萬國。列祖應命，四宗順則。", "申錫無疆，宗我同德。曾孫繼緒，享神配極。"]'),
('yuding-7','曉發','賀知章','唐','御定全唐诗','yuding','','[]','江皋聞曙鐘，輕枻理還舼。海潮夜約約，川露晨溶溶。',48,'御定全唐詩/json/112.json','["江皋聞曙鐘，輕枻理還舼。海潮夜約約，川露晨溶溶。", "始見沙上鳥，猶埋雲外峰。故鄉杳無際，明發懷朋從。"]'),
('yuding-8','奉和禦制春台望','賀知章','唐','御定全唐诗','yuding','','[]','青陽布王道，玄覽陶真性。欣若天下春，高逾域中聖。',156,'御定全唐詩/json/112.json','["青陽布王道，玄覽陶真性。欣若天下春，高逾域中聖。", "神皋類觀賞，帝裏如懸鏡。繚繞八川浮，岧嶢雙闕映。", "曉色遍昭陽，晴雲卷建章。華滋的皪丹青樹，", "自昔秦奢漢窮武，後庭萬餘宮百數。旗回五丈殿千門，", "乃眷天晴興隱恤，古來土木良非一。荊臨章觀趙叢台。", "何如堯階將禹室。層欄窈窕下龍輿，清管逶迤半綺疏。", "一聽南風引鸞舞，長謠北極仰鶉居。"]'),
('yuding-9','望人家桃李花','賀知章','唐','御定全唐诗','yuding','','[]','山源夜雨度仙家，朝發東園桃李花。桃花紅兮李花白，',88,'御定全唐詩/json/112.json','["山源夜雨度仙家，朝發東園桃李花。桃花紅兮李花白，", "棄置千金輕不顧，踟躕五馬謝相逢。徒言南國容華晚，", "苑中珍木元自奇，黃金作葉白銀枝。千年萬歲不凋落，", "莫道春花不可樹，會持仙實薦君王。"]'),
('yuding-10','送人之軍','賀知章','唐','御定全唐诗','yuding','','[]','常經絕脈塞，複見斷腸流。送子成今別，令人起昔愁。',48,'御定全唐詩/json/112.json','["常經絕脈塞，複見斷腸流。送子成今別，令人起昔愁。", "隴雲晴半雨，邊草夏先秋。萬里長城寄，無貽漢國憂。"]'),
('yuding-11','奉和聖制送張說上集賢學士賜宴賦得謨字','賀知章','唐','御定全唐诗','yuding','','[]','西學垂玄覽，東堂發聖謨。天光燭武殿，時宰集鴻都。',72,'御定全唐詩/json/112.json','["西學垂玄覽，東堂發聖謨。天光燭武殿，時宰集鴻都。", "枯朽沾皇澤，翾飛舞帝梧。跡同游汗漫，榮是出泥塗。", "三歎承湯鼎，千歡接舜壺。微軀不可答，空欲詠依蒲。"]'),
('yuding-12','奉和聖制送張說巡邊','賀知章','唐','御定全唐诗','yuding','','[]','荒憬盡懷忠，梯航已自通。九攻雖不戰，五月尚持戎。',120,'御定全唐詩/json/112.json','["荒憬盡懷忠，梯航已自通。九攻雖不戰，五月尚持戎。", "遣戍征周牒，恢邊重漢功。選車命元宰，授律取文雄。", "胄出天弧上，謀成帝幄中。詔旗分夏物，專土錫唐弓。", "帳宿伊川右，鉦傳晉苑東。饔人藉蕡實，樂正理絲桐。", "岐陌涵餘雨，離川照晚虹。恭聞詠方叔，千載舞皇風。"]'),
('yuding-13','題袁氏別業','賀知章','唐','御定全唐诗','yuding','','[]','主人不相識，偶坐為林泉。莫謾愁沽酒，囊中自有錢。',24,'御定全唐詩/json/112.json','["主人不相識，偶坐為林泉。莫謾愁沽酒，囊中自有錢。"]'),
('yuding-14','詠柳','賀知章','唐','御定全唐诗','yuding','','[]','碧玉妝成一樹高，萬條垂下綠絲絛。',32,'御定全唐詩/json/112.json','["碧玉妝成一樹高，萬條垂下綠絲絛。", "不知細葉誰裁出，二月春風似剪刀。"]'),
('yuding-15','採蓮曲','賀知章','唐','御定全唐诗','yuding','','[]','稽山罷霧鬱嵯峨，鏡水無風也自波。',32,'御定全唐詩/json/112.json','["稽山罷霧鬱嵯峨，鏡水無風也自波。", "莫言春度芳菲盡，別有中流采芰荷。"]'),
('yuding-16','回鄉偶書二首','賀知章','唐','御定全唐诗','yuding','','[]','少小離鄉老大回，鄉音難改鬢毛衰。',64,'御定全唐詩/json/112.json','["少小離鄉老大回，鄉音難改鬢毛衰。", "兒童相見不相識，笑問客從何處來。", "離別家鄉歲月多，近來人事半銷磨。", "唯有門前鏡湖水，春風不改舊時波。"]'),
('yuding-17','答朝士','賀知章','唐','御定全唐诗','yuding','','[]','fk鏤銀盤盛蛤蜊，鏡湖蓴菜亂如絲。',33,'御定全唐詩/json/112.json','["fk鏤銀盤盛蛤蜊，鏡湖蓴菜亂如絲。", "鄉曲近來佳此味，遮渠不道是吳兒。"]'),
('yuding-18','句','賀知章','唐','御定全唐诗','yuding','','[]','落花真好些，一醉一回顛。',12,'御定全唐詩/json/112.json','["落花真好些，一醉一回顛。"]'),
('yuding-0','敬酬張九齡當塗界留贈之作','裴耀卿','唐','御定全唐诗','yuding','','[]','茂先實王佐，仲舉信時英。氣睹沖天發，人將下榻迎。',108,'御定全唐詩/json/113.json','["茂先實王佐，仲舉信時英。氣睹沖天發，人將下榻迎。", "珪符肅有命，江國遠徂征。九派期方越，千鈞或所輕。", "高帆出風迥，孤嶼入雲平。遄邁嗟於役，離憂空自情。", "飾簪陪早歲，接壤廁專城。曠別心彌軫，宏觀義轉傾。", "徒然恨饑渴，況乃諷瑤瓊。"]'),
('yuding-1','酬張九齡使風見示','裴耀卿','唐','御定全唐诗','yuding','','[]','茲地五湖鄰，艱哉萬里人。驚飆翻是托，危浪亦相因。',48,'御定全唐詩/json/113.json','["茲地五湖鄰，艱哉萬里人。驚飆翻是托，危浪亦相因。", "宣室才華子，金閨諷議臣。承明有三入，去去速歸輪。"]'),
('yuding-2','贈張丞相','宋鼎','唐','御定全唐诗','yuding','','[]','漢上登飛幰，荊南曆舊居。已嘗臨砌橘，更睹躍池魚。',72,'御定全唐詩/json/113.json','["漢上登飛幰，荊南曆舊居。已嘗臨砌橘，更睹躍池魚。", "盛德繼微渺，深衷能卷舒。義申蓬閣際，情切廟堂初。", "郡挹文章美，人懷燮理餘。皇恩儻照亮，豈厭承明廬。"]'),
('yuding-3','酬故人還山','宋鼎','唐','御定全唐诗','yuding','','[]','舉棹乘春水，歸山撫歲華。碧潭宵見月，紅樹晚開花。',72,'御定全唐詩/json/113.json','["舉棹乘春水，歸山撫歲華。碧潭宵見月，紅樹晚開花。", "肅穆輕風度，依微隱徑斜。危亭暗松石，幽澗落雲霞。", "思鳥吟高樹，遊魚戲淺沙。安知餘興盡，相望紫煙賒。"]'),
('yuding-4','和張荊州九齡晨出郡舍林下','崔頌','唐','御定全唐诗','yuding','','[]','優閑表政清，林薄賞秋成。江上懸曉月，往來虧複盈。',48,'御定全唐詩/json/113.json','["優閑表政清，林薄賞秋成。江上懸曉月，往來虧複盈。", "天雲抗真意，郡閣晦高名。坐嘯應無欲，甯辜濟物情。"]'),
('yuding-5','奉酬張洪州九齡江上見贈','孫翃','唐','御定全唐诗','yuding','','[]','受命讞封疆，逢君牧豫章。于焉審虞芮，複爾共舟航。',48,'御定全唐詩/json/113.json','["受命讞封疆，逢君牧豫章。于焉審虞芮，複爾共舟航。", "悵別秋陰盡，懷歸客思長。江皋枉離贈，持此慰他鄉。"]'),
('yuding-6','古意贈孫翃','徐仁友','唐','御定全唐诗','yuding','','[]','南望緱氏嶺，山居共澗陰。東西十數裏，緬邈方寸心。',48,'御定全唐詩/json/113.json','["南望緱氏嶺，山居共澗陰。東西十數裏，緬邈方寸心。", "雲日落廣廈，鶯花對孤琴。琴中多苦調，淒切誰複尋。"]'),
('yuding-7','奉和姚令公駕幸溫湯喜雪應制','蘇綰','唐','御定全唐诗','yuding','','[]','漢主新豐邑，周王尚父師。雲符沛童唱，雪應海神期。',48,'御定全唐詩/json/113.json','["漢主新豐邑，周王尚父師。雲符沛童唱，雪應海神期。", "林變驚春早，山明訝夕遲。況逢溫液霈，恩重禦裘詩。"]'),
('yuding-8','詠月','康庭芝','唐','御定全唐诗','yuding','','[]','天使下西樓，光含萬里秋。台前疑掛鏡，簾外似懸鉤。',48,'御定全唐詩/json/113.json','["天使下西樓，光含萬里秋。台前疑掛鏡，簾外似懸鉤。", "張尹將眉學，班姬取扇儔。佳期應借問，為報在刀頭。"]'),
('yuding-9','山行見孤松成詠','張宣明','唐','御定全唐诗','yuding','','[]','孤松鬱山椒，肅爽淩清霄。既挺千丈幹，亦生百尺條。',60,'御定全唐詩/json/113.json','["孤松鬱山椒，肅爽淩清霄。既挺千丈幹，亦生百尺條。", "青青恒一色，落落非一朝。大廈今已構，惜哉無人招。", "寒霜十二月，枝葉獨不凋。"]'),
('yuding-10','使至三姓咽面','張宣明','唐','御定全唐诗','yuding','','[]','昔聞班家子，筆硯忽然投。一朝撫長劍，萬里入荒陬。',84,'御定全唐詩/json/113.json','["昔聞班家子，筆硯忽然投。一朝撫長劍，萬里入荒陬。", "豈不服艱險，只思清國讎。山川去何歲，霜露幾逢秋。", "玉塞已遐廓，鐵關方阻修。東都日窅窅，西海此悠悠。", "卒使功名建，長封萬里侯。"]'),
('yuding-11','新都南亭別郭大元振','盧崇道','唐','御定全唐诗','yuding','','[]','竹徑女蘿蹊，蓮洲文石堤。靜深人俗斷，尋玩往還迷。',72,'御定全唐詩/json/113.json','["竹徑女蘿蹊，蓮洲文石堤。靜深人俗斷，尋玩往還迷。", "碧潭秀初月，素林驚夕棲。褰幌納鳥侶，罷琴聽猿啼。", "佳辰改宿昔，勝寄在暌攜。長懷賞心愛，如玉複如珪。"]'),
('yuding-0','登翅頭山題儼公石壁','包融','唐','御定全唐诗','yuding','','[]','晨登翅頭山，山曛黃霧起。卻瞻迷向背，直下失城市。',120,'御定全唐詩/json/114.json','["晨登翅頭山，山曛黃霧起。卻瞻迷向背，直下失城市。", "暾日銜東郊，朝光生邑裏。掃除諸煙氛，照出眾樓雉。", "青為洞庭山，白是太湖水。蒼茫遠郊樹，倏忽不相似。", "萬象以區別，森然共盈幾。坐令開心胸，漸覺落塵滓。", "北岩千餘仞，結廬誰家子。願陪中峰遊，朝暮白雲裏。"]'),
('yuding-1','阮公嘯台','包融','唐','御定全唐诗','yuding','','[]','荒台森荊杞，蒙籠無上路。傳是古人跡，阮公長嘯處。',72,'御定全唐詩/json/114.json','["荒台森荊杞，蒙籠無上路。傳是古人跡，阮公長嘯處。", "至今清風來，時時動林樹。逝者共已遠，升攀想遺趣。", "靜然荒榛門，久之若有悟。靈光未歇滅，千載知仰慕。"]'),
('yuding-2','酬忠公林亭','包融','唐','御定全唐诗','yuding','','[]','江外有真隱，寂居歲已侵。結廬近西術，種樹久成陰。',120,'御定全唐詩/json/114.json','["江外有真隱，寂居歲已侵。結廬近西術，種樹久成陰。", "人跡乍及戶，車聲遙隔林。自言解塵事，咫尺能輜塵。", "為道豈廬霍，會靜由吾心。方秋院木落，仰望日蕭森。", "持我興來趣，采菊行相尋。塵念到門盡，遠情對君深。", "一談入理窟，再索破幽襟。安得山中信，致書移尚禽。"]'),
('yuding-3','送國子張主簿','包融','唐','御定全唐诗','yuding','','[]','湖岸纜初解，鶯啼別離處。遙見舟中人，時時一回顧。',48,'御定全唐詩/json/114.json','["湖岸纜初解，鶯啼別離處。遙見舟中人，時時一回顧。", "坐悲芳歲晚，花落青軒樹。春夢隨我心，悠揚逐君去。"]'),
('yuding-4','和陳校書省中玩雪','包融','唐','御定全唐诗','yuding','','[]','芸閣朝來雪，飄颻正滿空。褰開明月下，校理落花中。',48,'御定全唐詩/json/114.json','["芸閣朝來雪，飄颻正滿空。褰開明月下，校理落花中。", "色向懷鉛白，光因翰簡融。能令草玄者，回思入流風。"]'),
('yuding-5','和崔會稽詠王兵曹廳前湧泉勢城中字','包融','唐','御定全唐诗','yuding','','[]','茂德來征應，流泉入詠歌。含靈符上善，作字表中和。',48,'御定全唐詩/json/114.json','["茂德來征應，流泉入詠歌。含靈符上善，作字表中和。", "有草恒垂露，無風欲偃波。為看人共水，清白定誰多。"]'),
('yuding-6','賦得岸花臨水發','包融','唐','御定全唐诗','yuding','','[]','笑笑傍溪花，叢叢逐岸斜。朝開川上日，夜發浦中霞。',49,'御定全唐詩/json/114.json','["笑笑傍溪花，叢叢逐岸斜。朝開川上日，夜發浦中霞。", "照灼如臨鏡，zv茸勝浣紗。春來武陵道，幾樹落仙家。"]'),
('yuding-7','武陵桃源送人','包融','唐','御定全唐诗','yuding','','[]','武陵川徑入幽遐，中有雞犬秦人家。',32,'御定全唐詩/json/114.json','["武陵川徑入幽遐，中有雞犬秦人家。", "先時見者為誰耶，源水今流桃複花。"]'),
('yuding-8','和薦福寺英公新構禪堂','丁仙芝','唐','御定全唐诗','yuding','','[]','上人久棄世，中道自忘筌。寂照出群有，了心清眾緣。',96,'御定全唐詩/json/114.json','["上人久棄世，中道自忘筌。寂照出群有，了心清眾緣。", "所以於此地，築館開青蓮。果藥羅砌下，煙虹垂戶前。", "咒中灑甘露，指處流香泉。禪遠目無事，體清宵不眠。", "枳聞廬山法，松入漢陽禪。一枕西山外，虛舟常浩然。"]'),
('yuding-9','贈朱中書','丁仙芝','唐','御定全唐诗','yuding','','[]','十年種田濱五湖，十年遭澇盡為蕪。頻年井稅常不足，',64,'御定全唐詩/json/114.json','["十年種田濱五湖，十年遭澇盡為蕪。頻年井稅常不足，", "而我守道不遷業，誰能肯敢效此事。紫微侍郎白虎殿，", "會應憐爾居素約，可即長年守貧賤。"]'),
('yuding-10','戲贈姚侍禦','丁仙芝','唐','御定全唐诗','yuding','','[]','繁霜曉幕鳴柏烏，待子獸炭然金爐。重門啟鎖紫髯胡。',48,'御定全唐詩/json/114.json','["繁霜曉幕鳴柏烏，待子獸炭然金爐。重門啟鎖紫髯胡。", "新披驄馬隴西駒，頭戴獬豸急晨趨。明光殿前見天子，"]'),
('yuding-11','餘杭醉歌贈吳山人','丁仙芝','唐','御定全唐诗','yuding','','[]','曉幕紅襟燕，春城白項烏。只來梁上語，不向府中趨。',64,'御定全唐詩/json/114.json','["曉幕紅襟燕，春城白項烏。只來梁上語，不向府中趨。", "城頭坎坎鼓聲曙，滿庭新種櫻桃樹。桃花昨夜撩亂開，", "酒後留君待明月，還將明月送君回。"]'),
('yuding-12','京中守歲','丁仙芝','唐','御定全唐诗','yuding','','[]','守歲多然燭，通宵莫掩扉。客愁當暗滿，春色向明歸。',48,'御定全唐詩/json/114.json','["守歲多然燭，通宵莫掩扉。客愁當暗滿，春色向明歸。", "玉鬥巡初匝，銀河落漸微。開正獻歲酒，千里間庭闈。"]'),
('yuding-13','渡揚子江','丁仙芝','唐','御定全唐诗','yuding','','[]','桂楫中流望，空波兩畔明。林開揚子驛，山出潤州城。',48,'御定全唐詩/json/114.json','["桂楫中流望，空波兩畔明。林開揚子驛，山出潤州城。", "海盡邊陰靜，江寒朔吹生。更聞風葉下，淅瀝度秋聲。"]'),
('yuding-14','長寧公主舊山池','丁仙芝','唐','御定全唐诗','yuding','','[]','平陽舊池館，寂寞使人愁。座卷流黃簟，簾垂白玉鉤。',48,'御定全唐詩/json/114.json','["平陽舊池館，寂寞使人愁。座卷流黃簟，簾垂白玉鉤。", "庭閑花自落，門閉水空流。追想吹簫處，應隨仙鶴遊。"]'),
('yuding-15','剡溪館聞笛','丁仙芝','唐','御定全唐诗','yuding','','[]','夜久聞羌笛，寥寥虛客堂。山空響不散，溪靜曲宜長。',48,'御定全唐詩/json/114.json','["夜久聞羌笛，寥寥虛客堂。山空響不散，溪靜曲宜長。", "草木生邊氣，城池泛夕涼。虛然異風出，仿佛宿平陽。"]'),
('yuding-16','越裳貢白雉','丁仙芝','唐','御定全唐诗','yuding','','[]','聖哲承休運，伊夔列上臺。覃恩丹徼遠，入貢素翬來。',72,'御定全唐詩/json/114.json','["聖哲承休運，伊夔列上臺。覃恩丹徼遠，入貢素翬來。", "北闕欣初見，南枝顧未回。斂容殘雪淨，矯翼片雲開。", "馴擾將無懼，翻飛幸不猜。甘從上林裏，飲啄自徘徊。"]'),
('yuding-17','江南曲五首','丁仙芝','唐','御定全唐诗','yuding','','[]','長幹斜路北，近浦是兒家。有意來相訪，明朝出浣紗。',120,'御定全唐詩/json/114.json','["長幹斜路北，近浦是兒家。有意來相訪，明朝出浣紗。", "發向橫塘口，船開值急流。知郎舊時意，且請攏船頭。", "昨暝逗南陵，風聲波浪阻。入浦不逢人，歸家誰信汝。", "未曉已成妝，乘潮去茫茫。因從京口渡，使報邵陵王。", "始下芙蓉樓，言發琅琊岸。急為打船開，惡許傍人見。"]'),
('yuding-18','句','丁仙芝','唐','御定全唐诗','yuding','','[]','窮花常閉戶，秋城聞擣衣。',24,'御定全唐詩/json/114.json','["窮花常閉戶，秋城聞擣衣。", "樹回早秋色，川長遲落暉。"]'),
('yuding-19','石橋琪樹','蔡隱丘','唐','御定全唐诗','yuding','','[]','山上天將近，人間路漸遙。誰當雲裏見，知欲渡仙橋。',24,'御定全唐詩/json/114.json','["山上天將近，人間路漸遙。誰當雲裏見，知欲渡仙橋。"]'),
('yuding-20','句','蔡隱丘','唐','御定全唐诗','yuding','','[]','整巾千嶂聳，曳履百泉鳴。',12,'御定全唐詩/json/114.json','["整巾千嶂聳，曳履百泉鳴。"]'),
('yuding-21','奉和扈從溫泉宮承恩賜浴','蔡希周','唐','御定全唐诗','yuding','','[]','天行雲從指驪宮，浴日餘波錫詔同。彩殿氤氳擁香溜，',40,'御定全唐詩/json/114.json','["天行雲從指驪宮，浴日餘波錫詔同。彩殿氤氳擁香溜，", "自憐遇坎便能止，願托仙槎路未通。"]'),
('yuding-22','同家兄題渭南王公別業','蔡希寂','唐','御定全唐诗','yuding','','[]','好閑知在家，退跡何必深。不出人境外，蕭條江海心。',120,'御定全唐詩/json/114.json','["好閑知在家，退跡何必深。不出人境外，蕭條江海心。", "軒車自來往，空名對清陰。川涘將釣玉，鄉亭期散金。", "素暉射流瀨，翠色綿森林。曾為詩書癖，寧惟耕稼任。", "吾兄許微尚，枉道來相尋。朝慶老萊服，夕閑安道琴。", "文章遙頌美，寤寐增所欽。既鬱蒼生望，明時豈陸沉。"]'),
('yuding-23','登福先寺上方然公禪室','蔡希寂','唐','御定全唐诗','yuding','','[]','名都標佛刹，梵構臨河幹。舉目上方峻，森森青翠攢。',108,'御定全唐詩/json/114.json','["名都標佛刹，梵構臨河幹。舉目上方峻，森森青翠攢。", "步登諸劫盡，忽造浮雲端。當暑敞扃闥，卻嫌絺綌寒。", "禪房最高頂，靜者殊閑安。疏雨向空城，數峰簾外盤。", "午鐘振衣坐，招我同一餐。真味雜飴露，眾香唯茝蘭。", "晚來恣偃俯，茶果仍留歡。"]'),
('yuding-24','陝中作','蔡希寂','唐','御定全唐诗','yuding','','[]','西別秦關近，東行陝服長。川原餘讓畔，歌吹憶遺棠。',48,'御定全唐詩/json/114.json','["西別秦關近，東行陝服長。川原餘讓畔，歌吹憶遺棠。", "河水流城下，山雲起路傍。更憐棲泊處，池館繞林篁。"]'),
('yuding-25','洛陽客舍逢祖詠留宴','蔡希寂','唐','御定全唐诗','yuding','','[]','綿綿鐘漏洛陽城，客舍貧居絕送迎。',32,'御定全唐詩/json/114.json','["綿綿鐘漏洛陽城，客舍貧居絕送迎。", "逢君貰酒因成醉，醉後焉知世上情。"]'),
('yuding-26','贈張敬微','蔡希寂','唐','御定全唐诗','yuding','','[]','大河東北望桃林，雜樹冥冥結翠陰。',32,'御定全唐詩/json/114.json','["大河東北望桃林，雜樹冥冥結翠陰。", "不知君作神仙尉，特訝行來雲霧深。"]'),
('yuding-27','江風行','張潮','唐','御定全唐诗','yuding','','[]','婿貧如珠玉，婿富如埃塵。貧時不忘舊，富日多寵新。',144,'御定全唐詩/json/114.json','["婿貧如珠玉，婿富如埃塵。貧時不忘舊，富日多寵新。", "妾本富家女，與君為偶匹。惠好一何深，中門不曾出。", "妾有繡衣裳，葳蕤金縷光。念君貧且賤，易此從遠方。", "遠方三千里，思君心未已。日暮情更來，空望去時水。", "孟夏麥始秀，江上多南風。商賈歸欲盡，君今尚巴東。", "巴東有巫山，窈窕神女顏。常恐游此方，果然不知還。"]'),
('yuding-28','襄陽行','張潮','唐','御定全唐诗','yuding','','[]','玉盤轉明珠，君心無定準。昨見襄陽客，剩說襄陽好無盡。',92,'御定全唐詩/json/114.json','["玉盤轉明珠，君心無定準。昨見襄陽客，剩說襄陽好無盡。", "襄漢水，峴山垂，漢水東流風北吹。只言一世長嬌寵，", "尚如匣中劍，分形會同處。是君婦，識君情，", "襄陽傳近大堤北，君到襄陽莫回惑。大堤諸女兒，"]'),
('yuding-29','採蓮詞','張潮','唐','御定全唐诗','yuding','','[]','朝出沙頭日正紅，晚來雲起半江中。',32,'御定全唐詩/json/114.json','["朝出沙頭日正紅，晚來雲起半江中。", "賴逢鄰女曾相識，並著蓮舟不畏風。"]'),
('yuding-30','江南行','張潮','唐','御定全唐诗','yuding','','[]','茨菰葉爛別西灣，蓮子花開猶未還。',32,'御定全唐詩/json/114.json','["茨菰葉爛別西灣，蓮子花開猶未還。", "妾夢不離江水上，人傳郎在鳳凰山。"]'),
('yuding-31','長幹行','張潮','唐','御定全唐诗','yuding','','[]','憶昔深閨裏，煙塵不曾識。嫁與長幹人，沙頭候風色。',168,'御定全唐詩/json/114.json','["憶昔深閨裏，煙塵不曾識。嫁與長幹人，沙頭候風色。", "五月南風興，思君下巴陵。八月西風起，想君發揚子。", "去來悲如何，見少離別多。湘潭幾日到，妾夢越風波。", "昨夜狂風度，吹折江頭樹。淼淼暗無邊，行人在何處。", "北客真三公，朱衣滿江中。薄暮來投宿，數朝不肯東。", "好乘浮雲驄，佳期蘭渚東。鴛鴦綠浦上，翡翠錦屏中。", "自憐十五餘，顏色桃花紅。那作商人婦，愁水複愁風。"]'),
('yuding-32','句','張潮','唐','御定全唐诗','yuding','','[]','寒林苞晚橘，風絮露垂楊。',12,'御定全唐詩/json/114.json','["寒林苞晚橘，風絮露垂楊。"]'),
('yuding-33','遊棲霞寺','張翬','唐','御定全唐诗','yuding','','[]','躋險入幽林，翠微含竹殿。泉聲無休歇，山色時隱見。',48,'御定全唐詩/json/114.json','["躋險入幽林，翠微含竹殿。泉聲無休歇，山色時隱見。", "潮來雜風雨，梅落成霜霰。一從方外遊，頓覺塵心變。"]'),
('yuding-34','絕句','張翬','唐','御定全唐诗','yuding','','[]','茫茫煙水上，日暮陰雲飛。孤坐正愁緒，湖南誰擣衣。',24,'御定全唐詩/json/114.json','["茫茫煙水上，日暮陰雲飛。孤坐正愁緒，湖南誰擣衣。"]'),
('yuding-35','潘司馬別業','周瑀','唐','御定全唐诗','yuding','','[]','門對青山近，汀牽綠草長。寒深包晚橘，風緊落垂楊。',48,'御定全唐詩/json/114.json','["門對青山近，汀牽綠草長。寒深包晚橘，風緊落垂楊。", "湖畔聞漁唱，天邊數雁行。蕭然有高士，清思滿書堂。"]'),
('yuding-36','送潘三入京','周瑀','唐','御定全唐诗','yuding','','[]','故人嗟此別，相送出煙坰。柳色分官路，荷香入水亭。',48,'御定全唐詩/json/114.json','["故人嗟此別，相送出煙坰。柳色分官路，荷香入水亭。", "離歌未盡曲，酌酒共忘形。把手河橋上，孤山日暮青。"]'),
('yuding-37','臨川山行','周瑀','唐','御定全唐诗','yuding','','[]','朝見青山雪，暮見青山雲。雲山無斷絕，秋思日紛紛。',24,'御定全唐詩/json/114.json','["朝見青山雪，暮見青山雲。雲山無斷絕，秋思日紛紛。"]'),
('yuding-38','清溪館作','談戭','唐','御定全唐诗','yuding','','[]','指途清溪裏，左右唯深林。雲蔽望鄉處，雨愁為客心。',48,'御定全唐詩/json/114.json','["指途清溪裏，左右唯深林。雲蔽望鄉處，雨愁為客心。", "遇人多物役，聽鳥時幽音。何必滄浪水，庶茲浣塵襟。"]'),
('yuding-39','句','談戭','唐','御定全唐诗','yuding','','[]','清清江潭樹，日夕增所思。',12,'御定全唐詩/json/114.json','["清清江潭樹，日夕增所思。"]'),
('yuding-40','塞上','殷遙','唐','御定全唐诗','yuding','','[]','萬里隤城在，三邊虜氣衰。沙填孤嶂角，燒斷故關碑。',48,'御定全唐詩/json/114.json','["萬里隤城在，三邊虜氣衰。沙填孤嶂角，燒斷故關碑。", "馬色經寒慘，雕聲帶晚悲。將軍正閒暇，留客換歌辭。"]'),
('yuding-41','送友人下第歸省','殷遙','唐','御定全唐诗','yuding','','[]','君此蔔行日，高堂應夢歸。莫將和氏淚，滴著老萊衣。',48,'御定全唐詩/json/114.json','["君此蔔行日，高堂應夢歸。莫將和氏淚，滴著老萊衣。", "岳雨連河細，田禽出麥飛。到家調膳後，吟好送斜暉。"]'),
('yuding-42','送杜士瞻楚州覲省','殷遙','唐','御定全唐诗','yuding','','[]','風流與才思，俱似晉時人。淮月歸心促，江花入興新。',48,'御定全唐詩/json/114.json','["風流與才思，俱似晉時人。淮月歸心促，江花入興新。", "雲深滄海暮，柳暗白門春。共道官猶小，憐君孝養親。"]'),
('yuding-43','友人山亭','殷遙','唐','御定全唐诗','yuding','','[]','故人雖薄宦，往往涉清溪。鑿牖對山月，褰裳拂澗霓。',48,'御定全唐詩/json/114.json','["故人雖薄宦，往往涉清溪。鑿牖對山月，褰裳拂澗霓。", "遊魚逆水上，宿鳥向風棲。一見桃花發，能令秦漢迷。"]'),
('yuding-44','春晚山行','殷遙','唐','御定全唐诗','yuding','','[]','寂曆青山晚，山行趣不稀。野花成子落，江燕引雛飛。',48,'御定全唐詩/json/114.json','["寂曆青山晚，山行趣不稀。野花成子落，江燕引雛飛。", "暗草熏苔徑，晴楊掃石磯。俗人猶語此，餘亦轉忘歸。"]'),
('yuding-45','寄張征古','沈如筠','唐','御定全唐诗','yuding','','[]','寂曆遠山意，微冥半空碧。綠蘿無冬春，彩雲竟朝夕。',48,'御定全唐詩/json/114.json','["寂曆遠山意，微冥半空碧。綠蘿無冬春，彩雲竟朝夕。", "張子海內奇，久為岩中客。聖君當夢想，安得老松石。"]'),
('yuding-46','閨怨二首','沈如筠','唐','御定全唐诗','yuding','','[]','雁盡書難寄，愁多夢不成。願隨孤月影，流照伏波營。',48,'御定全唐詩/json/114.json','["雁盡書難寄，愁多夢不成。願隨孤月影，流照伏波營。", "隴底嗟長別，流襟一動君。何言幽咽所，更作死生分。"]'),
('yuding-47','寄天臺司馬道士','沈如筠','唐','御定全唐诗','yuding','','[]','河洲花豔爚，庭樹光彩蒨。白雲天臺山，可思不可見。',24,'御定全唐詩/json/114.json','["河洲花豔爚，庭樹光彩蒨。白雲天臺山，可思不可見。"]'),
('yuding-48','句','沈如筠','唐','御定全唐诗','yuding','','[]','思酸寒雁斷，淅瀝秋樹空。',24,'御定全唐詩/json/114.json','["思酸寒雁斷，淅瀝秋樹空。", "漁陽燕舊都，美女花不如。"]'),
('yuding-49','詠黃鶯','孫處玄','唐','御定全唐诗','yuding','','[]','欲囀聲猶澀，將飛羽未調。高風不借便，何處得遷喬。',24,'御定全唐詩/json/114.json','["欲囀聲猶澀，將飛羽未調。高風不借便，何處得遷喬。"]'),
('yuding-50','失題','孫處玄','唐','御定全唐诗','yuding','','[]','漢家輕壯士，無狀殺彭王。一遇風塵起，令誰守四方。',24,'御定全唐詩/json/114.json','["漢家輕壯士，無狀殺彭王。一遇風塵起，令誰守四方。"]'),
('yuding-51','句','孫處玄','唐','御定全唐诗','yuding','','[]','殘花與露落，墜葉隨風翻。',24,'御定全唐詩/json/114.json','["殘花與露落，墜葉隨風翻。", "日側南澗幽，風凝北林暮。"]'),
('yuding-52','折楊柳','徐延壽','唐','御定全唐诗','yuding','','[]','大道連國門，東西種楊柳。葳蕤君不見，嫋娜垂來久。',96,'御定全唐詩/json/114.json','["大道連國門，東西種楊柳。葳蕤君不見，嫋娜垂來久。", "緣枝棲暝禽，雄去雌獨吟。餘花怨春盡，微月起秋陰。", "坐望窗中蝶，起攀枝上葉。好風吹長條，婀娜何如妾。", "妾見柳園新，高樓四五春。莫吹胡塞曲，愁殺隴頭人。"]'),
('yuding-53','南州行','徐延壽','唐','御定全唐诗','yuding','','[]','搖艇至南國，國門連大江。中洲西邊岸，數步一垂楊。',72,'御定全唐詩/json/114.json','["搖艇至南國，國門連大江。中洲西邊岸，數步一垂楊。", "金釧越溪女，羅衣胡粉香。織縑春捲幔，采蕨暝提筐。", "弄瑟嬌垂幌，迎人笑下堂。河頭浣衣處，無數紫鴛鴦。"]'),
('yuding-54','人日剪綵','徐延壽','唐','御定全唐诗','yuding','','[]','閨婦持刀坐，自憐裁剪新。葉催情綴色，花寄手成春。',48,'御定全唐詩/json/114.json','["閨婦持刀坐，自憐裁剪新。葉催情綴色，花寄手成春。", "帖燕留妝戶，黏雞待餉人。擎來問夫婿，何處不如真。"]'),
('yuding-55','南中感懷','樊晃','唐','御定全唐诗','yuding','','[]','南路蹉跎客未回，常嗟物候暗相催。',32,'御定全唐詩/json/114.json','["南路蹉跎客未回，常嗟物候暗相催。", "四時不變江頭草，十月先開嶺上梅。"]'),
('yuding-56','句','樊晃','唐','御定全唐诗','yuding','','[]','巧裁蟬鬢畏風吹，盡作蛾眉恐人妒。',16,'御定全唐詩/json/114.json','["巧裁蟬鬢畏風吹，盡作蛾眉恐人妒。"]'),
('yuding-0','和戶部楊員外伯成寓直','李憕','唐','御定全唐诗','yuding','','[]','落日彌綸地，公才畫省郎。詞驚起草筆，坐引護衣香。',48,'御定全唐詩/json/115.json','["落日彌綸地，公才畫省郎。詞驚起草筆，坐引護衣香。", "雙闕天河近，千門夕漏長。遙知臺上宿，不獨有文強。"]'),
('yuding-1','同望幸新亭賜錢公宴','李憕','唐','御定全唐诗','yuding','','[]','感夢通玄化，覃恩降紫宸。賜錢開漢府，分帛醉堯人。',48,'御定全唐詩/json/115.json','["感夢通玄化，覃恩降紫宸。賜錢開漢府，分帛醉堯人。", "地隔朝宗慶，亭臨蔔洛新。行看廣雲雨，二月次東巡。"]'),
('yuding-2','奉和聖制從蓬萊向興慶閣道中留春雨中春望之作應制','李憕','唐','御定全唐诗','yuding','','[]','別館春還淑氣催，三宮路轉鳳凰台。雲飛北闕輕陰散，',40,'御定全唐詩/json/115.json','["別館春還淑氣催，三宮路轉鳳凰台。雲飛北闕輕陰散，", "已知聖澤深無限，更喜年芳入睿才。"]'),
('yuding-3','銅雀妓','李邕','唐','御定全唐诗','yuding','','[]','西陵望何及，弦管徒在茲。誰言死者樂，但令生者悲。',96,'御定全唐詩/json/115.json','["西陵望何及，弦管徒在茲。誰言死者樂，但令生者悲。", "丈夫有餘志，兒女焉足私。擾擾多俗情，投跡互相師。", "直節豈感激，荒淫乃淒其。潁水有許由，西山有伯夷。", "頌聲何寥寥，唯聞銅雀詩。君舉良未易，永為後代嗤。"]'),
('yuding-4','詠雲','李邕','唐','御定全唐诗','yuding','','[]','彩雲驚歲晚，繚繞孤山頭。散作五般色，凝為一段愁。',48,'御定全唐詩/json/115.json','["彩雲驚歲晚，繚繞孤山頭。散作五般色，凝為一段愁。", "影雖沉澗底，形在天際遊。風動必飛去，不應長此留。"]'),
('yuding-5','登曆下古城員外孫新亭','李邕','唐','御定全唐诗','yuding','','[]','吾宗固神秀，體物寫謀長。形制開古跡，曾冰延樂方。',72,'御定全唐詩/json/115.json','["吾宗固神秀，體物寫謀長。形制開古跡，曾冰延樂方。", "太山雄地理，巨壑眇雲莊。高興汩煩促，永懷清典常。", "含弘知四大，出入見三光。負郭喜粳稻，安時歌吉祥。"]'),
('yuding-6','奉和初春幸太平公主南莊應制','李邕','唐','御定全唐诗','yuding','','[]','傳聞銀漢支機石，複見金輿出紫微。織女橋邊烏鵲起，',40,'御定全唐詩/json/115.json','["傳聞銀漢支機石，複見金輿出紫微。織女橋邊烏鵲起，", "今日還同犯牛鬥，乘槎共逐海潮歸。"]'),
('yuding-7','奉使登終南山','王灣','唐','御定全唐诗','yuding','','[]','常愛南山遊，因而盡原隰。數朝至林嶺，百仞登嵬岌。',204,'御定全唐詩/json/115.json','["常愛南山遊，因而盡原隰。數朝至林嶺，百仞登嵬岌。", "石壯馬徑窮，苔色步緣入。物奇春狀改，氣遠天香集。", "虛洞策杖鳴，低雲拂衣濕。倚岩見廬舍，入戶欣拜揖。", "問性矜勤勞，示心教澄習。玉英時共飯，芝草為餘拾。", "境絕人不行，潭深鳥空立。一乘從此授，九轉兼是給。", "辭處若輕飛，憩來唯吐吸。閑襟超已勝，回路倏而及。", "煙色松上深，水流山下急。漸平逢車騎，向晚睨城邑。", "峰在野趣繁，塵飄宦情澀。辛苦久為吏，勞生何妄執。", "日暮懷此山，悠然賦斯什。"]'),
('yuding-8','晚夏馬嵬卿叔池亭即事寄京都一二知己','王灣','唐','御定全唐诗','yuding','','[]','忝職畿甸淹，濫陪時俊後。才輕策疲劣，勢薄常驅走。',132,'御定全唐詩/json/115.json','["忝職畿甸淹，濫陪時俊後。才輕策疲劣，勢薄常驅走。", "牽役勞風塵，秉心在岩藪。宗賢開別業，形勝代希偶。", "竹繞清渭濱，泉流白渠口。逡巡期賞會，揮忽變星斗。", "逮此乘務閑，因而訪幽叟。入來殊景物，行複洗紛垢。", "林靜秋色多，潭深月光厚。盛香蓮近拆，新味瓜初剖。", "滯拙懷隱淪，書之寄良友。"]'),
('yuding-9','麗正殿賜宴同勒天前煙年四韻應制','王灣','唐','御定全唐诗','yuding','','[]','金殿忝陪賢，瓊羞忽降天。鼎羅仙掖裏，觴拜瑣闈前。',48,'御定全唐詩/json/115.json','["金殿忝陪賢，瓊羞忽降天。鼎羅仙掖裏，觴拜瑣闈前。", "院逼青霄路，廚和紫禁煙。酒酣空忭舞，何以答昌年。"]'),
('yuding-10','奉和賀監林月清酌','王灣','唐','御定全唐诗','yuding','','[]','華月當秋滿，朝英假興同。淨林新霽入，規院小涼通。',48,'御定全唐詩/json/115.json','["華月當秋滿，朝英假興同。淨林新霽入，規院小涼通。", "碎影行筵裏，搖花落酒中。消宵凝爽意，並此助文雄。"]'),
('yuding-11','次北固山下','王灣','唐','御定全唐诗','yuding','','[]','客路青山外，行舟綠水前。潮平兩岸闊，風正一帆懸。',48,'御定全唐詩/json/115.json','["客路青山外，行舟綠水前。潮平兩岸闊，風正一帆懸。", "海日生殘夜，江春入舊年。鄉書何處達，歸雁洛陽邊。"]'),
('yuding-12','觀搊箏','王灣','唐','御定全唐诗','yuding','','[]','虛室有秦箏，箏新月複清。弦多弄委曲，柱促語分明。',48,'御定全唐詩/json/115.json','["虛室有秦箏，箏新月複清。弦多弄委曲，柱促語分明。", "曉怨凝繁手，春嬌入曼聲。近來唯此樂，傳得美人情。"]'),
('yuding-13','晚春詣蘇州敬贈武員外','王灣','唐','御定全唐诗','yuding','','[]','蘇台憶季常，飛棹曆江鄉。持此功曹掾，初離華省郎。',180,'御定全唐詩/json/115.json','["蘇台憶季常，飛棹曆江鄉。持此功曹掾，初離華省郎。", "貴門生禮樂，明代秉文章。嘉郡位先進，鴻儒名重揚。", "爰從姻婭貶，豈失忠信防。萬里行驥足，十年暌鳳翔。", "回遷翊元聖，入拜佇惟良。別業對南浦，群書滿北堂。", "意深投轄盛，才重接筵光。陋學叨鉛簡，弱齡許翰場。", "神馳勞舊國，顏展別殊方。際曉雜氛散，殘春眾物芳。", "煙和疏樹滿，雨續小溪長。旅拙感成慰，通賢顧不忘。", "從來琴曲罷，開匣為君張。"]'),
('yuding-14','秋夜寓直即事懷贈蕭令公裴侍郎兼通簡南省諸友人','王灣','唐','御定全唐诗','yuding','','[]','聖主萬年興，賢臣數載升。古靈傳嶽秀，宏量稟川澄。',312,'御定全唐詩/json/115.json','["聖主萬年興，賢臣數載升。古靈傳嶽秀，宏量稟川澄。", "畿甸舉長策，風霜秉直繩。出車遙俗震，登閣滿朝稱。", "賦簡流亡輯，農安政理憑。還家新長幼，巡壟舊溝塍。", "忠梗大勳立，寰瀛墮業懲。焚香兼禦史，懸鏡委中丞。", "旟隼當朝立，台驄發郡乘。司徒漢家重，國典潁川征。", "雲路俄平入，臺階忽上淩。秉鈞調造化，宣綍慰黎烝。", "金省方秋作，瑤軒直夜憑。中書贈陳准，右相簡王陵。", "三傑賢更穆，百僚歡且兢。搖懷及賓友，計曲辨淄澠。", "閶闔暝陰散，鉤陳爽氣凝。月深宮樹轉，河近禁樓冰。", "卑吏夙驅策，微涓效鬥升。望麾宵繼火，書板曙懷蒸。", "彼此雖流盼，規模轉服膺。惠將霄漢隔，勞或歲時矜。", "位重恩寧濫，才輕懾不勝。林巒甘獨往，疵賤苦相仍。", "敢忘銜花雀，思同附驥蠅。平生逐鳥雀，何日嗣蒼鷹。"]'),
('yuding-15','哭補闕亡友綦毋學士','王灣','唐','御定全唐诗','yuding','','[]','明代資多士，儒林得異才。書從金殿出，人向玉墀來。',216,'御定全唐詩/json/115.json','["明代資多士，儒林得異才。書從金殿出，人向玉墀來。", "詞學張平子，風儀褚彥回。崇儀希上德，近侍接元台。", "曩契心期早，今遊宴賞陪。屢遷君擢桂，分尉我從梅。", "忽遇乘軺客，雲傾構廈材。泣為洹水化，歎作泰山頹。", "冀善初將慰，尋言半始猜。位聯情易感，交密痛難裁。", "遠日寒旌暗，長風古挽哀。寰中無舊業，行處有新苔。", "反哭魂猶寄，終喪子尚孩。葬田門吏給，墳木路人栽。", "遽泄悲成往，俄傳寵令回。玄經貽石室，朱紱耀泉台。", "地古春長閉，天明夜不開。登山一臨哭，揮淚滿蒿萊。"]'),
('yuding-16','閏月七日織女','王灣','唐','御定全唐诗','yuding','','[]','耿耿曙河微，神仙此夜稀。今年七月閏，應得兩回歸。',24,'御定全唐詩/json/115.json','["耿耿曙河微，神仙此夜稀。今年七月閏，應得兩回歸。"]'),
('yuding-17','句','王灣','唐','御定全唐诗','yuding','','[]','月華照杵空隨妾，風響傳砧不到君。',16,'御定全唐詩/json/115.json','["月華照杵空隨妾，風響傳砧不到君。"]'),
('yuding-18','應詔賦得除夜','史青','唐','御定全唐诗','yuding','','[]','今歲今宵盡，明年明日催。寒隨一夜去，春逐五更來。',48,'御定全唐詩/json/115.json','["今歲今宵盡，明年明日催。寒隨一夜去，春逐五更來。", "氣色空中改，容顏暗裏回。風光人不覺，已著後園梅。"]'),
('yuding-19','汴堤柳','王泠然','唐','御定全唐诗','yuding','','[]','隋家天子憶揚州，厭坐深宮傍海遊。穿地鑿山開禦路，',88,'御定全唐詩/json/115.json','["隋家天子憶揚州，厭坐深宮傍海遊。穿地鑿山開禦路，", "功成力盡人旋亡，代謝年移樹空有。當時彩女侍君王，", "今日摧殘何用道，數裏曾無一枝好。驛騎征帆損更多，", "河畔時時聞木落，客中無不淚沾裳。"]'),
('yuding-20','夜光篇','王泠然','唐','御定全唐诗','yuding','','[]','遊人夜到汝陽間，夜色冥蒙不解顏。誰家暗起寒山燒，',96,'御定全唐詩/json/115.json','["遊人夜到汝陽間，夜色冥蒙不解顏。誰家暗起寒山燒，", "焦聲散著群樹鳴，炎氣傍林一川暖。是時西北多海風，", "初謂煉丹仙灶裏，還疑鑄劍神溪中。劃為飛電來照物，", "沸湯空谷數道水，融蓋陰崖幾年雪。兩京貧病若為居，"]'),
('yuding-21','古木臥平沙','王泠然','唐','御定全唐诗','yuding','','[]','古木臥平沙，摧殘歲月賒。有根橫水石，無葉拂煙霞。',48,'御定全唐詩/json/115.json','["古木臥平沙，摧殘歲月賒。有根橫水石，無葉拂煙霞。", "春至苔為葉，冬來雪作花。不逢星漢使，誰辨是靈槎。"]'),
('yuding-22','淮南寄舍弟','王泠然','唐','御定全唐诗','yuding','','[]','昔予從不調，經歲旅淮源。念爾長相失，何時返故園。',72,'御定全唐詩/json/115.json','["昔予從不調，經歲旅淮源。念爾長相失，何時返故園。", "寄書迷處所，分袂隔涼溫。遠道俱為客，他鄉共在原。", "歸情春伴雁，愁泣夜隨猿。愧見高堂上，朝朝獨倚門。"]'),
('yuding-23','句','王泠然','唐','御定全唐诗','yuding','','[]','林狖欺童子，山精試老僧。',40,'御定全唐詩/json/115.json','["林狖欺童子，山精試老僧。", "陳兵劍閣山將動，飲馬珠江水不流。", "官微思倚玉，文淺怯投珠。"]'),
('yuding-0','春江花月夜二首','張子容','唐','御定全唐诗','yuding','','[]','林花發岸口，氣色動江新。此夜江中月，流光花上春。',72,'御定全唐詩/json/116.json','["林花發岸口，氣色動江新。此夜江中月，流光花上春。", "分明石潭裏，宜照浣紗人。", "交甫憐瑤佩，仙妃難重期。沉沉綠江晚，惆悵碧雲姿。", "初逢花上月，言是弄珠時。"]'),
('yuding-1','雲陽驛陪崔使君邵道士夜宴','張子容','唐','御定全唐诗','yuding','','[]','一尉東南遠，誰知此夜歡。諸侯傾皂蓋，仙客整黃冠。',48,'御定全唐詩/json/116.json','["一尉東南遠，誰知此夜歡。諸侯傾皂蓋，仙客整黃冠。", "染翰燈花滿，飛觴雲氣寒。欣承國士遇，更借美人看。"]'),
('yuding-2','除夜樂城逢孟浩然','張子容','唐','御定全唐诗','yuding','','[]','遠客襄陽郡，來過海岸家。樽開柏葉酒，燈發九枝花。',48,'御定全唐詩/json/116.json','["遠客襄陽郡，來過海岸家。樽開柏葉酒，燈發九枝花。", "妙曲逢盧女，高才得孟嘉。東山行樂意，非是競繁華。"]'),
('yuding-3','送蘇倩游天臺','張子容','唐','御定全唐诗','yuding','','[]','靈異尋滄海，笙歌訪翠微。江鷗迎共狎，雲鶴待將飛。',48,'御定全唐詩/json/116.json','["靈異尋滄海，笙歌訪翠微。江鷗迎共狎，雲鶴待將飛。", "琪樹嘗仙果，瓊樓試羽衣。遙知神女問，獨怪阮郎歸。"]'),
('yuding-4','泛永嘉江日暮回舟','張子容','唐','御定全唐诗','yuding','','[]','無雲天欲暮，輕鷁大江清。歸路煙中遠，回舟月上行。',48,'御定全唐詩/json/116.json','["無雲天欲暮，輕鷁大江清。歸路煙中遠，回舟月上行。", "傍潭窺竹暗，出嶼見沙明。更值微風起，乘流絲管聲。"]'),
('yuding-5','永嘉即事寄贛縣袁少府瓘','張子容','唐','御定全唐诗','yuding','','[]','山繞樓臺出，溪通裏閈斜。曾為謝客郡，多有逐臣家。',48,'御定全唐詩/json/116.json','["山繞樓臺出，溪通裏閈斜。曾為謝客郡，多有逐臣家。", "海氣朝成雨，江天晚作霞。題書報賈誼，此濕似長沙。"]'),
('yuding-6','樂城歲日贈孟浩然','張子容','唐','御定全唐诗','yuding','','[]','土地窮甌越，風光肇建寅。插桃銷瘴癘，移竹近階墀。',48,'御定全唐詩/json/116.json','["土地窮甌越，風光肇建寅。插桃銷瘴癘，移竹近階墀。", "半是吳風俗，仍為楚歲時。更逢習鑿齒，言在漢川湄。"]'),
('yuding-7','永嘉作','張子容','唐','御定全唐诗','yuding','','[]','拙宦從江左，投荒更海邊。山將孤嶼近，水共惡溪連。',48,'御定全唐詩/json/116.json','["拙宦從江左，投荒更海邊。山將孤嶼近，水共惡溪連。", "地濕梅多雨，潭蒸竹起煙。未應悲晚發，炎瘴苦華年。"]'),
('yuding-8','送孟八浩然歸襄陽二首','張子容','唐','御定全唐诗','yuding','','[]','東越相逢地，西亭送別津。風潮看解纜，雲海去愁人。',96,'御定全唐詩/json/116.json','["東越相逢地，西亭送別津。風潮看解纜，雲海去愁人。", "鄉在桃林岸，山連楓樹春。因懷故園意，歸與孟家鄰。", "杜門不欲出，久與世情疏。以此為長策，勸君歸舊廬。", "醉歌田舍酒，笑讀古人書。好是一生事，無勞獻子虛。"]'),
('yuding-9','貶樂城尉日作','張子容','唐','御定全唐诗','yuding','','[]','竄謫邊窮海，川原近惡溪。有時聞虎嘯，無夜不猿啼。',48,'御定全唐詩/json/116.json','["竄謫邊窮海，川原近惡溪。有時聞虎嘯，無夜不猿啼。", "地暖花長髮，岩高日易低。故鄉可憶處，遙指鬥牛西。"]'),
('yuding-10','自樂城赴永嘉枉路泛白湖寄松陽李少府','張子容','唐','御定全唐诗','yuding','','[]','西行礙淺石，北轉入溪橋。樹色煙輕重，湖光風動搖。',60,'御定全唐詩/json/116.json','["西行礙淺石，北轉入溪橋。樹色煙輕重，湖光風動搖。", "百花亂飛雪，萬嶺疊青霄。猿掛臨潭筱，鷗迎出浦橈。", "惟應賞心客，茲路不言遙。"]'),
('yuding-11','九日陪潤州邵使君登北固山','張子容','唐','御定全唐诗','yuding','','[]','五馬向西椒，重陽坐麗譙。徐州帶綠水，楚國在青霄。',72,'御定全唐詩/json/116.json','["五馬向西椒，重陽坐麗譙。徐州帶綠水，楚國在青霄。", "張幕連江樹，開筵接海潮。淩雲詞客語，回雪舞人嬌。", "梅福慚仙吏，羊公賞下僚。新豐酒舊美，況是菊花朝。"]'),
('yuding-12','璧池望秋月','張子容','唐','御定全唐诗','yuding','','[]','涼夜窺清沼，池空水月秋。滿輪沉玉鏡，半魄落銀鉤。',72,'御定全唐詩/json/116.json','["涼夜窺清沼，池空水月秋。滿輪沉玉鏡，半魄落銀鉤。", "蟾影搖輕浪，菱花渡淺流。漏移光漸潔，雲斂色偏浮。", "似璧悲三獻，疑珠怯再投。能持千里意，來照楚鄉愁。"]'),
('yuding-13','長安早春','張子容','唐','御定全唐诗','yuding','','[]','開國維東井，城池起北辰。咸歌太平日，共樂建寅春。',72,'御定全唐詩/json/116.json','["開國維東井，城池起北辰。咸歌太平日，共樂建寅春。", "雪盡黃山樹，冰開黑水津。草迎金埒馬，花伴玉樓人。", "鴻漸看無數，鶯歌聽欲頻。何當桂枝擢，還及柳條新。"]'),
('yuding-14','贈司勳蕭郎中','張子容','唐','御定全唐诗','yuding','','[]','作相開黃閣，為郎奏赤墀。君臣道合體，父子貴同時。',144,'御定全唐詩/json/116.json','["作相開黃閣，為郎奏赤墀。君臣道合體，父子貴同時。", "國以推賢答，家無內舉疑。鳳池真水鏡，蘭省得華滋。", "未睹風流日，先聞新賦詩。江山清謝脁，花木媚丘遲。", "吏部來何暮，王言念在茲。丹青無不可，霖雨亦相期。", "昔我投荒處，孤煙望島夷。群鷗終日狎，落葉數年悲。", "漁父留歌詠，江妃入興詞。今將獻知己，相感勿吾欺。"]'),
('yuding-15','巫山','張子容','唐','御定全唐诗','yuding','','[]','巫嶺岧嶢天際重，佳期宿昔願相從。',32,'御定全唐詩/json/116.json','["巫嶺岧嶢天際重，佳期宿昔願相從。", "朝雲暮雨連天暗，神女知來第幾峰。"]'),
('yuding-16','除日','張子容','唐','御定全唐诗','yuding','','[]','臘月今知晦，流年此夕除。拾樵供歲火，帖牖作春書。',48,'御定全唐詩/json/116.json','["臘月今知晦，流年此夕除。拾樵供歲火，帖牖作春書。", "柳覺東風至，花疑小雪餘。忽逢雙鯉贈，言是上冰魚。"]'),
('yuding-0','清溪泛舟','張旭','唐','御定全唐诗','yuding','','[]','旅人倚征棹，薄暮起勞歌。笑攬清溪月，清輝不厭多。',24,'御定全唐詩/json/117.json','["旅人倚征棹，薄暮起勞歌。笑攬清溪月，清輝不厭多。"]'),
('yuding-1','桃花溪','張旭','唐','御定全唐诗','yuding','','[]','隱隱飛橋隔野煙，石磯西畔問漁船。',32,'御定全唐詩/json/117.json','["隱隱飛橋隔野煙，石磯西畔問漁船。", "桃花盡日隨流水，洞在清溪何處邊。"]'),
('yuding-2','山行留客','張旭','唐','御定全唐诗','yuding','','[]','山光物態弄春輝，莫為輕陰便擬歸。',32,'御定全唐詩/json/117.json','["山光物態弄春輝，莫為輕陰便擬歸。", "縱使晴明無雨色，入雲深處亦沾衣。"]'),
('yuding-3','春遊值雨','張旭','唐','御定全唐诗','yuding','','[]','欲尋軒檻列清尊，江上煙雲向晚昏。',32,'御定全唐詩/json/117.json','["欲尋軒檻列清尊，江上煙雲向晚昏。", "須倩東風吹散雨，明朝卻待入華園。"]'),
('yuding-4','春草','張旭','唐','御定全唐诗','yuding','','[]','春草青青萬里餘，邊城落日見離居。',32,'御定全唐詩/json/117.json','["春草青青萬里餘，邊城落日見離居。", "情知海上三年別，不寄雲間一紙書。"]'),
('yuding-5','柳','張旭','唐','御定全唐诗','yuding','','[]','濯濯煙條拂地垂，城邊樓畔結春思。',32,'御定全唐詩/json/117.json','["濯濯煙條拂地垂，城邊樓畔結春思。", "請君細看風流意，未減靈和殿裏時。"]'),
('yuding-6','南山','賀朝','唐','御定全唐诗','yuding','','[]','湖北雨初晴，湖南山盡見。岩岩石帆影，如得海風便。',48,'御定全唐詩/json/117.json','["湖北雨初晴，湖南山盡見。岩岩石帆影，如得海風便。", "仙穴茅山峰，彩雲時一見。邀君共探此，異籙殘幾卷。"]'),
('yuding-7','孤興','賀朝','唐','御定全唐诗','yuding','','[]','晴日暖珠箔，夭桃色正新。紅粉青鏡中，娟娟可憐嚬。',72,'御定全唐詩/json/117.json','["晴日暖珠箔，夭桃色正新。紅粉青鏡中，娟娟可憐嚬。", "君子在遐險，蕙心誰見珍。羅幕空掩晝，玉顏靜移春。", "江瑟語幽獨，再三情未申。黃鵠千里翅，芳音遲所因。"]'),
('yuding-8','從軍行','賀朝','唐','御定全唐诗','yuding','','[]','朔胡乘月寇邊城，軍書插羽刺中京。天子金壇拜飛將，',120,'御定全唐詩/json/117.json','["朔胡乘月寇邊城，軍書插羽刺中京。天子金壇拜飛將，", "聞有河湟客，愔愔理帷帟。常山啟霸圖，汜水先天策，", "邊樹蕭蕭不覺春，天山漠漠長飛雪。魚麗陣接塞雲平，", "自從一戍燕支山，春光幾度晉陽關。金河未轉青絲騎，", "已見氛清細柳營，莫更春歌落梅曲。烽沉灶減靜邊亭，"]'),
('yuding-9','賦得遊人久不歸','賀朝','唐','御定全唐诗','yuding','','[]','鄉關眇天末，引領悵懷歸。羈旅久淫滯，物色屢芳菲。',48,'御定全唐詩/json/117.json','["鄉關眇天末，引領悵懷歸。羈旅久淫滯，物色屢芳菲。", "稍覺出意盡，行看蓬鬢稀。如何千裏外，佇立沾裳衣。"]'),
('yuding-10','宿香山閣','賀朝','唐','御定全唐诗','yuding','','[]','暝上春山閣，梯雲宿半空。軒窗閉潮海，枕席拂煙虹。',48,'御定全唐詩/json/117.json','["暝上春山閣，梯雲宿半空。軒窗閉潮海，枕席拂煙虹。", "朱網防棲鴿，紗燈護夕蟲。一聞雞唱曉，已見日曈曈。"]'),
('yuding-11','贈酒店胡姬','賀朝','唐','御定全唐诗','yuding','','[]','胡姬春酒店，弦管夜鏘鏘。紅l1鋪新月，貂裘坐薄霜。',49,'御定全唐詩/json/117.json','["胡姬春酒店，弦管夜鏘鏘。紅l1鋪新月，貂裘坐薄霜。", "玉盤初鱠鯉，金鼎正烹羊。上客無勞散，聽歌樂世娘。"]'),
('yuding-12','賦得春鶯送友人二首','賀朝','唐','御定全唐诗','yuding','','[]','翅掩飛鶯舞，啼惱婕妤悲。料取金閨意，因君問所思。',48,'御定全唐詩/json/117.json','["翅掩飛鶯舞，啼惱婕妤悲。料取金閨意，因君問所思。", "流鶯拂繡羽，二月上林期。待雪銷金禁，銜花向玉墀。"]'),
('yuding-13','三日綠潭篇','萬齊融','唐','御定全唐诗','yuding','','[]','春潭滉漾接隋宮，宮闕連延潭水東。蘋苔嫩色涵波綠，',88,'御定全唐詩/json/117.json','["春潭滉漾接隋宮，宮闕連延潭水東。蘋苔嫩色涵波綠，", "素影沉沉對蝶飛，金沙礫礫窺魚泳。佳人祓禊賞韶年，", "公子王孫恣遊玩，沙陽水曲情無厭。禽浮似挹羽觴杯，", "綠水殘霞催席散，畫樓初月待人歸。"]'),
('yuding-14','仗劍行','萬齊融','唐','御定全唐诗','yuding','','[]','昨夜星官動紫微，今年天子用武威。登車一呼風雷動，',48,'御定全唐詩/json/117.json','["昨夜星官動紫微，今年天子用武威。登車一呼風雷動，", "願騎單馬仗天威，挼取長繩縛虜歸。仗劍遙叱路傍子，"]'),
('yuding-15','贈別江頭','萬齊融','唐','御定全唐诗','yuding','','[]','東南飛鳥處，言是故鄉天。江上風花晚，君行定幾千。',48,'御定全唐詩/json/117.json','["東南飛鳥處，言是故鄉天。江上風花晚，君行定幾千。", "計程頻破月，數別屢開年。明歲潯陽水，相思寄採蓮。"]'),
('yuding-16','送陳七還廣陵','萬齊融','唐','御定全唐诗','yuding','','[]','風流誰代子，雖有舊無雙。歡酒言相送，愁弦意不降。',48,'御定全唐詩/json/117.json','["風流誰代子，雖有舊無雙。歡酒言相送，愁弦意不降。", "落花馥河道，垂楊拂水窗。海潮與春夢，朝夕廣陵江。"]'),
('yuding-17','游春','邢巨','唐','御定全唐诗','yuding','','[]','海岳三峰古，春皇二月寒。綠潭漁子釣，紅樹美人攀。',48,'御定全唐詩/json/117.json','["海岳三峰古，春皇二月寒。綠潭漁子釣，紅樹美人攀。", "弱蔓環沙嶼，飛花點石關。溪山遊未厭，琴酌弄晴灣。"]'),
('yuding-18','游宣州琴溪同武平一作','邢巨','唐','御定全唐诗','yuding','','[]','靈溪非人跡，仙意素所秉。鱗嶺森翠微，澄潭照秋景。',24,'御定全唐詩/json/117.json','["靈溪非人跡，仙意素所秉。鱗嶺森翠微，澄潭照秋景。"]'),
('yuding-19','春江花月夜','張若虛','唐','御定全唐诗','yuding','','[]','春江潮水連海平，海上明月共潮生。灩灩隨波千萬里，',288,'御定全唐詩/json/117.json','["春江潮水連海平，海上明月共潮生。灩灩隨波千萬里，", "何處春江無月明。江流宛轉繞芳甸，月照花林皆似霰。", "空裏流霜不覺飛，汀上白沙看不見。江天一色無纖塵，", "皎皎空中孤月輪。江畔何人初見月，江月何年初照人。", "人生代代無窮已，江月年年只相似。不知江月待何人，", "但見長江送流水。白雲一片去悠悠，青楓浦上不勝愁。", "誰家今夜扁舟子，何處相思明月樓。可憐樓上月裴回，", "應照離人妝鏡臺。玉戶簾中卷不去，搗衣砧上拂還來。", "此時相望不相聞，願逐月華流照君。鴻雁長飛光不度，", "魚龍潛躍水成文。昨夜閑潭夢落花，可憐春半不還家。", "江水流春去欲盡，江潭落月複西斜。斜月沉沉藏海霧，", "碣石瀟湘無限路。不知乘月幾人歸，落月搖情滿江樹。"]'),
('yuding-20','代答閨夢還','張若虛','唐','御定全唐诗','yuding','','[]','關塞年華早，樓臺別望違。試衫著暖氣，開鏡覓春暉。',72,'御定全唐詩/json/117.json','["關塞年華早，樓臺別望違。試衫著暖氣，開鏡覓春暉。", "燕入窺羅幕，蜂來上畫衣。情催桃李豔，心寄管弦飛。", "妝洗朝相待，風花暝不歸。夢魂何處入，寂寂掩重扉。"]'),
('yuding-21','洪州客舍寄柳博士芳','薛業','唐','御定全唐诗','yuding','','[]','去年燕巢主人屋，今年花發路傍枝。年年為客不到舍，',24,'御定全唐詩/json/117.json','["去年燕巢主人屋，今年花發路傍枝。年年為客不到舍，"]'),
('yuding-22','晚秋贈張折沖此公事制舉','薛業','唐','御定全唐诗','yuding','','[]','都尉今無事，時清但閉關。夜霜戎馬瘦，秋草射堂閑。',48,'御定全唐詩/json/117.json','["都尉今無事，時清但閉關。夜霜戎馬瘦，秋草射堂閑。", "位以穿楊得，名因折桂還。馮唐真不遇，歎息鬢毛斑。"]'),
('yuding-0','和左司張員外自洛使入京中路先赴長安逢立春日贈韋侍御等諸公','孫逖','唐','御定全唐诗','yuding','','[]','拜郎登省闥，奉使馳車乘。遙瞻使者星，便是郎官應。',72,'御定全唐詩/json/118.json','["拜郎登省闥，奉使馳車乘。遙瞻使者星，便是郎官應。", "台妙時相許，皇華德彌稱。二陝聽風謠，三秦望形勝。", "此中暌益友，是日多詩興。寒盡歲陰催，春歸物華證。"]'),
('yuding-1','和登會稽山','孫逖','唐','御定全唐诗','yuding','','[]','稽山碧湖上，勢入東溟盡。煙景晝清明，九峰爭隱嶙。',120,'御定全唐詩/json/118.json','["稽山碧湖上，勢入東溟盡。煙景晝清明，九峰爭隱嶙。", "望中厭朱紱，俗內探玄牝。野老聽鳴騶，山童擁行軫。", "仙花寒未落，古蔓柔堪引。竹澗入山多，松崖向天近。", "雲從海天去，日就江村隕。能賦丘嘗聞，和歌參不敏。", "冥搜信沖漠，多士期標準。願奉濯纓心，長謠反招隱。"]'),
('yuding-2','送楊法曹按括州','孫逖','唐','御定全唐诗','yuding','','[]','東海天臺山，南方縉雲驛。溪澄問人隱，岩險煩登陟。',48,'御定全唐詩/json/118.json','["東海天臺山，南方縉雲驛。溪澄問人隱，岩險煩登陟。", "潭壑隨星使，軒車繞春色。儻尋琪樹人，為報長相憶。"]'),
('yuding-3','葛山潭','孫逖','唐','御定全唐诗','yuding','','[]','圓潭寫流月，晴明涵萬象。仙翁何時還，綠水空蕩漾。',48,'御定全唐詩/json/118.json','["圓潭寫流月，晴明涵萬象。仙翁何時還，綠水空蕩漾。", "涼哉草木腓，白露沾人衣。猶醉空山裏，時聞笙鶴飛。"]'),
('yuding-4','丹陽行','孫逖','唐','御定全唐诗','yuding','','[]','丹陽古郡洞庭陰，落日扁舟此路尋。傳是東南舊都處，',140,'御定全唐詩/json/118.json','["丹陽古郡洞庭陰，落日扁舟此路尋。傳是東南舊都處，", "雙闕戎虜間，千門戰場裏。傳聞一馬化為龍，", "青楓林下回天蹕，杜若洲前轉國容。都門不見河陽樹，", "英雄傾奪何紛然，一盛一衰如逝川。可憐宮觀重江裏，", "昔年王氣今何在，並向長安就堯日。荊榛古木閉荒阡，", "暮來山水登臨遍，覽古愁吟淚如霰。唯有空城多白雲，"]'),
('yuding-5','山陰縣西樓','孫逖','唐','御定全唐诗','yuding','','[]','都邑西樓芳樹間，逶迤霽色繞江山。山月夜從公署出，',40,'御定全唐詩/json/118.json','["都邑西樓芳樹間，逶迤霽色繞江山。山月夜從公署出，", "一見湖邊楊柳風，遙憶青青洛陽道。"]'),
('yuding-6','夜宿浙江','孫逖','唐','御定全唐诗','yuding','','[]','扁舟夜入江潭泊，露白風高氣蕭索。富春渚上潮未還，',40,'御定全唐詩/json/118.json','["扁舟夜入江潭泊，露白風高氣蕭索。富春渚上潮未還，", "洛陽城闕何時見，西北浮雲朝暝深。"]'),
('yuding-7','春日留別','孫逖','唐','御定全唐诗','yuding','','[]','春路逶迤花柳前，孤舟晚泊就人煙。東山白雲不可見，',40,'御定全唐詩/json/118.json','["春路逶迤花柳前，孤舟晚泊就人煙。東山白雲不可見，", "越國山川看漸無，可憐愁思江南樹。"]'),
('yuding-8','奉和四月三日上陽水窗賜宴應制得春字','孫逖','唐','御定全唐诗','yuding','','[]','今日逢初夏，歡游續舊旬。氣和先作雨，恩厚別成春。',48,'御定全唐詩/json/118.json','["今日逢初夏，歡游續舊旬。氣和先作雨，恩厚別成春。", "鳳吹臨清洛，龍輿下紫宸。此中歌在藻，還見躍潛鱗。"]'),
('yuding-9','奉和登會昌山應制','孫逖','唐','御定全唐诗','yuding','','[]','岩磴列雲旗，吾君訪道時。幹行萬物睹，日馭六龍遲。',48,'御定全唐詩/json/118.json','["岩磴列雲旗，吾君訪道時。幹行萬物睹，日馭六龍遲。", "望遠回天顧，登高動睿詞。願因山作壽，長保會昌期。"]'),
('yuding-10','正月十五日夜應制','孫逖','唐','御定全唐诗','yuding','','[]','洛城三五夜，天子萬年春。彩仗移雙闕，瓊筵會九賓。',48,'御定全唐詩/json/118.json','["洛城三五夜，天子萬年春。彩仗移雙闕，瓊筵會九賓。", "舞成蒼頡字，燈作法王輪。不覺東方日，遙垂禦藻新。"]'),
('yuding-11','奉和禦制登鴛鴦樓即目應制','孫逖','唐','御定全唐诗','yuding','','[]','玉輦下離宮，瓊樓上半空。方巡五年狩，更辟四門聰。',48,'御定全唐詩/json/118.json','["玉輦下離宮，瓊樓上半空。方巡五年狩，更辟四門聰。", "井邑觀秦野，山河念禹功。停鑾留睿作，軒檻起南風。"]'),
('yuding-12','進船泛洛水應制','孫逖','唐','御定全唐诗','yuding','','[]','禁園紆睿覽，仙棹葉時遊。洛北風花樹，江南彩畫舟。',48,'御定全唐詩/json/118.json','["禁園紆睿覽，仙棹葉時遊。洛北風花樹，江南彩畫舟。", "芳生蘭蕙草，春入鳳凰樓。興盡離宮暮，煙光起夕流。"]'),
('yuding-13','和常州崔使君寒食夜','孫逖','唐','御定全唐诗','yuding','','[]','聞道清明近，春庭向夕闌。行遊晝不厭，風物夜宜看。',48,'御定全唐詩/json/118.json','["聞道清明近，春庭向夕闌。行遊晝不厭，風物夜宜看。", "斗柄更初轉，梅香暗裏殘。無勞秉華燭，清月在南端。"]'),
('yuding-14','和韋兄春日南亭宴兄弟','孫逖','唐','御定全唐诗','yuding','','[]','台閣升高位，園林隔舊鄉。忽聞歌棣萼，還比報瓊芳。',48,'御定全唐詩/json/118.json','["台閣升高位，園林隔舊鄉。忽聞歌棣萼，還比報瓊芳。", "門向宜春近，郊連禦宿長。德星常有會，相望在文昌。"]'),
('yuding-15','奉和崔司馬遊雲門寺','孫逖','唐','御定全唐诗','yuding','','[]','系馬清溪樹，禪門春氣濃。香台花下出，講坐竹間逢。',48,'御定全唐詩/json/118.json','["系馬清溪樹，禪門春氣濃。香台花下出，講坐竹間逢。", "覺路山童引，經行穀鳥從。更言窮寂滅，回策上南峰。"]'),
('yuding-16','酬萬八賀九雲門下歸溪中作','孫逖','唐','御定全唐诗','yuding','','[]','晚從靈境出，林壑曙雲飛。稍覺清溪盡，回瞻畫刹微。',48,'御定全唐詩/json/118.json','["晚從靈境出，林壑曙雲飛。稍覺清溪盡，回瞻畫刹微。", "獨園餘興在，孤棹宿心違。更憶登攀處，天香滿袖歸。"]'),
('yuding-17','春初送呂補闕往西嶽勒碑得雲字','孫逖','唐','御定全唐诗','yuding','','[]','刻石記天文，朝推穀子雲。篋中緘聖劄，岩下揖神君。',48,'御定全唐詩/json/118.json','["刻石記天文，朝推穀子雲。篋中緘聖劄，岩下揖神君。", "語別梅初豔，為期草欲熏。往來春不盡，離思莫氛氳。"]'),
('yuding-18','送越州裴參軍充使入京','孫逖','唐','御定全唐诗','yuding','','[]','日落川徑寒，離心苦未安。客愁西向盡，鄉夢北歸難。',48,'御定全唐詩/json/118.json','["日落川徑寒，離心苦未安。客愁西向盡，鄉夢北歸難。", "霜果林中變，秋花水上殘。明朝渡江後，雲物向南看。"]'),
('yuding-19','送周判官往台州','孫逖','唐','御定全唐诗','yuding','','[]','吾宗長作賦，登陸訪天臺。星使行看入，雲仙意轉催。',48,'御定全唐詩/json/118.json','["吾宗長作賦，登陸訪天臺。星使行看入，雲仙意轉催。", "飲冰攀璀璨，驅傳曆莓苔。日暮東郊別，真情去不回。"]'),
('yuding-20','送魏騎曹充宇文侍禦判官分按山南','孫逖','唐','御定全唐诗','yuding','','[]','雲雨陽臺路，光華驛騎巡。勸農開夢土，恤隱惠荊人。',48,'御定全唐詩/json/118.json','["雲雨陽臺路，光華驛騎巡。勸農開夢土，恤隱惠荊人。", "樓迥吟黃鶴，江長望白蘋。觀風布明詔，更是漢南春。"]'),
('yuding-21','送蘇郎中綰出佐荊州','孫逖','唐','御定全唐诗','yuding','','[]','神仙久留滯，清切佇飛翻。忽佐南方牧，何時西掖垣。',48,'御定全唐詩/json/118.json','["神仙久留滯，清切佇飛翻。忽佐南方牧，何時西掖垣。", "高車自蘭省，便道出荊門。不見河梁別，空銷郢路魂。"]'),
('yuding-22','冬末送魏起居赴京','孫逖','唐','御定全唐诗','yuding','','[]','大名將起魏，良史更逢遷。驛騎朝丹闕，關亭望紫煙。',48,'御定全唐詩/json/118.json','["大名將起魏，良史更逢遷。驛騎朝丹闕，關亭望紫煙。", "西京春色近，東觀物華偏。早赴王正月，揮毫記首年。"]'),
('yuding-23','送李補闕攝禦史充河西節度判官','孫逖','唐','御定全唐诗','yuding','','[]','昔年叨補袞，邊地亦埋輪。官序慚先達，才名畏後人。',48,'御定全唐詩/json/118.json','["昔年叨補袞，邊地亦埋輪。官序慚先達，才名畏後人。", "西戎雖獻款，上策恥和親。早赴前軍幕，長清外域塵。"]'),
('yuding-24','送趙評事攝禦史監軍嶺南','孫逖','唐','御定全唐诗','yuding','','[]','議獄持邦典，臨戎假憲威。風從閶闔去，霜入洞庭飛。',48,'御定全唐詩/json/118.json','["議獄持邦典，臨戎假憲威。風從閶闔去，霜入洞庭飛。", "篁竹迎金鼓，樓船引繡衣。明年拜真月，南斗使星歸。"]'),
('yuding-25','送靳十五侍禦使蜀','孫逖','唐','御定全唐诗','yuding','','[]','天使出霜台，行人擇吏才。傳車春色送，離興夕陽催。',48,'御定全唐詩/json/118.json','["天使出霜台，行人擇吏才。傳車春色送，離興夕陽催。", "驛繞巴江轉，關迎劍道開。西南一何幸，前後二龍來。"]'),
('yuding-26','送李給事歸徐州覲省','孫逖','唐','御定全唐诗','yuding','','[]','列位登青瑣，還鄉複彩衣。共言晨省日，便是晝遊歸。',48,'御定全唐詩/json/118.json','["列位登青瑣，還鄉複彩衣。共言晨省日，便是晝遊歸。", "春水經梁宋，晴山入海沂。莫愁東路遠，四牡正騑騑。"]'),
('yuding-27','送杜侍禦赴上都','孫逖','唐','御定全唐诗','yuding','','[]','避馬台中貴，登車嶺外遙。還因貢賦禮，來謁大明朝。',48,'御定全唐詩/json/118.json','["避馬台中貴，登車嶺外遙。還因貢賦禮，來謁大明朝。", "地入商山路，鄉連渭水橋。承恩返南越，尊酒重相邀。"]'),
('yuding-28','送張環攝禦史監南選','孫逖','唐','御定全唐诗','yuding','','[]','漢使得張綱，威名攝遠方。恩沾柱下史，榮比選曹郎。',48,'御定全唐詩/json/118.json','["漢使得張綱，威名攝遠方。恩沾柱下史，榮比選曹郎。", "江帶黔中闊，山連峽水長。莫愁炎暑地，秋至有嚴霜。"]'),
('yuding-29','宴越府陳法曹西亭','孫逖','唐','御定全唐诗','yuding','','[]','公府西岩下，紅亭間白雲。雪梅初度臘，煙竹稍迎曛。',48,'御定全唐詩/json/118.json','["公府西岩下，紅亭間白雲。雪梅初度臘，煙竹稍迎曛。", "水木涵澄景，簾櫳引霽氛。江南歸思逼，春雁不堪聞。"]'),
('yuding-30','同邢判官尋龍湍觀歸湖中','孫逖','唐','御定全唐诗','yuding','','[]','星使下仙京，雲湖喜晝晴。更從探穴處，還作棹歌行。',48,'御定全唐詩/json/118.json','["星使下仙京，雲湖喜晝晴。更從探穴處，還作棹歌行。", "絲管荷風入，簾帷竹氣清。莫愁歸路遠，水月夜虛明。"]'),
('yuding-31','尋龍湍','孫逖','唐','御定全唐诗','yuding','','[]','仙穴尋遺跡，輕舟愛水鄉。溪流一曲盡，山路九峰長。',48,'御定全唐詩/json/118.json','["仙穴尋遺跡，輕舟愛水鄉。溪流一曲盡，山路九峰長。", "漁父歌金洞，江妃舞翠房。遙憐葛仙宅，真氣共微茫。"]'),
('yuding-32','宿雲門寺閣','孫逖','唐','御定全唐诗','yuding','','[]','香閣東山下，煙花象外幽。懸燈千嶂夕，卷幔五湖秋。',48,'御定全唐詩/json/118.json','["香閣東山下，煙花象外幽。懸燈千嶂夕，卷幔五湖秋。", "畫壁餘鴻雁，紗窗宿鬥牛。更疑天路近，夢與白雲遊。"]'),
('yuding-33','揚子江樓','孫逖','唐','御定全唐诗','yuding','','[]','揚子何年邑，雄圖作楚關。江連二妃渚，雲近八公山。',48,'御定全唐詩/json/118.json','["揚子何年邑，雄圖作楚關。江連二妃渚，雲近八公山。", "驛道青楓外，人煙綠嶼間。晚來潮正滿，數處落帆還。"]'),
('yuding-34','淮陰夜宿二首','孫逖','唐','御定全唐诗','yuding','','[]','水國南無畔，扁舟北未期。鄉情淮上失，歸夢郢中疑。',96,'御定全唐詩/json/118.json','["水國南無畔，扁舟北未期。鄉情淮上失，歸夢郢中疑。", "木落知寒近，山長見日遲。客行心緒亂，不及洛陽時。", "永夕臥煙塘，蕭條天一方。秋風淮水落，寒夜楚歌長。", "宿莽非中土，鱸魚豈我鄉。孤舟行已倦，南越尚茫茫。"]'),
('yuding-35','下京口埭夜行','孫逖','唐','御定全唐诗','yuding','','[]','孤帆度綠氛，寒浦落紅曛。江樹朝來出，吳歌夜漸聞。',48,'御定全唐詩/json/118.json','["孤帆度綠氛，寒浦落紅曛。江樹朝來出，吳歌夜漸聞。", "南溟接潮水，北斗近鄉雲。行役從茲去，歸情入雁群。"]'),
('yuding-36','山行遇雨','孫逖','唐','御定全唐诗','yuding','','[]','驟雨晝氤氳，空天望不分。暗山唯覺電，窮海但生雲。',48,'御定全唐詩/json/118.json','["驟雨晝氤氳，空天望不分。暗山唯覺電，窮海但生雲。", "涉澗猜行潦，緣崖畏宿氛。夜來江月霽，棹唱此中聞。"]'),
('yuding-37','夜到潤州','孫逖','唐','御定全唐诗','yuding','','[]','夜入丹陽郡，天高氣象秋。海隅雲漢轉，江畔火星流。',48,'御定全唐詩/json/118.json','["夜入丹陽郡，天高氣象秋。海隅雲漢轉，江畔火星流。", "城郭傳金柝，閭閻閉綠洲。客行凡幾夜，新月再如鉤。"]'),
('yuding-38','和常州崔使君詠後庭梅二首','孫逖','唐','御定全唐诗','yuding','','[]','聞唱梅花落，江南春意深。更傳千裏外，來入越人吟。',96,'御定全唐詩/json/118.json','["聞唱梅花落，江南春意深。更傳千裏外，來入越人吟。", "弱幹紅妝倚，繁香翠羽尋。庭中自公日，歌舞向芳陰。", "梅院重門掩，遙遙歌吹邊。庭深人不見，春至曲能傳。", "花落彈棋處，香來薦枕前。使君停五馬，行樂此中偏。"]'),
('yuding-39','同和詠樓前海石榴二首','孫逖','唐','御定全唐诗','yuding','','[]','客自新亭郡，朝來數物華。傳君妓樓好，初落海榴花。',96,'御定全唐詩/json/118.json','["客自新亭郡，朝來數物華。傳君妓樓好，初落海榴花。", "露色珠簾映，香風粉壁遮。更宜林下雨，日晚逐行車。", "海上移珍木，樓前詠所思。遙聞下車日，正在落花時。", "舊綠香行蓋，新紅灑步綦。從來寒不易，終見久逾滋。"]'),
('yuding-40','故右丞相贈太師燕文貞公挽詞二首','孫逖','唐','御定全唐诗','yuding','','[]','海內文章伯，朝端禮樂英。一言興寶運，三入濟群生。',96,'御定全唐詩/json/118.json','["海內文章伯，朝端禮樂英。一言興寶運，三入濟群生。", "命與才相偶，年將位不並。台星忽已坼，流慟軫皇情。", "甲第三重戟，高門四列侯。已成冠蓋裏，更有鳳凰樓。", "人世方為樂，生涯遽若休。空餘掌綸地，傳慶百千秋。"]'),
('yuding-41','故陳州刺史贈兵部尚書韋公挽詞','孫逖','唐','御定全唐诗','yuding','','[]','奕葉金章貴，連枝鼎位尊。台庭為鳳穴，相府是鴒原。',48,'御定全唐詩/json/118.json','["奕葉金章貴，連枝鼎位尊。台庭為鳳穴，相府是鴒原。", "世閱空悲命，泉幽不返魂。惟餘漢臣史，繼術贊韋門。"]'),
('yuding-42','故程將軍妻南陽郡夫人樊氏挽歌','孫逖','唐','御定全唐诗','yuding','','[]','德配程休甫，名高魯季薑。寵榮蒼玉佩，宴夢郁金堂。',48,'御定全唐詩/json/118.json','["德配程休甫，名高魯季薑。寵榮蒼玉佩，宴夢郁金堂。", "白日期偕老，幽泉忽悼亡。國風猶在詠，江漢近南陽。"]'),
('yuding-43','和上巳連寒食有懷京洛','孫逖','唐','御定全唐诗','yuding','','[]','天津禦柳碧遙遙，軒騎相從半下朝。行樂光輝寒食借，',40,'御定全唐詩/json/118.json','["天津禦柳碧遙遙，軒騎相從半下朝。行樂光輝寒食借，", "坐見司空掃西第，看君侍從落花朝。"]'),
('yuding-44','和左司張員外自洛使入京中路先赴長安逢立春日贈韋侍御等諸公','孫逖','唐','御定全唐诗','yuding','','[]','忽睹雲間數雁回，更逢山上正花開。河邊淑氣迎芳草，',40,'御定全唐詩/json/118.json','["忽睹雲間數雁回，更逢山上正花開。河邊淑氣迎芳草，", "共言東閣招賢地，自有西征謝傅才。"]'),
('yuding-45','和崔司馬登稱心山寺','孫逖','唐','御定全唐诗','yuding','','[]','郡府乘休日，王城訪道初。覺花迎步履，香草藉行車。',120,'御定全唐詩/json/118.json','["郡府乘休日，王城訪道初。覺花迎步履，香草藉行車。", "倚閣觀無際，尋山坐太虛。岩空迷禹跡，海靜望秦餘。", "翡翠巢珠網，鶤雞間綺疏。地靈資淨土，水若護真如。", "寶樹誰攀折，禪雲自卷舒。晴分五湖勢，煙合九夷居。", "生滅紛無象，窺臨已得魚。嘗聞寶刀贈，今日奉瓊琚。"]'),
('yuding-46','奉和李右相中書壁畫山水','孫逖','唐','御定全唐诗','yuding','','[]','廟堂多暇日，山水契中情。欲寫高深趣，還因藻繪成。',96,'御定全唐詩/json/118.json','["廟堂多暇日，山水契中情。欲寫高深趣，還因藻繪成。", "九江臨戶牖，三峽繞簷楹。花柳窮年發，煙雲逐意生。", "能令萬里近，不覺四時行。氣染荀香馥，光含樂鏡清。", "詠歌齊出處，圖畫表沖盈。自保千年遇，何論八載榮。"]'),
('yuding-47','奉和李右相賞會昌林亭','孫逖','唐','御定全唐诗','yuding','','[]','賢相初陪蹕，靈山本降神。作京雄近縣，開閣寵平津。',72,'御定全唐詩/json/118.json','["賢相初陪蹕，靈山本降神。作京雄近縣，開閣寵平津。", "地勝林亭好，時清宴賞頻。百泉縈草木，萬井布郊畛。", "德與春和盛，功將造化鄰。還嗤渭濱叟，歲晚獨垂綸。"]'),
('yuding-48','和左衛武倉曹衛中對雨創韻贈右衛李騎曹','孫逖','唐','御定全唐诗','yuding','','[]','林父同官意，宣尼久敬交。文場刊玉篆，武事掌金鐃。',120,'御定全唐詩/json/118.json','["林父同官意，宣尼久敬交。文場刊玉篆，武事掌金鐃。", "道合宜連茹，時清豈系匏。克勤居簿領，多暇屏讙譊。", "美酒懷公宴，玄談俟客嘲。薄雲生北闕，飛雨自西郊。", "院暑便清曠，庭蕪覺漸苞。高門關詎閉，逸韻柱難膠。", "枳棘鸞無歎，椅梧鳳必巢。忽聞征並作，觀海愧堂坳。"]'),
('yuding-49','送新羅法師還國','孫逖','唐','御定全唐诗','yuding','','[]','異域今無外，高僧代所稀。苦心歸寂滅，宴坐得精微。',72,'御定全唐詩/json/118.json','["異域今無外，高僧代所稀。苦心歸寂滅，宴坐得精微。", "持缽何年至，傳燈是日歸。上卿揮別藻，中禁下禪衣。", "海闊杯還度，雲遙錫更飛。此行迷處所，何以慰虔祈。"]'),
('yuding-50','送趙大夫護邊','孫逖','唐','御定全唐诗','yuding','','[]','外域分都護，中台命職方。欲傳清廟略，先取劇曹郎。',96,'御定全唐詩/json/118.json','["外域分都護，中台命職方。欲傳清廟略，先取劇曹郎。", "已佩登壇印，猶懷伏奏香。百壺開祖餞，駟牡戒戎裝。", "青海連西掖，黃河帶北涼。關山瞻漢月，戈劍宿胡霜。", "體國才先著，論兵策複長。果持文武術，還繼杜當陽。"]'),
('yuding-51','立秋日題安昌寺北山亭','孫逖','唐','御定全唐诗','yuding','','[]','樓觀倚長霄，登攀及霽朝。高如石門頂，勝擬赤城標。',96,'御定全唐詩/json/118.json','["樓觀倚長霄，登攀及霽朝。高如石門頂，勝擬赤城標。", "天路雲虹近，人寰氣象遙。山圍伯禹廟，江落伍胥潮。", "徂暑迎秋薄，涼風是日飄。果林餘苦李，萍水覆甘蕉。", "覽古嗟夷漫，淩空愛泬寥。更聞金刹下，鐘梵晚蕭蕭。"]'),
('yuding-52','登越州城','孫逖','唐','御定全唐诗','yuding','','[]','越嶂繞層城，登臨萬象清。封圻滄海合，廛市碧湖明。',72,'御定全唐詩/json/118.json','["越嶂繞層城，登臨萬象清。封圻滄海合，廛市碧湖明。", "曉日漁歌滿，芳春棹唱行。山風吹美箭，田雨潤香粳。", "代閱英靈盡，人閑吏隱並。贈言王逸少，已見曲池平。"]'),
('yuding-53','江行有懷','孫逖','唐','御定全唐诗','yuding','','[]','秋水明川路，輕舟轉石圻。霜多山橘熟，寒至浦禽稀。',72,'御定全唐詩/json/118.json','["秋水明川路，輕舟轉石圻。霜多山橘熟，寒至浦禽稀。", "飛席乘風勢，回流蕩日暉。晝行疑海若，夕夢識江妃。", "野霽看吳盡，天長望洛非。不知何歲月，一似暮潮歸。"]'),
('yuding-54','長洲苑','孫逖','唐','御定全唐诗','yuding','','[]','吳王初鼎峙，羽獵騁雄才。輦道閶門出，軍容茂苑來。',120,'御定全唐詩/json/118.json','["吳王初鼎峙，羽獵騁雄才。輦道閶門出，軍容茂苑來。", "山從列嶂轉，江自繞林回。劍騎緣汀入，旌門隔嶼開。", "合離紛若電，馳逐溢成雷。勝地虞人守，歸舟漢女陪。", "可憐夷漫處，猶在洞庭隈。山靜吟猿父，城空應雉媒。", "戎行委喬木，馬跡盡黃埃。攬涕問遺老，繁華安在哉。"]'),
('yuding-55','和詠廨署有櫻桃','孫逖','唐','御定全唐诗','yuding','','[]','上林天禁裏，芳樹有紅櫻。江國今來見，君門春意生。',72,'御定全唐詩/json/118.json','["上林天禁裏，芳樹有紅櫻。江國今來見，君門春意生。", "香從花綬轉，色繞佩珠明。海鳥銜初實，吳姬掃落英。", "切將稀取貴，羞與眾同榮。為此堪攀折，芳蹊處處成。"]'),
('yuding-56','同洛陽李少府觀永樂公主入蕃','孫逖','唐','御定全唐诗','yuding','','[]','邊地鶯花少，年來未覺新。美人天上落，龍塞始應春。',24,'御定全唐詩/json/118.json','["邊地鶯花少，年來未覺新。美人天上落，龍塞始應春。"]'),
('yuding-57','途中口號','孫逖','唐','御定全唐诗','yuding','','[]','鄴城東北望陵台，珠翠繁華去不回。',32,'御定全唐詩/json/118.json','["鄴城東北望陵台，珠翠繁華去不回。", "無複新妝豔紅粉，空餘故壟滿青苔。"]'),
('yuding-58','晦日湖塘','孫逖','唐','御定全唐诗','yuding','','[]','吉日初成晦，方塘遍是春。落花迎二月，芳樹曆三旬。',48,'御定全唐詩/json/118.json','["吉日初成晦，方塘遍是春。落花迎二月，芳樹曆三旬。", "公子能留客，巫陽好解神。夜還何慮暗，秉燭向城闉。"]'),
('yuding-59','句','孫逖','唐','御定全唐诗','yuding','','[]','野煙出爐上，山花落鏡中。',12,'御定全唐詩/json/118.json','["野煙出爐上，山花落鏡中。"]'),
('yuding-0','從軍行','崔國輔','唐','御定全唐诗','yuding','','[]','塞北胡霜下，營州索兵救。夜裏偷道行，將軍馬亦瘦。',48,'御定全唐詩/json/119.json','["塞北胡霜下，營州索兵救。夜裏偷道行，將軍馬亦瘦。", "刀光照塞月，陣色明如晝。傳聞賊滿山，已共前鋒鬥。"]'),
('yuding-1','雜詩','崔國輔','唐','御定全唐诗','yuding','','[]','逢著平樂兒，論交鞍馬前。與酤一鬥酒，恰用十千錢。',48,'御定全唐詩/json/119.json','["逢著平樂兒，論交鞍馬前。與酤一鬥酒，恰用十千錢。", "後餘在關內，作事多迍邅。何肯相救援，徒聞寶劍篇。"]'),
('yuding-2','古意','崔國輔','唐','御定全唐诗','yuding','','[]','紅荷楚水曲，彪炳爍晨霞。未得兩回摘，秋風吹卻花。',48,'御定全唐詩/json/119.json','["紅荷楚水曲，彪炳爍晨霞。未得兩回摘，秋風吹卻花。", "時芳不待妾，玉佩無處誇。悔不盛年時，嫁與青樓家。"]'),
('yuding-3','宿法華寺','崔國輔','唐','御定全唐诗','yuding','','[]','松雨時複滴，寺門清且涼。此心竟誰證，回憩支公床。',48,'御定全唐詩/json/119.json','["松雨時複滴，寺門清且涼。此心竟誰證，回憩支公床。", "壁畫感靈跡，龕經傳異香。獨遊寄象外，忽忽歸南昌。"]'),
('yuding-4','題預章館','崔國輔','唐','御定全唐诗','yuding','','[]','楊柳映春江，江南轉佳麗。吳門綠波里，越國青山際。',84,'御定全唐詩/json/119.json','["楊柳映春江，江南轉佳麗。吳門綠波里，越國青山際。", "游宦常往來，津亭暫臨憩。驛前蒼石沒，浦外湖沙細。", "向晚宴且久，孤舟冏然逝。雲留西北客，氣歇東南帝。", "獨有萋萋心，誰知怨芳歲。"]'),
('yuding-5','石頭灘作','崔國輔','唐','御定全唐诗','yuding','','[]','悵矣秋風時，餘臨石頭瀨。因高見遠境，盡此數州內。',108,'御定全唐詩/json/119.json','["悵矣秋風時，餘臨石頭瀨。因高見遠境，盡此數州內。", "羽山數點青，海岸雜光碎。離離樹木少，漭漭湖波大。", "日暮千里帆，南飛落天外。須臾遂入夜，楚色有微靄。", "尋遠跡已窮，遺榮事多昧。一身猶未理，安得濟時代。", "且泛朝夕潮，荷衣蕙為帶。"]'),
('yuding-6','漂母岸','崔國輔','唐','御定全唐诗','yuding','','[]','泗水入淮處，南邊古岸存。秦時有漂母，于此飯王孫。',120,'御定全唐詩/json/119.json','["泗水入淮處，南邊古岸存。秦時有漂母，于此飯王孫。", "王孫初未遇，寄食何足論。後為楚王來，黃金答母恩。", "事蹟遺在此，空傷千載魂。茫茫水中渚，上有一孤墩。", "遙望不可到，蒼蒼煙樹昏。幾年崩塚色，每日落潮痕。", "古地多堙圮，時哉不敢言。向夕淚沾裳，遂宿蘆洲村。"]'),
('yuding-7','對酒吟','崔國輔','唐','御定全唐诗','yuding','','[]','行行日將夕，荒村古塚無人跡。蒙籠荊棘一鳥吟，',38,'御定全唐詩/json/119.json','["行行日將夕，荒村古塚無人跡。蒙籠荊棘一鳥吟，", "寄言世上諸少年，平生且盡杯中醁。"]'),
('yuding-8','奉和華清宮觀行香應制','崔國輔','唐','御定全唐诗','yuding','','[]','天子蕊珠宮，樓臺碧落通。豫遊皆汗漫，齋處即崆峒。',48,'御定全唐詩/json/119.json','["天子蕊珠宮，樓臺碧落通。豫遊皆汗漫，齋處即崆峒。", "雲物三光裏，君臣一氣中。道言何所說，寶曆自無窮。"]'),
('yuding-9','七夕','崔國輔','唐','御定全唐诗','yuding','','[]','太守仙潢族，含情七夕多。扇風生玉漏，置水寫銀河。',48,'御定全唐詩/json/119.json','["太守仙潢族，含情七夕多。扇風生玉漏，置水寫銀河。", "閣下陳書籍，閨中曝綺羅。遙思漢武帝，青鳥幾時過。"]'),
('yuding-10','宿范浦','崔國輔','唐','御定全唐诗','yuding','','[]','月暗潮又落，西陵渡暫停。村煙和海霧，舟火亂江星。',48,'御定全唐詩/json/119.json','["月暗潮又落，西陵渡暫停。村煙和海霧，舟火亂江星。", "路轉定山繞，塘連範浦橫。鴟夷近何去，空山臨滄溟。"]'),
('yuding-11','奉和聖制上巳祓禊應制','崔國輔','唐','御定全唐诗','yuding','','[]','元巳秦中節，吾君灞上游。鳴鑾通禁苑，別館繞芳洲。',72,'御定全唐詩/json/119.json','["元巳秦中節，吾君灞上游。鳴鑾通禁苑，別館繞芳洲。", "鵷鷺千官列，魚龍百戲浮。桃花春欲盡，穀雨夜來收。", "慶向堯樽祝，歡從楚棹謳。逸詩何足對，窅作掩東周。"]'),
('yuding-12','九日侍宴應制','崔國輔','唐','御定全唐诗','yuding','','[]','運偶千年聖，時傳九日神。堯樽列鐘鼓，漢闕辟鉤陳。',72,'御定全唐詩/json/119.json','["運偶千年聖，時傳九日神。堯樽列鐘鼓，漢闕辟鉤陳。", "金籙三清降，瓊筵五老巡。始驚蘭佩出，複詠柏梁新。", "雲雁樓前晚，霜花酒裏春。歡娛無限極，書劍太平人。"]'),
('yuding-13','杭州北郭戴氏荷池送侯愉','崔國輔','唐','御定全唐诗','yuding','','[]','秋近萬物肅，況當臨水時。折花贈歸客，離緒斷荷絲。',72,'御定全唐詩/json/119.json','["秋近萬物肅，況當臨水時。折花贈歸客，離緒斷荷絲。", "誰謂江國永，故人感在茲。道存過北郭，情極望東菑。", "喬木故園意，鳴蟬窮巷悲。扁舟竟何待，中路每遲遲。"]'),
('yuding-14','怨詞二首','崔國輔','唐','御定全唐诗','yuding','','[]','妾有羅衣裳，秦王在時作。為舞春風多，秋來不堪著。',48,'御定全唐詩/json/119.json','["妾有羅衣裳，秦王在時作。為舞春風多，秋來不堪著。", "樓頭桃李疏，池上芙蓉落。織錦猶未成，蛩聲入羅幕。"]'),
('yuding-15','古意二首','崔國輔','唐','御定全唐诗','yuding','','[]','玉籠熏繡裳，著罷眠洞房。不能春風裏，吹卻蘭麝香。',48,'御定全唐詩/json/119.json','["玉籠熏繡裳，著罷眠洞房。不能春風裏，吹卻蘭麝香。", "種棘遮蘼蕪，畏人來采殺。比至狂夫還，看看幾花發。"]'),
('yuding-16','襄陽曲二首','崔國輔','唐','御定全唐诗','yuding','','[]','蕙草嬌紅萼，時光舞碧雞。城中美年少，相見白銅鞮。',48,'御定全唐詩/json/119.json','["蕙草嬌紅萼，時光舞碧雞。城中美年少，相見白銅鞮。", "少年襄陽地，來往襄陽城。城中輕薄子，知妾解秦箏。"]'),
('yuding-17','魏宮詞','崔國輔','唐','御定全唐诗','yuding','','[]','朝日照紅妝，擬上銅雀台。畫眉猶未了，魏帝使人催。',24,'御定全唐詩/json/119.json','["朝日照紅妝，擬上銅雀台。畫眉猶未了，魏帝使人催。"]'),
('yuding-18','長信草','崔國輔','唐','御定全唐诗','yuding','','[]','長信宮中草，年年愁處生。故侵珠履跡，不使玉階行。',24,'御定全唐詩/json/119.json','["長信宮中草，年年愁處生。故侵珠履跡，不使玉階行。"]'),
('yuding-19','長樂少年行','崔國輔','唐','御定全唐诗','yuding','','[]','遺卻珊瑚鞭，白馬驕不行。章台折楊柳，春日路傍情。',24,'御定全唐詩/json/119.json','["遺卻珊瑚鞭，白馬驕不行。章台折楊柳，春日路傍情。"]'),
('yuding-20','湖南曲','崔國輔','唐','御定全唐诗','yuding','','[]','湖南送君去，湖北送君歸。湖裏鴛鴦鳥，雙雙他自飛。',24,'御定全唐詩/json/119.json','["湖南送君去，湖北送君歸。湖裏鴛鴦鳥，雙雙他自飛。"]'),
('yuding-21','中流曲','崔國輔','唐','御定全唐诗','yuding','','[]','歸時日尚早，更欲向芳洲。渡口水流急，回船不自由。',24,'御定全唐詩/json/119.json','["歸時日尚早，更欲向芳洲。渡口水流急，回船不自由。"]'),
('yuding-22','王孫游','崔國輔','唐','御定全唐诗','yuding','','[]','自與王孫別，頻看黃鳥飛。應由春草誤，著處不成歸。',24,'御定全唐詩/json/119.json','["自與王孫別，頻看黃鳥飛。應由春草誤，著處不成歸。"]'),
('yuding-23','採蓮曲','崔國輔','唐','御定全唐诗','yuding','','[]','玉漵花爭發，金塘水亂流。相逢畏相失，並著採蓮舟。',24,'御定全唐詩/json/119.json','["玉漵花爭發，金塘水亂流。相逢畏相失，並著採蓮舟。"]'),
('yuding-24','子夜冬歌','崔國輔','唐','御定全唐诗','yuding','','[]','寂寥抱冬心，裁羅又褧褧。夜久頻挑燈，霜寒剪刀冷。',24,'御定全唐詩/json/119.json','["寂寥抱冬心，裁羅又褧褧。夜久頻挑燈，霜寒剪刀冷。"]'),
('yuding-25','麗人曲','崔國輔','唐','御定全唐诗','yuding','','[]','紅顏稱絕代，欲並真無侶。獨有鏡中人，由來自相許。',24,'御定全唐詩/json/119.json','["紅顏稱絕代，欲並真無侶。獨有鏡中人，由來自相許。"]'),
('yuding-26','小長幹曲','崔國輔','唐','御定全唐诗','yuding','','[]','月暗送潮風，相尋路不通。菱歌唱不徹，知在此塘中。',24,'御定全唐詩/json/119.json','["月暗送潮風，相尋路不通。菱歌唱不徹，知在此塘中。"]'),
('yuding-27','王昭君','崔國輔','唐','御定全唐诗','yuding','','[]','漢使南還盡，胡中妾獨存。紫台綿望絕，秋草不堪論。',24,'御定全唐詩/json/119.json','["漢使南還盡，胡中妾獨存。紫台綿望絕，秋草不堪論。"]'),
('yuding-28','秦女卷衣','崔國輔','唐','御定全唐诗','yuding','','[]','雖入秦帝宮，不上秦帝床。夜夜玉窗裏，與他卷衣裳。',24,'御定全唐詩/json/119.json','["雖入秦帝宮，不上秦帝床。夜夜玉窗裏，與他卷衣裳。"]'),
('yuding-29','今別離','崔國輔','唐','御定全唐诗','yuding','','[]','送別未能旋，相望連水口。船行欲映洲，幾度急搖手。',24,'御定全唐詩/json/119.json','["送別未能旋，相望連水口。船行欲映洲，幾度急搖手。"]'),
('yuding-30','衛豔詞','崔國輔','唐','御定全唐诗','yuding','','[]','淇上桑葉青，青樓含白日。比時遙望君，車馬城中出。',24,'御定全唐詩/json/119.json','["淇上桑葉青，青樓含白日。比時遙望君，車馬城中出。"]'),
('yuding-31','渭水西別李侖','崔國輔','唐','御定全唐诗','yuding','','[]','隴右長亭堠，山陰古塞秋。不知嗚咽水，何事向西流。',24,'御定全唐詩/json/119.json','["隴右長亭堠，山陰古塞秋。不知嗚咽水，何事向西流。"]'),
('yuding-32','古意','崔國輔','唐','御定全唐诗','yuding','','[]','淨掃黃金階，飛霜皎如雪。下簾彈箜篌，不忍見秋月。',24,'御定全唐詩/json/119.json','["淨掃黃金階，飛霜皎如雪。下簾彈箜篌，不忍見秋月。"]'),
('yuding-33','送韓十四被魯王推遞往濟南府','崔國輔','唐','御定全唐诗','yuding','','[]','西候情何極，南冠怨有餘。梁王雖好事，不察獄中書。',24,'御定全唐詩/json/119.json','["西候情何極，南冠怨有餘。梁王雖好事，不察獄中書。"]'),
('yuding-34','《白紵辭二首','崔國輔','唐','御定全唐诗','yuding','','[]','洛陽梨花落如霰，河陽桃葉生複齊。',64,'御定全唐詩/json/119.json','["洛陽梨花落如霰，河陽桃葉生複齊。", "坐惜玉樓春欲盡，紅綿粉絮裛妝啼。", "董賢女弟在椒風，窈窕繁華貴後宮。", "璧帶金釭皆翡翠，一朝零落變成空。"]'),
('yuding-35','九日','崔國輔','唐','御定全唐诗','yuding','','[]','江邊楓落菊花黃，少長登高一望鄉。',32,'御定全唐詩/json/119.json','["江邊楓落菊花黃，少長登高一望鄉。", "九日陶家雖載酒，三年楚客已沾裳。"]'),
('yuding-36','王昭君','崔國輔','唐','御定全唐诗','yuding','','[]','一回望月一回悲，望月月移人不移。',32,'御定全唐詩/json/119.json','["一回望月一回悲，望月月移人不移。", "何時得見漢朝使，為妾傳書斬畫師。"]'),
('yuding-0','孤寢怨','崔珪','唐','御定全唐诗','yuding','','[]','征戍動經年，含情拂玳筵。花飛織錦處，月落擣衣邊。',48,'御定全唐詩/json/120.json','["征戍動經年，含情拂玳筵。花飛織錦處，月落擣衣邊。", "燈暗愁孤坐，床空怨獨眠。自君遼海去，玉匣閉春弦。"]'),
('yuding-1','題武陵草堂','楊浚','唐','御定全唐诗','yuding','','[]','草堂列仙樓，上在青山頂。戶外窺數峰，階前對雙井。',96,'御定全唐詩/json/120.json','["草堂列仙樓，上在青山頂。戶外窺數峰，階前對雙井。", "雨來花盡濕，風度松初冷。登棧行不疲，入溪語彌靜。", "雲能去塵服，兼欲事金鼎。正直心所存，諂諛長自省。", "適知幽遁趣，已覺煩慮屏。更愛雲林間，吾將臥南潁。"]'),
('yuding-2','廣武懷古','楊浚','唐','御定全唐诗','yuding','','[]','河水城下流，登城望彌愜。海雲飛不斷，岸草綠相接。',72,'御定全唐詩/json/120.json','["河水城下流，登城望彌愜。海雲飛不斷，岸草綠相接。", "龍門無舊場，武牢有遺堞。扼喉兵易守，捫指計何捷。", "天奪項氏謀，卒成漢家業。鄉山遙可見，西顧淚盈睫。"]'),
('yuding-3','贈李郎中','楊浚','唐','御定全唐诗','yuding','','[]','仙郎早朝退，直省臥南軒。院竹自成賞，階庭寂不喧。',72,'御定全唐詩/json/120.json','["仙郎早朝退，直省臥南軒。院竹自成賞，階庭寂不喧。", "焚香開後閣，起草閉前門。禮樂風流美，光華星位尊。", "榮兼朱紱貴，交乃布衣存。是日登龍客，無忘君子恩。"]'),
('yuding-4','詠王大娘戴竿','劉晏','唐','御定全唐诗','yuding','','[]','樓前百戲競爭新，唯有長竿妙入神。',32,'御定全唐詩/json/120.json','["樓前百戲競爭新，唯有長竿妙入神。", "誰謂綺羅翻有力，猶自嫌輕更著人。"]'),
('yuding-5','享太廟樂章','劉晏','唐','御定全唐诗','yuding','','[]','漢祚惟永，神功中興。夙驅氛祲，天覆黎蒸。',40,'御定全唐詩/json/120.json','["漢祚惟永，神功中興。夙驅氛祲，天覆黎蒸。", "三光再朗，庶績其凝。重熙累葉，景命是膺。"]'),
('yuding-6','鴻門行','袁瓘','唐','御定全唐诗','yuding','','[]','少年買意氣，百金不辭費。學劍西入秦，結交北游魏。',264,'御定全唐詩/json/120.json','["少年買意氣，百金不辭費。學劍西入秦，結交北游魏。", "秦魏多豪人，與代亦殊倫。由來不相識，皆是暗相親。", "寶馬青絲轡，狐裘貂鼠服。晨過劇孟遊，暮投咸陽宿。", "然諾本云云，諸侯莫不聞。猶思百戰術，更逐李將軍。", "始從灞陵下，遙遙度朔野。北風聞楚歌，南庭見胡馬。", "胡馬秋正肥，相邀夜合圍。戰酣烽火滅，路斷救兵稀。", "白刃縱橫逼，黃塵飛不息。虜騎血灑衣，單于淚沾臆。", "獻凱雲台中，自言塞上雄。將軍行失勢，部曲遂無功。", "新人不如舊，舊人不相救。萬里長飄颻，十年計不就。", "棄置難重論，驅馬度鴻門。行看楚漢事，不覺風塵昏。", "寶劍中夜撫，悲歌聊自舞。此曲不可終，曲終淚如雨。"]'),
('yuding-7','惠文太子挽歌','袁瓘','唐','御定全唐诗','yuding','','[]','寒仗丹旄引，陰堂白日違。暗燈明象物，畫水濕靈衣。',48,'御定全唐詩/json/120.json','["寒仗丹旄引，陰堂白日違。暗燈明象物，畫水濕靈衣。", "羽化淮王去，仙迎太子歸。空餘燕銜士，朝夕向陵飛。"]'),
('yuding-8','從軍行','李昂2','唐','御定全唐诗','yuding','','[]','漢家未得燕支山，征戍年年沙朔間。塞下長驅汗血馬，',164,'御定全唐詩/json/120.json','["漢家未得燕支山，征戍年年沙朔間。塞下長驅汗血馬，", "稽洛川邊胡騎來，漁陽戍裏烽煙起。長途羽檄何相望，", "幽陵異域風煙改，亭障連連古今在。夜聞鴻雁南渡河，", "玄漠雲平初合陣，西山月出聞鳴鏑。城南百戰多苦辛，", "楊葉樓中不寄書，蓮花劍上空流血。匈奴未滅不言家，", "天邊回望何悠悠，芳樹無人渡隴頭。春雲不變陽關雪，", "麾兵靜北垂，此日交河湄。欲令塞上無干戚，"]'),
('yuding-9','賦戚夫人楚舞歌','李昂2','唐','御定全唐诗','yuding','','[]','定陶城中是妾家，妾年二八顏如花。閨中歌舞未終曲，',136,'御定全唐詩/json/120.json','["定陶城中是妾家，妾年二八顏如花。閨中歌舞未終曲，", "風花菡萏落轅門，雲雨裴回入行殿。日夕悠悠非舊鄉，", "相從顧恩不雇己，何異浮萍寄深水。逐戰曾迷只輪下，", "珠簾夕殿聞鐘磬，白日秋天憶鼓鼙。君王縱恣翻成誤，", "黃泉白骨不可報，雀釵翠羽從此辭。君楚歌兮妾楚舞，", "已見儲君歸惠帝，徒留愛子付周昌。"]'),
('yuding-10','句','李昂2','唐','御定全唐诗','yuding','','[]','耳臨清渭洗，心向白雲閑。',12,'御定全唐詩/json/120.json','["耳臨清渭洗，心向白雲閑。"]'),
('yuding-11','夏晚初霽南省寓直用餘字','厙狄履溫','唐','御定全唐诗','yuding','','[]','薄宦因時泰，涼宵寓直初。沉沉仙閣閉，的的暗更徐。',120,'御定全唐詩/json/120.json','["薄宦因時泰，涼宵寓直初。沉沉仙閣閉，的的暗更徐。", "霽色連空上，炎氛入夜除。星回南斗落，月度北窗虛。", "待漏殘燈照，含芳襲氣餘。寐來冠不解，奏罷草仍書。", "幕府慚良策，明曹愧散樗。命輕徒有報，義重更難疏。", "燕廈欣成托，鵷行濫所如。晨趨當及早，複此戒朝車。"]'),
('yuding-12','同皇甫兵曹天官寺浴室新成招友人賞會','寇坦','唐','御定全唐诗','yuding','','[]','溫室歡初就，蘭交托勝因。共聽無漏法，兼濯有為塵。',48,'御定全唐詩/json/120.json','["溫室歡初就，蘭交托勝因。共聽無漏法，兼濯有為塵。", "水潔三空性，香沾四大身。清心多善友，頌德慰同人。"]'),
('yuding-13','同張少府和厙狄員外夏晚初霽南省寓直時兼充節度判官之作','寇坦','唐','御定全唐诗','yuding','','[]','黃綬歸休日，仙郎複奏餘。晏居當夏晚，寓直會晴初。',120,'御定全唐詩/json/120.json','["黃綬歸休日，仙郎複奏餘。晏居當夏晚，寓直會晴初。", "露散星文發，雲披水鏡虛。高才推獨唱，嘉會喜連茹。", "月色搖春闥，香煙靄暝廬。千門傳夜警，萬象照階除。", "少孺嘉能賦，文強閱賜書。兼曹謀未展，入幕志方攄。", "為奉靈台帛，恭先待漏車。貞標不可仰，空此樂樵漁。"]'),
('yuding-14','詠銅柱','李休烈','唐','御定全唐诗','yuding','','[]','天門街裏倒天樞，火急先須卸火珠。',32,'御定全唐詩/json/120.json','["天門街裏倒天樞，火急先須卸火珠。", "計合一條絲線挽，何勞兩縣索人夫。"]'),
('yuding-0','送賀監歸四明應制','李林甫','唐','御定全唐诗','yuding','','[]','掛冠知止足，豈獨漢疏賢。入道求真侶，辭恩訪列仙。',48,'御定全唐詩/json/121.json','["掛冠知止足，豈獨漢疏賢。入道求真侶，辭恩訪列仙。", "睿文含日月，宸翰動雲煙。鶴駕吳鄉遠，遙遙南斗邊。"]'),
('yuding-1','奉和聖制次瓊岳應制','李林甫','唐','御定全唐诗','yuding','','[]','東幸從人望，西巡順物回。雲收二華出，天轉五星來。',48,'御定全唐詩/json/121.json','["東幸從人望，西巡順物回。雲收二華出，天轉五星來。", "十月農初罷，三驅禮複開。更看瓊嶽上，佳氣接神台。"]'),
('yuding-2','秋夜望月憶韓席等諸侍郎因以投贈','李林甫','唐','御定全唐诗','yuding','','[]','秋天碧雲夜，明月懸東方。皓皓庭際色，稍稍林下光。',120,'御定全唐詩/json/121.json','["秋天碧雲夜，明月懸東方。皓皓庭際色，稍稍林下光。", "桂華澄遠近，璧彩散池塘。鴻雁飛難度，關山曲易長。", "揆予秉孤直，虛薄忝文昌。握鏡慚先照，持衡愧後行。", "多才眾君子，載筆久詞場。作賦推潘岳，題詩許謝康。", "當時陪宴語，今夕恨相望。願欲接高論，清晨朝建章。"]'),
('yuding-3','流崖州至鬼門關作','楊炎','唐','御定全唐诗','yuding','','[]','一去一萬里，千知千不還。崖州何處在，生度鬼門關。',24,'御定全唐詩/json/121.json','["一去一萬里，千知千不還。崖州何處在，生度鬼門關。"]'),
('yuding-4','贈元載歌妓','楊炎','唐','御定全唐诗','yuding','','[]','雪面淡眉天上女，鳳簫鸞翅欲飛去。',32,'御定全唐詩/json/121.json','["雪面淡眉天上女，鳳簫鸞翅欲飛去。", "玉山翹翠步無塵，楚腰如柳不勝春。"]'),
('yuding-5','別妻王韞秀','元載','唐','御定全唐诗','yuding','','[]','年來誰不厭龍鍾，雖在侯門似不容。',32,'御定全唐詩/json/121.json','["年來誰不厭龍鍾，雖在侯門似不容。", "看取海山寒翠樹，苦遭霜霰到秦封。"]'),
('yuding-6','賦得雲生棟樑間','陳希烈','唐','御定全唐诗','yuding','','[]','一片蒼梧意，氤氳生棟樑。下簾山足暗，開戶日添光。',48,'御定全唐詩/json/121.json','["一片蒼梧意，氤氳生棟樑。下簾山足暗，開戶日添光。", "偏使衣裘潤，能令枕簟涼。無心伴行雨，何必夢荊王。"]'),
('yuding-7','奉和聖制三月三日','陳希烈','唐','御定全唐诗','yuding','','[]','上巳迂龍駕，中流泛羽觴。酒因朝太子，詩為樂賢王。',72,'御定全唐詩/json/121.json','["上巳迂龍駕，中流泛羽觴。酒因朝太子，詩為樂賢王。", "錦纜方舟渡，瓊筵大樂張。風搖垂柳色，花發異林香。", "野老歌無事，朝臣飲歲芳。皇情被群物，中外洽恩光。"]'),
('yuding-8','省試白雲起封中','陳希烈','唐','御定全唐诗','yuding','','[]','千年泰山頂，雲起漢王封。不作奇峰狀，甯分觸石容。',72,'御定全唐詩/json/121.json','["千年泰山頂，雲起漢王封。不作奇峰狀，甯分觸石容。", "為霖雖易得，表聖自難逢。冉冉排空上，依依疊影重。", "素光非曳練，靈貺是從龍。豈學無心出，東西任所從。"]'),
('yuding-9','郎月行','張漸','唐','御定全唐诗','yuding','','[]','朗月照簾幌，清夜有餘姿。洞房怨孤枕，挾琴愛前墀。',120,'御定全唐詩/json/121.json','["朗月照簾幌，清夜有餘姿。洞房怨孤枕，挾琴愛前墀。", "萱草已數葉，梨花複遍枝。去歲草始榮，與君新相知。", "今年花未落，誰分生別離。代情難重論，人事好乖移。", "合比月華滿，分同月易虧。虧月當再圓，人別星隕天。", "吾欲竟此曲，意深不可傳。歎息孤鸞鳥，傷心明鏡前。"]'),
('yuding-10','曉次荊江','宋昱','唐','御定全唐诗','yuding','','[]','孤舟大江水，水涉無昏曙。雨暗迷津時，雲生望鄉處。',72,'御定全唐詩/json/121.json','["孤舟大江水，水涉無昏曙。雨暗迷津時，雲生望鄉處。", "漁翁閑自樂，樵客紛多慮。秋色湖上山，歸心日邊樹。", "徒稱竹箭美，未得楓林趣。向夕垂釣還，吾從落潮去。"]'),
('yuding-11','題石窟','宋昱','唐','御定全唐诗','yuding','','[]','梵宇開金地，香龕鑿鐵圍。影中群象動，空裏眾靈飛。',72,'御定全唐詩/json/121.json','["梵宇開金地，香龕鑿鐵圍。影中群象動，空裏眾靈飛。", "簷牖籠朱旭，房廊挹翠微。瑞蓮生佛步，瑤樹掛天衣。", "邀福功雖在，興王代久非。誰知雲朔外，更睹化胡歸。"]'),
('yuding-12','樟亭觀濤','宋昱','唐','御定全唐诗','yuding','','[]','濤來勢轉雄，獵獵駕長風。雷震雲霓裏，山飛霜雪中。',144,'御定全唐詩/json/121.json','["濤來勢轉雄，獵獵駕長風。雷震雲霓裏，山飛霜雪中。", "激流起平地，吹澇上侵空。翕辟乾坤異，盈虛日月同。", "艅艎從陸起，洲浦隔阡通。跳沫噴岩翠，翻波帶景紅。", "怒湍初抵北，卻浪複歸東。寂聽堪增勇，晴看自發蒙。", "伍生傳或謬，枚叟說難窮。來信應無已，申威亦匪躬。", "沖騰如決勝，回合似相攻。委質任平視，誰能涯始終。"]'),
('yuding-0','贈程秘書','盧象','唐','御定全唐诗','yuding','','[]','客自岐陽來，吐音若鳴鳳。孤飛畏不偶，獨立誰見用。',96,'御定全唐詩/json/122.json','["客自岐陽來，吐音若鳴鳳。孤飛畏不偶，獨立誰見用。", "忽從被褐中，召入承明宮。聖人借顏色，言事無不通。", "殷勤拯黎庶，感激論諸公。將相猜賈誼，圖書歸馬融。", "顧餘久寂寞，一歲麒麟閣。且共歌太平，勿嗟名宦薄。"]'),
('yuding-1','家叔征君東溪草堂二首','盧象','唐','御定全唐诗','yuding','','[]','開山十餘裏，青壁森相倚。欲識堯時天，東溪白雲是。',168,'御定全唐詩/json/122.json','["開山十餘裏，青壁森相倚。欲識堯時天，東溪白雲是。", "雷聲轉幽壑，雲氣杳流水。澗影生龍蛇，岩端翳檉梓。", "大道終不易，君恩曷能已。鶴羨無老時，龜言攝生理。", "浮年笑六甲，元化潛一指。未暇掃雲梯，空慚阮氏子。", "今朝共遊者，得性閑未歸。已到仙人家，莫驚鷗鳥飛。", "水深嚴子釣，松掛巢父衣。雲氣轉幽寂，溪流無是非。", "名理未足羨，腥臊詎所希。自惟負貞意，何歲當食薇。"]'),
('yuding-2','鄉試後自鞏還田家，因謝鄰友見過之作','盧象','唐','御定全唐诗','yuding','','[]','雞鳴出東邑，馬倦登南巒。落日見桑柘，翳然丘中寒。',96,'御定全唐詩/json/122.json','["雞鳴出東邑，馬倦登南巒。落日見桑柘，翳然丘中寒。", "鄰家多舊識，投暝來相看。且問春稅苦，兼陳行路難。", "園場近陰壑，草木易凋殘。峰晴雪猶積，澗深冰已團。", "浮名知何用，歲晏不成歡。置酒共君飲，當歌聊自寬。"]'),
('yuding-3','青雀歌','盧象','唐','御定全唐诗','yuding','','[]','啾啾青雀兒，飛來飛去仰天池。逍遙飲啄安涯分，',22,'御定全唐詩/json/122.json','["啾啾青雀兒，飛來飛去仰天池。逍遙飲啄安涯分，"]'),
('yuding-4','雜詩二首','盧象','唐','御定全唐诗','yuding','','[]','家居五原上，征戰是平生。獨負山西勇，誰當塞下名。',96,'御定全唐詩/json/122.json','["家居五原上，征戰是平生。獨負山西勇，誰當塞下名。", "死生遼海戰，雨雪薊門行。諸將封侯盡，論功獨不成。", "君家禦溝上，垂柳夾朱門。列鼎會中貴，鳴珂朝至尊。", "死生在片議，窮達由一言。須識苦寒士，莫矜狐白溫。"]'),
('yuding-5','贈廣川馬先生','盧象','唐','御定全唐诗','yuding','','[]','經書滿腹中，吾識廣川翁。年老甘無位，家貧懶發蒙。',48,'御定全唐詩/json/122.json','["經書滿腹中，吾識廣川翁。年老甘無位，家貧懶發蒙。", "人歸洙泗學，歌盛舞雩風。願接諸生禮，三年事馬融。"]'),
('yuding-6','峽中作','盧象','唐','御定全唐诗','yuding','','[]','高唐幾百里，樹色接陽臺。晚見江山霽，宵聞風雨來。',48,'御定全唐詩/json/122.json','["高唐幾百里，樹色接陽臺。晚見江山霽，宵聞風雨來。", "雲從三峽起，天向數峰開。靈境信難見，輕舟那可回。"]'),
('yuding-7','竹裏館','盧象','唐','御定全唐诗','yuding','','[]','江南冰不閉，山澤氣潛通。臘月聞山鳥，寒崖見蟄熊。',48,'御定全唐詩/json/122.json','["江南冰不閉，山澤氣潛通。臘月聞山鳥，寒崖見蟄熊。", "柳林春半合，荻筍亂無叢。回首金陵岸，依依向北風。"]'),
('yuding-8','永城使風','盧象','唐','御定全唐诗','yuding','','[]','長風起秋色，細雨含落暉。夕鳥向林去，晚帆相逐飛。',48,'御定全唐詩/json/122.json','["長風起秋色，細雨含落暉。夕鳥向林去，晚帆相逐飛。", "蟲聲出亂草，水氣薄行衣。一別故鄉道，悠悠今始歸。"]'),
('yuding-9','和徐侍郎叢筱詠','盧象','唐','御定全唐诗','yuding','','[]','中禁夕沉沉，幽篁別作林。色連雞樹近，影落鳳池深。',48,'御定全唐詩/json/122.json','["中禁夕沉沉，幽篁別作林。色連雞樹近，影落鳳池深。", "為重淩霜節，能虛應物心。年年承雨露，長對紫庭陰。"]'),
('yuding-10','駕幸溫泉','盧象','唐','御定全唐诗','yuding','','[]','傳聞聖主幸新豐，清蹕鳴鑾出禁中。細草終朝隨步輦，',40,'御定全唐詩/json/122.json','["傳聞聖主幸新豐，清蹕鳴鑾出禁中。細草終朝隨步輦，", "此日小臣徒獻賦，漢家誰複重揚雄。"]'),
('yuding-11','奉和張使君宴加朝散','盧象','唐','御定全唐诗','yuding','','[]','佐理星辰貴，分榮渙汗深。言從大夫後，用答聖人心。',72,'御定全唐詩/json/122.json','["佐理星辰貴，分榮渙汗深。言從大夫後，用答聖人心。", "騎擁軒裳客，鸞驚翰墨林。停杯歌麥秀，秉燭醉棠陰。", "爽氣淩秋笛，輕寒散暝砧。只應將四子，講德謝知音。"]'),
('yuding-12','贈張均員外','盧象','唐','御定全唐诗','yuding','','[]','公門世緒昌，才子冠裴王。出自平津邸，還為吏部郎。',96,'御定全唐詩/json/122.json','["公門世緒昌，才子冠裴王。出自平津邸，還為吏部郎。", "神仙餘氣色，列宿動輝光。夜直南宮靜，朝趨北禁長。", "時人歸水鏡，明主賜衣裳。翰苑飛鸚鵡，天池待鳳凰。", "承歡疇日顧，未紀後時傷。去去圖南遠，微才幸不忘。"]'),
('yuding-13','送祖詠','盧象','唐','御定全唐诗','yuding','','[]','田家宜伏臘，歲晏子言歸。石路雪初下，荒村雞共飛。',60,'御定全唐詩/json/122.json','["田家宜伏臘，歲晏子言歸。石路雪初下，荒村雞共飛。", "東原多煙火，北澗隱寒暉。滿酌野人酒，倦聞鄰女機。", "胡為困樵采，幾日罷朝衣。"]'),
('yuding-14','送綦毋潛','盧象','唐','御定全唐诗','yuding','','[]','夫君不得意，本自滄海來。高足未雲騁，虛舟空複回。',96,'御定全唐詩/json/122.json','["夫君不得意，本自滄海來。高足未雲騁，虛舟空複回。", "淮南楓葉落，灞岸桃花開。出處暫為耳，沉浮安系哉。", "如何天覆物，還遣世遺才。欲識秦將漢，嘗聞王與裴。", "離筵對寒食，別雨乘春雷。會有征書到，荷衣且漫裁。"]'),
('yuding-15','送趙都護赴安西','盧象','唐','御定全唐诗','yuding','','[]','下客候旌麾，元戎複在斯。門開都護府，兵動羽林兒。',96,'御定全唐詩/json/122.json','["下客候旌麾，元戎複在斯。門開都護府，兵動羽林兒。", "黠虜多翻覆，謀臣有別離。智同天所授，恩共日相隨。", "漢使開賓幕，胡笳送酒卮。風霜迎馬首，雨雪事魚麗。", "上策應無戰，深情屬載馳。不應行萬里，明主寄安危。"]'),
('yuding-16','追涼曆下古城西北隅，此地有清泉喬木','盧象','唐','御定全唐诗','yuding','','[]','謝脁出華省，王祥貽佩刀。前賢真可慕，衰病意空勞。',120,'御定全唐詩/json/122.json','["謝脁出華省，王祥貽佩刀。前賢真可慕，衰病意空勞。", "貞悔不自卜，遊隨共爾曹。未能齊得喪，時複誦離騷。", "閑陰七賢地，醉餐三士桃。蒼苔虞舜井，喬木古城壕。", "漁父偏相狎，堯年不可逃。蟬鳴秋雨霽，雲白曉山高。", "咫尺傳雙鯉，吹噓借一毛。故人皆得路，誰肯念同袍。"]'),
('yuding-17','戲贈邵使君張郎','盧象','唐','御定全唐诗','yuding','','[]','少婦石榴裙，新妝白玉面。能迷張公子，不許時相見。',24,'御定全唐詩/json/122.json','["少婦石榴裙，新妝白玉面。能迷張公子，不許時相見。"]'),
('yuding-18','同王維過崔處士林亭','盧象','唐','御定全唐诗','yuding','','[]','映竹時聞轉轆轤，當窗只見網蜘蛛。',32,'御定全唐詩/json/122.json','["映竹時聞轉轆轤，當窗只見網蜘蛛。", "主人非病常高臥，環堵蒙籠一老儒。"]'),
('yuding-19','寄河上段十六','盧象','唐','御定全唐诗','yuding','','[]','與君相識即相親，聞道君家住孟津。',32,'御定全唐詩/json/122.json','["與君相識即相親，聞道君家住孟津。", "為見行舟試借問，客中時有洛陽人。"]'),
('yuding-20','寒食','盧象','唐','御定全唐诗','yuding','','[]','子推言避世，山火遂焚身。四海同寒食，千秋為一人。',72,'御定全唐詩/json/122.json','["子推言避世，山火遂焚身。四海同寒食，千秋為一人。", "深冤何用道，峻跡古無鄰。魂魄山河氣，風雷禦宇神。", "光煙榆柳滅，怨曲龍蛇新。可歎文公霸，平生負此臣。"]'),
('yuding-21','八月十五日象自江東止田園移莊慶會未幾歸汶上小弟幼妹尤嗟其別兼賦是詩三首','盧象','唐','御定全唐诗','yuding','','[]','謝病始告歸，依然入桑梓。家人皆佇立，相候衡門裏。',204,'御定全唐詩/json/122.json','["謝病始告歸，依然入桑梓。家人皆佇立，相候衡門裏。", "疇類皆長年，成人舊童子。上堂家慶畢，願與親姻邇。", "論舊或餘悲，思存且相喜。田園轉蕪沒，但有寒泉水。", "衰柳日蕭條，秋光清邑裏。入門乍如客，休騎非便止。", "中飲顧王程，離憂從此始。", "兩妹日長成，雙鬟將及人。已能持寶瑟，自解掩羅巾。", "念昔別時小，未知疏與親。今來識離恨，掩淚方殷勤。", "小弟更孩幼，歸來不相識。同居雖漸慣，見人猶默默。", "宛作越人言，殊鄉甘水食。別此最為難，淚盡有餘憶。"]'),
('yuding-22','歎白髮','盧象','唐','御定全唐诗','yuding','','[]','我年一何長，鬢髮日已白。俯仰天地間，能為幾時客。',48,'御定全唐詩/json/122.json','["我年一何長，鬢髮日已白。俯仰天地間，能為幾時客。", "惆悵故山雲，裴回空日夕。何事與時人，東城複南陌。"]'),
('yuding-23','早秋宴張郎中海亭即事','盧象','唐','御定全唐诗','yuding','','[]','邑有弦歌宰，翔鸞狎野鷗。眷言華省舊，暫滯海池遊。',48,'御定全唐詩/json/122.json','["邑有弦歌宰，翔鸞狎野鷗。眷言華省舊，暫滯海池遊。", "郁島藏深竹，前溪對舞樓。更聞書即事，雲物是新秋。"]'),
('yuding-24','句','盧象','唐','御定全唐诗','yuding','','[]','吳越山多秀，新安江甚清。',44,'御定全唐詩/json/122.json','["吳越山多秀，新安江甚清。", "書名會粹才偏逸，酒號屠蘇味更醇。", "初疑輕煙淡古松，又似山開萬仞峰。"]'),
('yuding-0','嵩山十志十首：草堂','盧鴻一','唐','御定全唐诗','yuding','','[]','草堂者，蓋因自然之溪阜，前當墉洫；資人力之締構，',66,'御定全唐詩/json/123.json','["草堂者，蓋因自然之溪阜，前當墉洫；資人力之締構，", "及靡者居之，則妄為剪飾，失天理矣。詞曰：", "山為宅兮草為堂，芝蘭兮藥房。羅蘼蕪兮拍薜荔，"]'),
('yuding-1','嵩山十志十首：倒景台','盧鴻一','唐','御定全唐诗','yuding','','[]','倒景台者，蓋太室南麓，天門右崖，傑峰如台，氣淩倒景。',72,'御定全唐詩/json/123.json','["倒景台者，蓋太室南麓，天門右崖，傑峰如台，氣淩倒景。", "登路有三處可憩，或曰三休台，可以邀馭風之客，", "天門豁兮仙台聳，傑屹崒兮零澒湧。窮三休兮曠一觀，"]'),
('yuding-2','嵩山十志十首：樾館','盧鴻一','唐','御定全唐诗','yuding','','[]','樾館者，蓋即林取材，基顛柘，架茅茨，居不期逸，',48,'御定全唐詩/json/123.json','["樾館者，蓋即林取材，基顛柘，架茅茨，居不期逸，", "紫岩隈兮青溪側，雲松煙蔦兮千古色。芳靃蘼兮蔭蒙蘢，"]'),
('yuding-3','嵩山十志十首：枕煙庭','盧鴻一','唐','御定全唐诗','yuding','','[]','枕煙庭者，蓋特峰秀起，意若枕煙。秘庭凝虛，窅若仙會，',72,'御定全唐詩/json/123.json','["枕煙庭者，蓋特峰秀起，意若枕煙。秘庭凝虛，窅若仙會，", "詞曰：", "臨泱漭兮背青熒，吐雲煙兮合窅冥。怳欻翕兮遝幽靄，", "聞夫至誠必感兮祈此巔，契顥氣，養丹田，"]'),
('yuding-4','嵩山十志十首：雲錦淙','盧鴻一','唐','御定全唐诗','yuding','','[]','雲錦淙者，蓋激溜沖攢，傾石叢倚，鳴湍疊濯，噴若雷風，',94,'御定全唐詩/json/123.json','["雲錦淙者，蓋激溜沖攢，傾石叢倚，鳴湍疊濯，噴若雷風，", "及匪士觀之，則反曰寒泉傷玉趾矣。詞曰：", "水攢沖兮石叢聳，煥雲錦兮噴洶湧。苔駁犖兮草夤緣，", "有潔冥者媚此幽，漱靈液兮樂天休，實獲我心兮夫何求。"]'),
('yuding-5','嵩山十志十首：期仙磴','盧鴻一','唐','御定全唐诗','yuding','','[]','期仙磴者，蓋危磴穹窿，迥接雲路，靈仙仿佛。若可期及，',86,'御定全唐詩/json/123.json','["期仙磴者，蓋危磴穹窿，迥接雲路，靈仙仿佛。若可期及，", "霏微陰壑兮氣騰虹，迤邐危磴兮上淩空。", "青霞杪兮紫雲垂，鸞歌鳳舞兮吹參差。", "鸞歌鳳舞兮期仙磴，鴻駕迎兮瑤華贈。山中人兮好神仙，"]'),
('yuding-6','嵩山十志十首：滌煩磯','盧鴻一','唐','御定全唐诗','yuding','','[]','滌煩磯者，蓋窮穀峻崖，發地磐石，飛流攢激，積漱成渠。',76,'御定全唐詩/json/123.json','["滌煩磯者，蓋窮穀峻崖，發地磐石，飛流攢激，積漱成渠。", "澡性滌煩，迥有幽致。可為智者說，難為俗人言。詞曰：", "靈磯盤礴兮溜奔錯漱，泠風兮鎮冥壑。研苔滋兮泉珠潔，"]'),
('yuding-7','嵩山十志十首：冪翠庭','盧鴻一','唐','御定全唐诗','yuding','','[]','冪翠庭者，蓋崖巘積陰，林蘿遝翠，其上綿冪，其下深湛。',123,'御定全唐詩/json/123.json','["冪翠庭者，蓋崖巘積陰，林蘿遝翠，其上綿冪，其下深湛。", "可以王神，可以冥道矣。及喧者遊之，則酣謔永日，", "青崖陰兮月澗曲，重幽疊邃兮隱淪躅。", "草樹綿冪兮翠蒙蘢，當其無兮庭在中。", "當無有用兮冪翠庭，神可穀兮道可冥。", "有幽人兮張素琴，皇徽兮綠水陰，德之愔兮澹多心。"]'),
('yuding-8','嵩山十志十首：洞元室','盧鴻一','唐','御定全唐诗','yuding','','[]','洞元室者，蓋因岩作室，即理談玄，室返自然，元斯洞矣。',99,'御定全唐詩/json/123.json','["洞元室者，蓋因岩作室，即理談玄，室返自然，元斯洞矣。", "及邪者居之，則假容竊次，妄作虛誕，竟以盜言。詞曰：", "嵐氣肅兮岩翠冥，空陰虛兮戶芳迎。披蕙帳兮促蘿筵，", "返自然兮道可冥，澤妙思兮草玄經，結幽門兮在黃庭。"]'),
('yuding-9','嵩山十志十首：金碧潭','盧鴻一','唐','御定全唐诗','yuding','','[]','金碧潭者，蓋水潔石鮮，光涵金碧，岩葩林蔦，有助芳陰。',102,'御定全唐詩/json/123.json','["金碧潭者，蓋水潔石鮮，光涵金碧，岩葩林蔦，有助芳陰。", "鑒空洞虛，道斯勝矣。而世生纏乎利害，則未暇遊之。", "詞曰：", "水碧色兮石金光，灩熠熠兮濙湟湟。泉葩映兮煙蔦臨，", "有幽人兮好冥絕，炳其煥兮凝其潔，悠悠千古兮長不滅。"]'),
('yuding-0','書殿賜宴應制','徐安貞','唐','御定全唐诗','yuding','','[]','校文常近日，賜宴忽升天。酒正傳杯至，饔人捧案前。',48,'御定全唐詩/json/124.json','["校文常近日，賜宴忽升天。酒正傳杯至，饔人捧案前。", "玉階鳴溜水，清閣引歸煙。共惜芸香暮，春風幾萬年。"]'),
('yuding-1','從駕溫泉宮','徐安貞','唐','御定全唐诗','yuding','','[]','神女調溫液，年年待聖人。試開臨水殿，來洗屬車塵。',48,'御定全唐詩/json/124.json','["神女調溫液，年年待聖人。試開臨水殿，來洗屬車塵。", "暖氣隨明主，恩波浹近臣。靈威自無極，從此獻千春。"]'),
('yuding-2','送呂向補闕西嶽勒碑','徐安貞','唐','御定全唐诗','yuding','','[]','聖作西山頌，君其出使年。勒碑懸日月，驅傳接雲煙。',48,'御定全唐詩/json/124.json','["聖作西山頌，君其出使年。勒碑懸日月，驅傳接雲煙。", "寒盡函關路，春歸洛水邊。別離能幾許，朝暮玉墀前。"]'),
('yuding-3','送丹陽採訪','徐安貞','唐','御定全唐诗','yuding','','[]','郡縣分南國，皇華出聖朝。為憐鄉棹近，不道使車遙。',48,'御定全唐詩/json/124.json','["郡縣分南國，皇華出聖朝。為憐鄉棹近，不道使車遙。", "舊俗吳三讓，遺風漢六條。願言除疾苦，天子聽歌謠。"]'),
('yuding-4','送王判官','徐安貞','唐','御定全唐诗','yuding','','[]','明月開三峽，花源出五溪。城池青壁裏，煙火綠林西。',48,'御定全唐詩/json/124.json','["明月開三峽，花源出五溪。城池青壁裏，煙火綠林西。", "不畏王程促，惟愁仙路迷。巴東下歸棹，莫待夜猿啼。"]'),
('yuding-5','題襄陽圖','徐安貞','唐','御定全唐诗','yuding','','[]','畫得襄陽郡，依然見昔遊。峴山思駐馬，漢水憶回舟。',48,'御定全唐詩/json/124.json','["畫得襄陽郡，依然見昔遊。峴山思駐馬，漢水憶回舟。", "丹壑常含霽，青林不換秋。圖書空咫尺，千里意悠悠。"]'),
('yuding-6','程將軍夫人挽詩','徐安貞','唐','御定全唐诗','yuding','','[]','琴瑟調雙鳳，和鳴不獨飛。正歌春可樂，行泣露先晞。',48,'御定全唐詩/json/124.json','["琴瑟調雙鳳，和鳴不獨飛。正歌春可樂，行泣露先晞。", "環佩聲猶在，房櫳夢不歸。將軍休沐日，誰勸著新衣。"]'),
('yuding-7','奉和喜雪應制','徐安貞','唐','御定全唐诗','yuding','','[]','兩宮齋祭近登臨，雨雪紛紛天晝陰。只為經寒無瑞色，',40,'御定全唐詩/json/124.json','["兩宮齋祭近登臨，雨雪紛紛天晝陰。只為經寒無瑞色，", "自有三農歌帝力，還將萬庾答堯心。"]'),
('yuding-8','聞鄰家理箏','徐安貞','唐','御定全唐诗','yuding','','[]','北斗橫天夜欲闌，愁人倚月思無端。忽聞畫閣秦箏逸，',40,'御定全唐詩/json/124.json','["北斗橫天夜欲闌，愁人倚月思無端。忽聞畫閣秦箏逸，", "銀鎖重關聽未辟，不如眠去夢中看。"]'),
('yuding-9','奉和聖制早度蒲津關','徐安貞','唐','御定全唐诗','yuding','','[]','仙掌臨秦甸，虹橋辟晉關。兩都分地險，一曲度河灣。',72,'御定全唐詩/json/124.json','["仙掌臨秦甸，虹橋辟晉關。兩都分地險，一曲度河灣。", "路得津門要，時稱古戍閑。城花春正發，岸柳曙堪攀。", "後乘猶臨水，前旌欲換山。長安回望日，宸禦六龍還。"]'),
('yuding-10','奉和聖制答二相出雀鼠谷','徐安貞','唐','御定全唐诗','yuding','','[]','兩臣初入夢，二月扈巡邊。澗北寒猶在，山南春半傳。',72,'御定全唐詩/json/124.json','["兩臣初入夢，二月扈巡邊。澗北寒猶在，山南春半傳。", "頌聲先奉禦，辰象複回天。雲日明千里，旌旗照一川。", "柳陰低輦路，草色變新田。還望汾陽近，宸遊自窅然。"]'),
('yuding-11','句','徐安貞','唐','御定全唐诗','yuding','','[]','暮雨衣猶濕，春風帆正開。',12,'御定全唐詩/json/124.json','["暮雨衣猶濕，春風帆正開。"]'),
('yuding-12','奉和聖制答張說南出雀鼠谷','崔翹','唐','御定全唐诗','yuding','','[]','硤路繞河汾，晴光拂曙氛。笳吟中嶺樹，仗入半峰雲。',72,'御定全唐詩/json/124.json','["硤路繞河汾，晴光拂曙氛。笳吟中嶺樹，仗入半峰雲。", "頓覺山原盡，平看邑裏分。早行芳草迥，晚憩好風熏。", "嘉頌推英宰，春遊扈聖君。共欣承睿渥，日月照天文。"]'),
('yuding-13','送友人使夷陵','崔翹','唐','御定全唐诗','yuding','','[]','猿鳴三峽裏，行客舊沾裳。複道從茲去，思君不暫忘。',48,'御定全唐詩/json/124.json','["猿鳴三峽裏，行客舊沾裳。複道從茲去，思君不暫忘。", "開襟春葉短，分手夏條長。獨有幽庭桂，年年空自芳。"]'),
('yuding-14','鄭郎中山亭','崔翹','唐','御定全唐诗','yuding','','[]','篆筆飛章暇，園亭染翰遊。地奇人境別，事遠俗塵收。',72,'御定全唐詩/json/124.json','["篆筆飛章暇，園亭染翰遊。地奇人境別，事遠俗塵收。", "書閣山雲起，琴齋澗月留。泉清鱗影見，樹密鳥聲幽。", "杜馥熏梅雨，荷香送麥秋。無勞置驛騎，文酒可相求。"]'),
('yuding-15','奉和聖制答張說扈從南出雀鼠谷','梁升卿','唐','御定全唐诗','yuding','','[]','何意重關道，千年過聖皇。幽林承睿澤，閑客見清光。',72,'御定全唐詩/json/124.json','["何意重關道，千年過聖皇。幽林承睿澤，閑客見清光。", "日禦仙途遠，山靈壽域長。寒雲入晉薄，春樹隔汾香。", "國佐同時雨，天文屬歲陽。從來漢家盛，未若此巡方。"]'),
('yuding-16','白雲溪','吳鞏','唐','御定全唐诗','yuding','','[]','山徑入修篁，深林蔽日光。夏雲生嶂遠，瀑水引溪長。',48,'御定全唐詩/json/124.json','["山徑入修篁，深林蔽日光。夏雲生嶂遠，瀑水引溪長。", "秀跡逢皆勝，清芬坐轉涼。回看玉樽夕，歸路賞前忘。"]'),
('yuding-17','題奉國寺','陸海','唐','御定全唐诗','yuding','','[]','新秋夜何爽，露下風轉淒。一磬竹林外，千燈花塔西。',24,'御定全唐詩/json/124.json','["新秋夜何爽，露下風轉淒。一磬竹林外，千燈花塔西。"]'),
('yuding-18','題龍門寺','陸海','唐','御定全唐诗','yuding','','[]','窗燈林靄裏，聞磬水聲中。更與龍華會，爐煙滿夕風。',24,'御定全唐詩/json/124.json','["窗燈林靄裏，聞磬水聲中。更與龍華會，爐煙滿夕風。"]'),
('yuding-19','句','陸海','唐','御定全唐诗','yuding','','[]','忽然一曲稱君心，破卻中人百家產。',32,'御定全唐詩/json/124.json','["忽然一曲稱君心，破卻中人百家產。", "城外平人驅欲盡，帳中猶打袞花球。"]'),
('yuding-20','白牡丹','裴士淹','唐','御定全唐诗','yuding','','[]','長安年少惜春殘，爭認慈恩紫牡丹。',32,'御定全唐詩/json/124.json','["長安年少惜春殘，爭認慈恩紫牡丹。", "別有玉盤乘露冷，無人起就月中看。"]'),
('yuding-21','和從叔祿愔元日早朝','李元操','唐','御定全唐诗','yuding','','[]','銅渾變秋節，玉律動年灰。曖曖城霞旦，隱隱禁門開。',96,'御定全唐詩/json/124.json','["銅渾變秋節，玉律動年灰。曖曖城霞旦，隱隱禁門開。", "眾靈湊仙府，百神朝帝台。葉令雙鳧至，梁王駟馬來。", "戈鋋映林闕，歌管拂塵埃。保章望瑞氣，尚書免火災。", "冠冕多秀士，簪裾饒上才。誰憐張仲蔚，日暮反蒿萊。"]'),
('yuding-22','昭君怨','顧朝陽','唐','御定全唐诗','yuding','','[]','莫將鉛粉匣，不用鏡花光。一去邊城路，何情更畫妝。',48,'御定全唐詩/json/124.json','["莫將鉛粉匣，不用鏡花光。一去邊城路，何情更畫妝。", "影銷胡地月，衣盡漢宮香。妾死非關命，都緣怨斷腸。"]'),
('yuding-23','西塞山下回舟作','陶峴','唐','御定全唐诗','yuding','','[]','匡廬舊業是誰主，吳越新居安此生。白髮數莖歸未得，',40,'御定全唐詩/json/124.json','["匡廬舊業是誰主，吳越新居安此生。白髮數莖歸未得，", "從此舍舟何所詣，酒旗歌扇正相迎。"]'),
('yuding-0','酬諸公見過','王維','唐','御定全唐诗','yuding','','[]','嗟予未喪，哀此孤生。屏居藍田，薄地躬耕。歲晏輸稅，',75,'御定全唐詩/json/125.json','["嗟予未喪，哀此孤生。屏居藍田，薄地躬耕。歲晏輸稅，", "我聞有客，足掃荊扉。簞食伊何，疈瓜抓棗。仰廁群賢，", "靜觀素鮪，俯映白沙。山鳥群飛，日隱輕霞。登車上馬，"]'),
('yuding-1','奉和聖制登降聖觀與宰臣等同望應制','王維','唐','御定全唐诗','yuding','','[]','鳳扆朝碧落，龍圖耀金鏡。維岳降二臣，戴天臨萬姓。',96,'御定全唐詩/json/125.json','["鳳扆朝碧落，龍圖耀金鏡。維岳降二臣，戴天臨萬姓。", "山川八校滿，井邑三農竟。比屋皆可封，誰家不相慶。", "林疏遠村出，野曠寒山靜。帝城雲裏深，渭水天邊映。", "佳氣含風景，頌聲溢歌詠。端拱能任賢，彌彰聖君聖。"]'),
('yuding-2','奉和聖制禦春明樓臨右相園亭賦樂賢詩應制','王維','唐','御定全唐诗','yuding','','[]','複道通長樂，青門臨上路。遙聞鳳吹喧，闇識龍輿度。',96,'御定全唐詩/json/125.json','["複道通長樂，青門臨上路。遙聞鳳吹喧，闇識龍輿度。", "褰旒明四目，伏檻紆三顧。小苑接侯家，飛甍映宮樹。", "商山原上碧，滻水林端素。銀漢下天章，瓊筵承湛露。", "將非富人寵，信以平戎故。從來簡帝心，詎得回天步。"]'),
('yuding-3','奉和聖制送不蒙都護兼鴻臚卿歸安西應制','王維','唐','御定全唐诗','yuding','','[]','上卿增命服，都護揚歸旆。雜虜盡朝周，諸胡皆自鄶。',72,'御定全唐詩/json/125.json','["上卿增命服，都護揚歸旆。雜虜盡朝周，諸胡皆自鄶。", "鳴笳瀚海曲，按節陽關外。落日下河源，寒山靜秋塞。", "萬方氛祲息，六合乾坤大。無戰是天心，天心同覆載。"]'),
('yuding-4','扶南曲歌詞五首','王維','唐','御定全唐诗','yuding','','[]','翠羽流蘇帳，春眠曙不開。羞從面色起，嬌逐語聲來。',180,'御定全唐詩/json/125.json','["翠羽流蘇帳，春眠曙不開。羞從面色起，嬌逐語聲來。", "早向昭陽殿，君王中使催。", "堂上青弦動，堂前綺席陳。齊歌盧女曲，雙舞洛陽人。", "傾國徒相看，寧知心所親。", "香氣傳空滿，妝華影箔通。歌聞天仗外，舞出禦樓中。", "日暮歸何處，花間長樂宮。", "宮女還金屋，將眠複畏明。入春輕衣好，半夜薄妝成。", "拂曙朝前殿，玉墀多佩聲。", "朝日照綺窗，佳人坐臨鏡。散黛恨猶輕，插釵嫌未正。", "同心勿遽遊，幸待春妝竟。"]'),
('yuding-5','隴西行','王維','唐','御定全唐诗','yuding','','[]','十裏一走馬，五裏一揚鞭。都護軍書至，匈奴圍酒泉。',36,'御定全唐詩/json/125.json','["十裏一走馬，五裏一揚鞭。都護軍書至，匈奴圍酒泉。", "關山正飛雪，烽戍斷無煙。"]'),
('yuding-6','從軍行','王維','唐','御定全唐诗','yuding','','[]','吹角動行人，喧喧行人起。笳悲馬嘶亂，爭渡金河水。',48,'御定全唐詩/json/125.json','["吹角動行人，喧喧行人起。笳悲馬嘶亂，爭渡金河水。", "日暮沙漠陲，戰聲煙塵裏。盡系名王頸，歸來獻天子。"]'),
('yuding-7','早春行','王維','唐','御定全唐诗','yuding','','[]','紫梅發初遍，黃鳥歌猶澀。誰家折楊女，弄春如不及。',96,'御定全唐詩/json/125.json','["紫梅發初遍，黃鳥歌猶澀。誰家折楊女，弄春如不及。", "愛水看妝坐，羞人映花立。香畏風吹散，衣愁露沾濕。", "玉閨青門裏，日落香車入。遊衍益相思，含啼向彩帷。", "憶君長入夢，歸晚更生疑。不及紅簷燕，雙棲綠草時。"]'),
('yuding-8','早朝','王維','唐','御定全唐诗','yuding','','[]','皎潔明星高，蒼茫遠天曙。槐霧暗不開，城鴉鳴稍去。',48,'御定全唐詩/json/125.json','["皎潔明星高，蒼茫遠天曙。槐霧暗不開，城鴉鳴稍去。", "始聞高閣聲，莫辨更衣處。銀燭已成行，金門儼騶馭。"]'),
('yuding-9','獻始興公','王維','唐','御定全唐诗','yuding','','[]','甯棲野樹林，寧飲澗水流。不用坐粱肉，崎嶇見王侯。',96,'御定全唐詩/json/125.json','["甯棲野樹林，寧飲澗水流。不用坐粱肉，崎嶇見王侯。", "鄙哉匹夫節，布褐將白頭。任智誠則短，守任固其優。", "側聞大君子，安問黨與讎。所不賣公器，動為蒼生謀。", "賤子跪自陳，可為帳下不。感激有公議，曲私非所求。"]'),
('yuding-10','贈從弟司庫員外絿','王維','唐','御定全唐诗','yuding','','[]','少年識事淺，強學幹名利。徒聞躍馬年，苦無出人智。',96,'御定全唐詩/json/125.json','["少年識事淺，強學幹名利。徒聞躍馬年，苦無出人智。", "即事豈徒言，累官非不試。既寡遂性歡，恐招負時累。", "清冬見遠山，積雪凝蒼翠。浩然出東林，發我遺世意。", "惠連素清賞，夙語塵外事。欲緩攜手期，流年一何駛。"]'),
('yuding-11','座上走筆贈薛璩慕容損','王維','唐','御定全唐诗','yuding','','[]','希世無高節，絕跡有卑棲。君徒視人文，吾固和天倪。',84,'御定全唐詩/json/125.json','["希世無高節，絕跡有卑棲。君徒視人文，吾固和天倪。", "緬然萬物始，及與群物齊。分地依後稷，用天信重黎。", "春風何豫人，令我思東溪。草色有佳意，花枝稍含荑。", "更待風景好，與君藉萋萋。"]'),
('yuding-12','贈李頎','王維','唐','御定全唐诗','yuding','','[]','聞君餌丹砂，甚有好顏色。不知從今去，幾時生羽翼。',60,'御定全唐詩/json/125.json','["聞君餌丹砂，甚有好顏色。不知從今去，幾時生羽翼。", "王母翳華芝，望爾昆侖側。文螭從赤豹，萬里方一息。", "悲哉世上人，甘此膻腥食。"]'),
('yuding-13','贈劉藍田','王維','唐','御定全唐诗','yuding','','[]','籬間犬迎吠，出屋候荊扉。歲晏輸井稅，山村人夜歸。',48,'御定全唐詩/json/125.json','["籬間犬迎吠，出屋候荊扉。歲晏輸井稅，山村人夜歸。", "晚田始家食，餘布成我衣。詎肯無公事，煩君問是非。"]'),
('yuding-14','贈房盧氏管','王維','唐','御定全唐诗','yuding','','[]','達人無不可，忘己愛蒼生。豈複少十室，弦歌在兩楹。',120,'御定全唐詩/json/125.json','["達人無不可，忘己愛蒼生。豈複少十室，弦歌在兩楹。", "浮人日已歸，但坐事農耕。桑榆鬱相望，邑裏多雞鳴。", "秋山一何淨，蒼翠臨寒城。視事兼偃臥，對書不簪纓。", "蕭條人吏疏，鳥雀下空庭。鄙夫心所尚，晚節異平生。", "將從海岳居，守靜解天刑。或可累安邑，茅茨君試營。"]'),
('yuding-15','贈祖三詠','王維','唐','御定全唐诗','yuding','','[]','蕭蛸掛虛牖，蟋蟀鳴前除。歲晏涼風至，君子複何如。',120,'御定全唐詩/json/125.json','["蕭蛸掛虛牖，蟋蟀鳴前除。歲晏涼風至，君子複何如。", "高館闃無人，離居不可道。閑門寂已閉，落日照秋草。", "雖有近音信，千里阻河關。中複客汝潁，去年歸舊山。", "結交二十載，不得一日展。貧病子既深，契闊餘不淺。", "仲秋雖未歸，暮秋以為期。良會詎幾日，終日長相思。"]'),
('yuding-16','春夜竹亭贈錢少府歸藍田','王維','唐','御定全唐诗','yuding','','[]','夜靜群動息，時聞隔林犬。卻憶山中時，人家澗西遠。',36,'御定全唐詩/json/125.json','["夜靜群動息，時聞隔林犬。卻憶山中時，人家澗西遠。", "羨君明發去，采蕨輕軒冕。"]'),
('yuding-17','戲贈張五弟諲三首','王維','唐','御定全唐诗','yuding','','[]','吾弟東山時，心尚一何遠。日高猶自臥，鐘動始能飯。',288,'御定全唐詩/json/125.json','["吾弟東山時，心尚一何遠。日高猶自臥，鐘動始能飯。", "領上發未梳，妝頭書不卷。清川興悠悠，空林對偃蹇。", "青苔石上淨，細草松下軟。窗外鳥聲閑，階前虎心善。", "徒然萬象多，澹爾太虛緬。一知與物平，自顧為人淺。", "對君忽自得，浮念不煩遣。", "張弟五車書，讀書仍隱居。染翰過草聖，賦詩輕子虛。", "閉門二室下，隱居十年餘。宛是野人野，時從漁父漁。", "秋風自蕭索，五柳高且疏。望此去人世，渡水向吾廬。", "歲晏同攜手，只應君與予。", "設罝守毚兔，垂釣伺遊鱗。此是安口腹，非關慕隱淪。", "吾生好清淨，蔬食去情塵。今子方豪蕩，思為鼎食人。", "我家南山下，動息自遺身。入鳥不相亂，見獸皆相親。", "雲霞成伴侶，虛白侍衣巾。何事須夫子，邀予穀口真。"]'),
('yuding-18','胡居士臥病遺米因贈','王維','唐','御定全唐诗','yuding','','[]','了觀四大因，根性何所有。妄計苟不生，是身孰休咎。',144,'御定全唐詩/json/125.json','["了觀四大因，根性何所有。妄計苟不生，是身孰休咎。", "色聲何謂客，陰界複誰守。徒言蓮花目，豈惡楊枝肘。", "既飽香積飯，不醉聲聞酒。有無斷常見，生滅幻夢受。", "即病即實相，趨空定狂走。無有一法真，無有一法垢。", "居士素通達，隨宜善抖擻。床上無氈臥，鎘中有粥否。", "齋時不乞食，定應空漱口。聊持數斗米，且救浮生取。"]'),
('yuding-19','贈裴十迪','王維','唐','御定全唐诗','yuding','','[]','風景日夕佳，與君賦新詩。澹然望遠空，如意方支頤。',84,'御定全唐詩/json/125.json','["風景日夕佳，與君賦新詩。澹然望遠空，如意方支頤。", "春風動百草，蘭蕙生我籬。曖曖日暖閨，田家來致詞。", "欣欣春還皋，淡淡水生陂。桃李雖未開，荑萼滿芳枝。", "請君理還策，取告將農時。"]'),
('yuding-20','與胡居士皆病寄此詩兼示學人二首','王維','唐','御定全唐诗','yuding','','[]','一興微塵念，橫有朝露身。如是睹陰界，何方置我人。',240,'御定全唐詩/json/125.json','["一興微塵念，橫有朝露身。如是睹陰界，何方置我人。", "礙有固為主，趣空寧舍賓。洗心詎懸解，悟道正迷津。", "因愛果生病，從貪始覺貧。色聲非彼妄，浮幻即吾真。", "四達竟何遣，萬殊安可塵。胡生但高枕，寂寞與誰鄰。", "戰勝不謀食，理齊甘負薪。予若未始異，詎論疏與親。", "浮空徒漫漫，泛有定悠悠。無乘及乘者，所謂智人舟。", "詎舍貧病域，不疲生死流。無煩君喻馬，任以我為牛。", "植福祠迦葉，求仁笑孔丘。何津不鼓棹，何路不摧輈。", "念此聞思者，胡為多阻修。空虛花聚散，煩惱樹稀稠。", "滅相成無記，生心坐有求。降吳複歸蜀，不到莫相尤。"]'),
('yuding-21','奉寄韋太守陟','王維','唐','御定全唐诗','yuding','','[]','荒城自蕭索，萬里山河空。天高秋日迥，嘹唳聞歸鴻。',60,'御定全唐詩/json/125.json','["荒城自蕭索，萬里山河空。天高秋日迥，嘹唳聞歸鴻。", "寒塘映衰草，高館落疏桐。臨此歲方晏，顧景詠悲翁。", "故人不可見，寂寞平陵東。"]'),
('yuding-22','林園即事寄舍弟ヨ','王維','唐','御定全唐诗','yuding','','[]','寓目一蕭散，銷憂冀俄頃。青草肅澄陂，白雲移翠嶺。',109,'御定全唐詩/json/125.json','["寓目一蕭散，銷憂冀俄頃。青草肅澄陂，白雲移翠嶺。", "後沔通河渭，前山包鄢郢。松含風裏聲，花對池中影。", "地多齊後w9，人帶荊州癭。徒思赤筆書，詎有丹砂井。", "心悲常欲絕，發亂不能整。青簟日何長，閑門晝方靜。", "頹思茅簷下，彌傷好風景。"]'),
('yuding-23','至滑州隔河望黎陽憶丁三','王維','唐','御定全唐诗','yuding','','[]','隔河見桑柘，藹藹黎陽川。望望行漸遠，孤峰沒雲煙。',48,'御定全唐詩/json/125.json','["隔河見桑柘，藹藹黎陽川。望望行漸遠，孤峰沒雲煙。", "故人不可見，河水複悠然。賴有政聲遠，時聞行路傳。"]'),
('yuding-24','秋夜獨坐懷內弟崔興宗','王維','唐','御定全唐诗','yuding','','[]','夜靜群動息，蟪蛄聲悠悠。庭槐北風響，日夕方高秋。',60,'御定全唐詩/json/125.json','["夜靜群動息，蟪蛄聲悠悠。庭槐北風響，日夕方高秋。", "思子整羽翰，及時當雲浮。吾生將白首，歲晏思滄州。", "高足在旦暮，肯為南畝儔。"]'),
('yuding-25','和使君五郎西樓望遠思歸','王維','唐','御定全唐诗','yuding','','[]','高樓望所思，目極情未畢。枕上見千里，窗中窺萬室。',72,'御定全唐詩/json/125.json','["高樓望所思，目極情未畢。枕上見千里，窗中窺萬室。", "悠悠長路人，曖曖遠郊日。惆悵極浦外，迢遞孤煙出。", "能賦屬上才，思歸同下秩。故鄉不可見，雲水空如一。"]'),
('yuding-26','酬黎居士淅川作','王維','唐','御定全唐诗','yuding','','[]','儂家真個去，公定隨儂否。著處是蓮花，無心變楊柳。',48,'御定全唐詩/json/125.json','["儂家真個去，公定隨儂否。著處是蓮花，無心變楊柳。", "松龕藏藥裹，石唇安茶臼。氣味當共知，那能不攜手。"]'),
('yuding-27','送魏郡李太守赴任','王維','唐','御定全唐诗','yuding','','[]','與君伯氏別，又欲與君離。君行無幾日，當複隔山陂。',120,'御定全唐詩/json/125.json','["與君伯氏別，又欲與君離。君行無幾日，當複隔山陂。", "蒼茫秦川盡，日落桃林塞。獨樹臨關門，黃河向天外。", "前經洛陽陌，宛洛故人稀。故人離別盡，淇上轉驂騑。", "企予悲送遠，惆悵睢陽路。古木官渡平，秋城鄴宮故。", "想君行縣日，其出從如雲。遙思魏公子，複憶李將軍。"]'),
('yuding-28','送陸員外','王維','唐','御定全唐诗','yuding','','[]','郎署有伊人，居然古人風。天子顧河北，詔書除征東。',108,'御定全唐詩/json/125.json','["郎署有伊人，居然古人風。天子顧河北，詔書除征東。", "拜手辭上官，緩步出南宮。九河平原外，七國薊門中。", "陰風悲枯桑，古塞多飛蓬。萬里不見虜，蕭條胡地空。", "無為費中國，更欲邀奇功。遲遲前相送，握手嗟異同。", "行當封侯歸，肯訪商山翁。"]'),
('yuding-29','送宇文太守赴宣城','王維','唐','御定全唐诗','yuding','','[]','寥落雲外山，迢遞舟中賞。鐃吹發西江，秋空多清響。',60,'御定全唐詩/json/125.json','["寥落雲外山，迢遞舟中賞。鐃吹發西江，秋空多清響。", "地迥古城蕪，月明寒潮廣。時賽敬亭神，複解罟師網。", "何處寄相思，南風吹五兩。"]'),
('yuding-30','送綦毋秘書棄官還江東','王維','唐','御定全唐诗','yuding','','[]','明時久不達，棄置與君同。天命無怨色，人生有素風。',120,'御定全唐詩/json/125.json','["明時久不達，棄置與君同。天命無怨色，人生有素風。", "念君拂衣去，四海將安窮。秋天萬里淨，日暮澄江空。", "清夜何悠悠，扣舷明月中。和光魚鳥際，澹爾蒹葭叢。", "無庸客昭世，衰鬢日如蓬。頑疏暗人事，僻陋遠天聰。", "微物縱可采，其誰為至公。餘亦從此去，歸耕為老農。"]'),
('yuding-31','奉送六舅歸陸渾','王維','唐','御定全唐诗','yuding','','[]','伯舅吏淮泗，卓魯方喟然。悠哉自不競，退耕東皋田。',48,'御定全唐詩/json/125.json','["伯舅吏淮泗，卓魯方喟然。悠哉自不競，退耕東皋田。", "條桑臘月下，種杏春風前。酌醴賦歸去，共知陶令賢。"]'),
('yuding-32','送別','王維','唐','御定全唐诗','yuding','','[]','下馬飲君酒，問君何所之。君言不得意，歸臥南山陲。',36,'御定全唐詩/json/125.json','["下馬飲君酒，問君何所之。君言不得意，歸臥南山陲。", "但去莫復問，白雲無盡時。"]'),
('yuding-33','送張五歸山','王維','唐','御定全唐诗','yuding','','[]','送君盡惆悵，複送何人歸。幾日同攜手，一朝先拂衣。',48,'御定全唐詩/json/125.json','["送君盡惆悵，複送何人歸。幾日同攜手，一朝先拂衣。", "東山有茅屋，幸為掃荊扉。當亦謝官去，豈令心事違。"]'),
('yuding-34','齊州送祖三','王維','唐','御定全唐诗','yuding','','[]','相逢方一笑，相送還成泣。祖帳已傷離，荒城複愁入。',48,'御定全唐詩/json/125.json','["相逢方一笑，相送還成泣。祖帳已傷離，荒城複愁入。", "天寒遠山淨，日暮長河急。解纜君已遙，望君猶佇立。"]'),
('yuding-35','送縉雲苗太守','王維','唐','御定全唐诗','yuding','','[]','手疏謝明主，腰章為長吏。方從會稽邸，更發汝南騎。',48,'御定全唐詩/json/125.json','["手疏謝明主，腰章為長吏。方從會稽邸，更發汝南騎。", "按節下松陽，清江響鐃吹。露冕見三吳，方知百城貴。"]'),
('yuding-36','送從弟蕃游淮南','王維','唐','御定全唐诗','yuding','','[]','讀書複騎謝，帶劍游淮陰。淮陰少年輩，千里遠相尋。',132,'御定全唐詩/json/125.json','["讀書複騎謝，帶劍游淮陰。淮陰少年輩，千里遠相尋。", "高義難自隱，明時甯陸沉。島夷九州外，泉館三山深。", "席帆聊問罪，卉服盡成擒。歸來見天子，拜爵賜黃金。", "忽思鱸魚鱠，複有滄洲心。天寒蒹葭渚，日落雲夢林。", "江城下楓葉，淮上聞秋砧。送歸青門外，車馬去駸駸。", "惆悵新豐樹，空餘天際禽。"]');
